// ===== 角色内存缓存（性能优化：消除频繁 IndexedDB 读取）=====
// 原理：启动时将 characters 表加载到内存 Map，代理读写方法
// 读取走缓存（同步级速度），写入同时更新 DB + 缓存
// 效果：消除每次操作 ~180 次 DB 读取，大幅提升流畅度
const _charCache = new Map();
let _charCacheReady = false;

// 保存 Dexie 原始方法（代理实现中使用这些直接操作 DB）
const _dbChar = {
    get: db.characters.get.bind(db.characters),
    toArray: db.characters.toArray.bind(db.characters),
    put: db.characters.put.bind(db.characters),
    add: db.characters.add.bind(db.characters),
    update: db.characters.update.bind(db.characters),
    delete: db.characters.delete.bind(db.characters),
    bulkPut: db.characters.bulkPut.bind(db.characters),
    filter: db.characters.filter.bind(db.characters),
    where: db.characters.where.bind(db.characters),
};

// 启动时加载全部角色到缓存
async function _initCharCache() {
    try {
        const all = await _dbChar.toArray();
        all.forEach(c => _charCache.set(c.id, c));
        _charCacheReady = true;
        console.log(`[CharCache] ✅ 缓存就绪，共 ${_charCache.size} 个角色`);
    } catch (e) {
        console.error('[CharCache] ❌ 初始化失败，退化为直接读DB:', e);
    }
}
_initCharCache(); // 立即启动（不依赖DOM）

// --- 代理读取方法：缓存就绪时从内存读，否则回退DB ---
db.characters.get = async function(id) {
    if (_charCacheReady && id != null) {
        return _charCache.get(typeof id === 'number' ? id : parseInt(id)) || null;
    }
    return _dbChar.get(id);
};

db.characters.toArray = async function() {
    if (_charCacheReady) return Array.from(_charCache.values());
    return _dbChar.toArray();
};

db.characters.filter = function(fn) {
    if (_charCacheReady) {
        const result = Array.from(_charCache.values()).filter(fn);
        return { toArray: async () => result };
    }
    return _dbChar.filter(fn);
};

db.characters.where = function(field) {
    // ":id" 是 Dexie 内部使用的主键查询（如 update/modify），必须走原始方法
    if (_charCacheReady && field !== ':id') {
        return {
            equals: (val) => ({
                toArray: async () => Array.from(_charCache.values()).filter(c => c[field] === val)
            })
        };
    }
    return _dbChar.where(field);
};

// --- 代理写入方法：写DB + 同步更新缓存 ---
db.characters.put = async function(data) {
    const key = await _dbChar.put(data);
    if (data) {
        const id = data.id || key;
        if (id) { data.id = id; _charCache.set(id, data); }
    }
    return key;
};

db.characters.add = async function(data) {
    const id = await _dbChar.add(data);
    if (id) { data.id = id; _charCache.set(id, data); }
    return id;
};

db.characters.update = async function(id, changes) {
    const result = await _dbChar.update(id, changes);
    if (_charCacheReady && result) {
        const cached = _charCache.get(id);
        if (cached) {
            for (const [key, value] of Object.entries(changes)) {
                const parts = key.split('.');
                if (parts.length === 1) {
                    cached[key] = value;
                } else {
                    let obj = cached;
                    for (let i = 0; i < parts.length - 1; i++) {
                        if (obj[parts[i]] == null || typeof obj[parts[i]] !== 'object') obj[parts[i]] = {};
                        obj = obj[parts[i]];
                    }
                    obj[parts[parts.length - 1]] = value;
                }
            }
        }
    }
    return result;
};

db.characters.delete = async function(id) {
    const result = await _dbChar.delete(id);
    _charCache.delete(typeof id === 'number' ? id : parseInt(id));
    return result;
};

db.characters.bulkPut = async function(items) {
    const result = await _dbChar.bulkPut(items);
    // 批量导入后刷新整个缓存
    _charCache.clear();
    const all = await _dbChar.toArray();
    all.forEach(c => _charCache.set(c.id, c));
    return result;
};

// 📦 数据迁移：将 localStorage 中的电话和短信记录迁移到 IndexedDB
async function migratePhoneAndSmsToIndexedDB() {
    const migrationKey = 'phone_sms_migrated_to_indexeddb';
    if (localStorage.getItem(migrationKey) === 'true') {
        return; // 已经迁移过
    }
    
    console.log('[Migration] 开始迁移电话和短信记录到 IndexedDB...');
    
    // 获取默认账号ID
    const currentAccountId = localStorage.getItem('current_my_char_id') || '1';
    
    // 迁移电话记录
    try {
        const phoneRecents = JSON.parse(localStorage.getItem('phone_recents') || '[]');
        if (phoneRecents.length > 0) {
            console.log(`[Migration] 迁移 ${phoneRecents.length} 条电话记录...`);
            for (const record of phoneRecents) {
                await db.phone_recents.put({
                    accountId: currentAccountId,
                    charId: null, // 旧数据没有 charId
                    name: record.name,
                    number: record.number,
                    time: record.time || Date.now(),
                    type: record.type || 'missed',
                    isBlocked: record.isBlocked || false
                });
            }
            // 确认写入成功后再清理旧数据
            localStorage.removeItem('phone_recents');
            console.log('[Migration] ✅ 电话记录迁移完成');
        }
    } catch (e) {
        console.error('[Migration] ❌ 电话记录迁移失败:', e);
    }
    
    // 迁移短信记录
    try {
        const smsMessages = JSON.parse(localStorage.getItem('sms_messages') || '[]');
        if (smsMessages.length > 0) {
            console.log(`[Migration] 迁移 ${smsMessages.length} 条短信记录...`);
            for (const msg of smsMessages) {
                await db.sms_messages.put({
                    accountId: currentAccountId,
                    charId: null, // 旧数据没有 charId
                    sender: msg.sender,
                    number: msg.number,
                    content: msg.content || msg.message,
                    time: msg.time || msg.timestamp || Date.now(),
                    read: msg.read !== false,
                    type: msg.type || 'received',
                    isBlocked: msg.isBlocked || false,
                    receiverName: msg.receiverName,
                    receiverId: msg.receiverId
                });
            }
            // 确认写入成功后再清理旧数据
            localStorage.removeItem('sms_messages');
            console.log('[Migration] ✅ 短信记录迁移完成');
        }
    } catch (e) {
        console.error('[Migration] ❌ 短信记录迁移失败:', e);
    }
    
    // 标记迁移完成
    localStorage.setItem(migrationKey, 'true');
    console.log('[Migration] 🎉 电话和短信数据迁移完成');
}

// 📦 数据迁移v3：将 localStorage 中的离线聊天记录和财务数据迁移到 IndexedDB
async function migrateOfflineAndFinanceToIndexedDB() {
    const migrationKey = 'offline_finance_migrated_to_indexeddb_v1';
    if (localStorage.getItem(migrationKey) === 'true') {
        return; // 已经迁移过
    }
    
    console.log('[Migration-v3] 开始迁移离线聊天和财务数据到 IndexedDB...');
    
    try {
        // 1. 迁移离线聊天记录 (格式: offline_chat_{accountId}_{charId})
        const offlineChatKeys = [];
        for (let i = 0; i < localStorage.length; i++) {
            const k = localStorage.key(i);
            if (k && k.startsWith('offline_chat_')) {
                offlineChatKeys.push(k);
            }
        }
        
        for (const lsKey of offlineChatKeys) {
            try {
                const rawData = localStorage.getItem(lsKey);
                if (!rawData) continue;
                const chatData = JSON.parse(rawData);
                // 解析 key: offline_chat_{accountId}_{charId}
                const parts = lsKey.replace('offline_chat_', '').split('_');
                const accountId = parts[0] || '';
                const charId = parts.slice(1).join('_') || '';
                
                await db.offline_chats.put({
                    key: lsKey,
                    accountId: accountId,
                    charId: charId,
                    messages: chatData,
                    updatedAt: Date.now()
                });
                console.log(`[Migration-v3] ✅ 离线聊天已迁移: ${lsKey} (${chatData.length}条消息)`);
                // 注意：不删除 localStorage 中的旧数据，保留作为备份
                // 后续代码会优先从 IndexedDB 读取
            } catch (e) {
                console.error(`[Migration-v3] ❌ 离线聊天迁移失败: ${lsKey}`, e);
            }
        }
        
        // 2. 迁移财务数据
        const financeKeys = ['phone_balance', 'phone_recharge_history', 'loanHistory', 'scratchHistory'];
        for (const fKey of financeKeys) {
            try {
                const rawVal = localStorage.getItem(fKey);
                if (rawVal === null) continue;
                let parsedVal;
                try { parsedVal = JSON.parse(rawVal); } catch { parsedVal = rawVal; }
                
                await db.finance_data.put({
                    key: fKey,
                    value: parsedVal,
                    updatedAt: Date.now()
                });
                console.log(`[Migration-v3] ✅ 财务数据已迁移: ${fKey}`);
                // 不删除 localStorage 旧数据，保留兼容
            } catch (e) {
                console.error(`[Migration-v3] ❌ 财务数据迁移失败: ${fKey}`, e);
            }
        }
        
        localStorage.setItem(migrationKey, 'true');
        console.log('[Migration-v3] 🎉 离线聊天和财务数据迁移完成');
    } catch (e) {
        console.error('[Migration-v3] ❌ 迁移过程出错:', e);
    }
}

// ==================== 🛡️ 数据安全层：防丢数据核心工具 ====================

// 🛡️ 连续写入失败计数器（用于升级警告）
let _dbWriteFailCount = 0;
const _DB_FAIL_ESCALATE_THRESHOLD = 3; // 连续失败N次后显示持久红色横幅

// 🛡️ 显示持久性数据丢失风险横幅（不会自动消失，用户必须手动关闭）
function showDataLossBanner(message) {
    // 防止重复创建
    if (document.getElementById('data-loss-banner')) return;
    const banner = document.createElement('div');
    banner.id = 'data-loss-banner';
    banner.style.cssText = 'position:fixed;top:0;left:0;width:100%;z-index:999999;background:#d32f2f;color:#fff;padding:12px 40px 12px 16px;font-size:14px;line-height:1.4;box-shadow:0 2px 8px rgba(0,0,0,0.3);';
    banner.innerHTML = `⚠️ <b>数据保存异常</b>：${message}<br><small>请立即前往设置 → 导出备份，防止数据丢失！</small>`;
    const closeBtn = document.createElement('div');
    closeBtn.textContent = '×';
    closeBtn.style.cssText = 'position:absolute;top:8px;right:12px;cursor:pointer;font-size:22px;font-weight:bold;';
    closeBtn.onclick = () => banner.remove();
    banner.appendChild(closeBtn);
    document.body.appendChild(banner);
}

// 🛡️ 紧急备份到 localStorage（当 IndexedDB 写入失败时的最后手段）
function emergencyLocalStorageBackup(label, data) {
    try {
        const backupKey = '_emergency_backup_' + Date.now();
        const backupPayload = {
            label: label,
            time: new Date().toISOString(),
            data: data
        };
        localStorage.setItem(backupKey, JSON.stringify(backupPayload));
        console.warn(`[SafeDB] 🆘 紧急备份到 localStorage: ${backupKey}`);
        return true;
    } catch (e) {
        console.error('[SafeDB] 🆘 紧急备份也失败了:', e);
        return false;
    }
}

// 🛡️ 安全写入 localStorage（自带 try/catch + quota 检测 + 提示）
function safeLocalStorageSet(key, value) {
    try {
        localStorage.setItem(key, typeof value === 'string' ? value : JSON.stringify(value));
        return true;
    } catch (e) {
        console.error(`[SafeLS] ❌ localStorage写入失败 key=${key}:`, e.message);
        if (e.name === 'QuotaExceededError' || e.code === 22 || e.code === 1014) {
            showDataLossBanner('localStorage 存储空间已满，数据无法保存！');
        }
        try { if (typeof showToast === 'function') showToast('⚠️ 本地存储写入失败: ' + key); } catch(_) {}
        return false;
    }
}

// 🔧 安全写入 IndexedDB，带重试 + 用户提醒 + 紧急兜底
// maxRetries: 最大重试次数, delayMs: 重试间隔毫秒
async function safeDbPut(table, data, label, maxRetries = 3, delayMs = 500) {
    for (let attempt = 1; attempt <= maxRetries; attempt++) {
        try {
            await table.put(data);
            // 写入成功，重置失败计数
            if (_dbWriteFailCount > 0) {
                _dbWriteFailCount = 0;
                const banner = document.getElementById('data-loss-banner');
                if (banner) banner.remove(); // 恢复后移除横幅
            }
            return true;
        } catch (err) {
            console.error(`[SafeDB] ❌ ${label} 写入失败 (第${attempt}次):`, err.message);
            
            // 检查是否是配额不足
            if (err.name === 'QuotaExceededError' || (err.inner && err.inner.name === 'QuotaExceededError')) {
                console.error('[SafeDB] ⚠️ 存储空间不足！');
                _dbWriteFailCount++;
                // 紧急备份到 localStorage
                emergencyLocalStorageBackup(label, data);
                showDataLossBanner('存储空间不足，数据可能无法保存！');
                try {
                    if (typeof showToast === 'function') {
                        showToast('⚠️ 存储空间不足，部分数据可能无法保存！请导出备份后清理数据。');
                    }
                } catch(_) {}
                return false;
            }
            
            if (attempt < maxRetries) {
                await new Promise(r => setTimeout(r, delayMs * attempt));
            }
        }
    }
    
    // 所有重试都失败了
    _dbWriteFailCount++;
    console.error(`[SafeDB] ❌❌ ${label} 写入彻底失败（已重试${maxRetries}次），连续失败${_dbWriteFailCount}次`);
    
    // 紧急备份到 localStorage
    emergencyLocalStorageBackup(label, data);
    
    // 连续多次失败：显示持久红色横幅（不会自动消失）
    if (_dbWriteFailCount >= _DB_FAIL_ESCALATE_THRESHOLD) {
        showDataLossBanner(`IndexedDB 连续 ${_dbWriteFailCount} 次写入失败，数据有丢失风险！`);
    }
    
    try {
        if (typeof showToast === 'function') {
            showToast('⚠️ 数据保存失败，请尽快导出备份！', 5000);
        }
    } catch(_) {}
    return false;
}

// ==================== 🚀 内存缓存层（性能优化） ====================
// 数据常驻内存，DB 仅做持久化
// 减少 IndexedDB 读写频率，从根本上解决"群聊卡顿 / 页面崩溃"问题

/** 群聊对象缓存 groupId → group */
const _groupChatCache = new Map();
/** 角色/人物缓存 charId → character */
const _characterCache = new Map();

/**
 * 获取群聊对象（优先内存缓存，缓存未命中才读DB）
 */
async function getCachedGroupChat(id) {
    if (!id) return null;
    if (_groupChatCache.has(id)) return _groupChatCache.get(id);
    const group = await db.group_chats.get(id);
    if (group) _groupChatCache.set(id, group);
    return group;
}

/**
 * 获取角色对象（优先内存缓存，缓存未命中才读DB）
 */
async function getCachedCharacter(id) {
    if (!id) return null;
    const numId = typeof id === 'string' ? parseInt(id) : id;
    if (_characterCache.has(numId)) return _characterCache.get(numId);
    const char = await db.characters.get(numId);
    if (char) _characterCache.set(numId, char);
    return char;
}

/**
 * 批量预加载角色（减少循环内 N+1 查询）
 */
async function preloadCharacters(ids) {
    const missing = ids.filter(id => !_characterCache.has(typeof id === 'string' ? parseInt(id) : id));
    if (missing.length === 0) return;
    const chars = await db.characters.bulkGet(missing);
    chars.forEach(char => {
        if (char) _characterCache.set(char.id, char);
    });
}

/**
 * 使角色缓存失效（角色数据被外部修改时调用）
 */
function invalidateCharacterCache(id) {
    if (id) {
        _characterCache.delete(typeof id === 'string' ? parseInt(id) : id);
    }
}

/**
 * 使群聊缓存失效
 */
function invalidateGroupChatCache(id) {
    if (id) _groupChatCache.delete(id);
}

// 🚀 群聊 chat_history 最大条数（超出后自动裁剪最早的消息，保留内存和DB写入性能）
const GROUP_CHAT_HISTORY_MAX = 2000;

// 🔧 安全写入群聊数据（同时更新内存缓存 + 自动裁剪超长历史）
async function safeGroupChatPut(group, label) {
    // 🚀 自动裁剪：超出上限时移除最早的消息，保留最近的
    if (group && group.chat_history && group.chat_history.length > GROUP_CHAT_HISTORY_MAX) {
        const excess = group.chat_history.length - GROUP_CHAT_HISTORY_MAX;
        group.chat_history = group.chat_history.slice(excess);
        console.log(`[safeGroupChatPut] 群聊 "${group.name}" 历史消息超出${GROUP_CHAT_HISTORY_MAX}条上限，已自动裁剪${excess}条最早消息`);
    }
    if (group && group.id) _groupChatCache.set(group.id, group);
    return await safeDbPut(db.group_chats, group, label || `群聊[${group.name || group.id}]`);
}

// 🔧 安全局部更新 IndexedDB 记录（只更新指定字段，不覆盖整个对象）
// 使用 Dexie 的 update() 方法，支持点号嵌套写法如 'avatar_by_user.accountId'
async function safeDexieUpdate(table, id, payload, label, maxRetries = 3, delayMs = 500) {
    for (let attempt = 1; attempt <= maxRetries; attempt++) {
        try {
            const updated = await table.update(id, payload);
            if (updated) {
                // 写入成功，重置失败计数
                if (_dbWriteFailCount > 0) {
                    _dbWriteFailCount = 0;
                    const banner = document.getElementById('data-loss-banner');
                    if (banner) banner.remove();
                }
                return true; // 更新成功
            } else {
                console.warn(`[SafeDexieUpdate] ⚠️ ${label || ''} 更新返回0，记录可能不存在 (id=${id})`);
                return false;
            }
        } catch (err) {
            console.error(`[SafeDexieUpdate] ❌ ${label || ''} 更新失败 (第${attempt}次):`, err.message);
            
            // 检查是否是配额不足
            if (err.name === 'QuotaExceededError' || (err.inner && err.inner.name === 'QuotaExceededError')) {
                console.error('[SafeDexieUpdate] ⚠️ 存储空间不足！');
                _dbWriteFailCount++;
                emergencyLocalStorageBackup(label || `update-${id}`, payload);
                showDataLossBanner('存储空间不足，数据可能无法保存！');
                try {
                    if (typeof showToast === 'function') {
                        showToast('⚠️ 存储空间不足，部分数据可能无法保存！请导出备份后清理数据。');
                    }
                } catch(_) {}
                return false;
            }
            
            if (attempt < maxRetries) {
                await new Promise(r => setTimeout(r, delayMs * attempt));
            }
        }
    }
    
    _dbWriteFailCount++;
    console.error(`[SafeDexieUpdate] ❌❌ ${label || ''} 更新彻底失败（已重试${maxRetries}次），连续失败${_dbWriteFailCount}次`);
    emergencyLocalStorageBackup(label || `update-${id}`, payload);
    
    if (_dbWriteFailCount >= _DB_FAIL_ESCALATE_THRESHOLD) {
        showDataLossBanner(`IndexedDB 连续 ${_dbWriteFailCount} 次写入失败，数据有丢失风险！`);
    }
    
    try {
        if (typeof showToast === 'function') {
            showToast('⚠️ 数据保存失败，请尽快导出备份！', 5000);
        }
    } catch(_) {}
    return false;
}

// 🔧 安全写入角色数据（写入前合并最新的聊天详情设置，防止被旧数据覆盖）
async function safeCharacterPut(char, label) {
    // 🛡️ 保护聊天详情设置：put() 会覆盖整个对象，
    // 如果调用方持有的 char 是之前读取的旧数据，用户在此期间通过聊天详情修改的设置会丢失。
    // 解决方案：写入前先读取数据库中最新的设置字段，合并到即将写入的对象中。
    try {
        if (char && char.id) {
            const freshChar = await db.characters.get(char.id);
            if (freshChar) {
                // 聊天详情页的所有设置字段（通过 saveChatDetail / update() 保存）
                const settingsFields = [
                    'auto_reply_enabled', 'auto_reply_interval',
                    'context_message_count',
                    'reply_min_count', 'reply_max_count',
                    'input_placeholder',
                    'foreign_lang_mode',
                    'theater_mode',
                    'allow_ai_check_account', 'allow_shura_mode',
                    'allow_auto_avatar',
                    'allow_autonomous_activity',
                    'scheduled_activity_enabled', 'scheduled_activity_interval',
                    'moments_frequency',
                    'auto_summary_enabled', 'summary_interval',
                    'custom_bubble_css', 'bubble_style',
                    'lorebookIds', 'lorebookId',
                    'chat_background', 'chatThemeId',
                    'remark_by_user',
                    'mounted_sticker_categories', 'linked_user_id'
                ];
                for (const field of settingsFields) {
                    if (freshChar[field] !== undefined) {
                        char[field] = freshChar[field];
                    }
                }
            }
        }
    } catch (e) {
        console.warn('[safeCharacterPut] ⚠️ 合并最新设置失败，继续写入:', e);
    }
    return await safeDbPut(db.characters, char, label || `角色[${char.name || char.id}]`);
}

// 🔧 存储空间监控：检查 IndexedDB 使用情况
async function checkStorageQuota() {
    try {
        if (navigator.storage && navigator.storage.estimate) {
            const estimate = await navigator.storage.estimate();
            const usedMB = (estimate.usage / 1024 / 1024).toFixed(1);
            const quotaMB = (estimate.quota / 1024 / 1024).toFixed(1);
            const usagePercent = ((estimate.usage / estimate.quota) * 100).toFixed(1);
            
            console.log(`[Storage] 已用: ${usedMB}MB / ${quotaMB}MB (${usagePercent}%)`);
            
            // 超过80%时警告
            if (estimate.usage / estimate.quota > 0.8) {
                console.warn('[Storage] ⚠️ 存储空间使用超过80%！建议导出备份并清理旧数据。');
                try {
                    if (typeof showToast === 'function') {
                        showToast(`⚠️ 存储已用${usagePercent}%，建议导出备份`, 5000);
                    }
                } catch(_) {}
            }
            
            return { used: estimate.usage, quota: estimate.quota, percent: parseFloat(usagePercent) };
        }
    } catch (e) {
        console.warn('[Storage] 无法检测存储空间:', e);
    }
    return null;
}

// 🔧 定时自动保存守卫：防止浏览器崩溃/意外关闭导致内存数据丢失
// 每60秒检查一次，如果有未保存的脏数据则自动持久化
let _pendingDirtySaves = new Map(); // charId -> { char, accountId, history, timestamp }

function markChatDirty(charId, char, accountId, history) {
    _pendingDirtySaves.set(charId, {
        char: char,
        accountId: accountId,
        history: [...history], // 拷贝快照
        timestamp: Date.now()
    });
}

async function flushDirtySaves() {
    if (_pendingDirtySaves.size === 0) return;
    
    const entries = [..._pendingDirtySaves.entries()];
    _pendingDirtySaves.clear();
    
    for (const [charId, data] of entries) {
        try {
            const freshChar = await db.characters.get(charId);
            if (!freshChar) continue;
            
            // 只有当内存中的历史确实比DB中的新（更多消息）时才保存
            const dbHistory = data.accountId 
                ? (freshChar.chat_history_by_user?.[data.accountId] || [])
                : (freshChar.chat_history || []);
            
            if (data.history.length > dbHistory.length) {
                // 🛡️ 使用 update() 只更新聊天记录字段，防止覆盖设置
                const updatePayload = {};
                if (data.accountId) {
                    const mergedHistory = { ...(freshChar.chat_history_by_user || {}) };
                    mergedHistory[data.accountId] = data.history;
                    updatePayload.chat_history_by_user = mergedHistory;
                } else {
                    updatePayload.chat_history = data.history;
                }
                await db.characters.update(charId, updatePayload);
                console.log(`[AutoSave] ✅ 已自动保存 ${freshChar.name || charId} 的聊天记录（仅更新历史字段）`);
            }
        } catch (e) {
            console.error(`[AutoSave] ❌ 自动保存失败 charId=${charId}:`, e);
        }
    }
}

// 每60秒执行一次脏数据刷盘
setInterval(flushDirtySaves, 60000);

// 🛡️ 同步紧急保存（beforeunload 中 async 函数不可靠，浏览器可能不等待完成）
function emergencySyncFlush() {
    if (_pendingDirtySaves.size === 0) return;
    
    // 同步写入 localStorage 作为紧急兜底（IndexedDB 是异步的，不能保证 beforeunload 中完成）
    try {
        const emergencyData = {};
        for (const [charId, data] of _pendingDirtySaves.entries()) {
            emergencyData[charId] = {
                accountId: data.accountId,
                history: data.history,
                timestamp: data.timestamp
            };
        }
        localStorage.setItem('_emergency_dirty_saves', JSON.stringify(emergencyData));
        console.log(`[EmergencyFlush] 🆘 已将 ${_pendingDirtySaves.size} 条脏数据同步写入 localStorage`);
    } catch (e) {
        console.error('[EmergencyFlush] ❌ localStorage 紧急保存也失败:', e);
    }
    
    // 同时尝试异步 IndexedDB 刷盘（不保证能完成）
    flushDirtySaves();
}

// 🛡️ 启动时恢复紧急保存的脏数据
async function recoverEmergencyDirtySaves() {
    try {
        const raw = localStorage.getItem('_emergency_dirty_saves');
        if (!raw) return;
        
        const emergencyData = JSON.parse(raw);
        let recoveredCount = 0;
        
        for (const [charId, data] of Object.entries(emergencyData)) {
            try {
                const numCharId = parseInt(charId);
                const freshChar = await db.characters.get(numCharId || charId);
                if (!freshChar) continue;
                
                const dbHistory = data.accountId 
                    ? (freshChar.chat_history_by_user?.[data.accountId] || [])
                    : (freshChar.chat_history || []);
                
                // 只有紧急数据比 DB 中的更新（更多消息）时才恢复
                if (data.history && data.history.length > dbHistory.length) {
                    const updatePayload = {};
                    if (data.accountId) {
                        const merged = { ...(freshChar.chat_history_by_user || {}) };
                        merged[data.accountId] = data.history;
                        updatePayload.chat_history_by_user = merged;
                    } else {
                        updatePayload.chat_history = data.history;
                    }
                    await db.characters.update(numCharId || charId, updatePayload);
                    recoveredCount++;
                    console.log(`[EmergencyRecover] ✅ 已恢复 ${freshChar.name || charId} 的聊天记录（${data.history.length}条消息）`);
                }
            } catch (e) {
                console.error(`[EmergencyRecover] ❌ 恢复 charId=${charId} 失败:`, e);
            }
        }
        
        // 恢复完毕后清除紧急数据
        localStorage.removeItem('_emergency_dirty_saves');
        if (recoveredCount > 0) {
            console.log(`[EmergencyRecover] 🎉 共恢复 ${recoveredCount} 条紧急保存的聊天记录`);
            try { showToast(`已恢复 ${recoveredCount} 条上次未保存的聊天记录`); } catch(_) {}
        }
    } catch (e) {
        console.error('[EmergencyRecover] ❌ 紧急数据恢复失败:', e);
        localStorage.removeItem('_emergency_dirty_saves');
    }
}

// 页面关闭/隐藏时立即刷盘
window.addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'hidden') {
        emergencySyncFlush();
    }
});
window.addEventListener('beforeunload', () => {
    emergencySyncFlush();
});

// 启动时检查存储空间
setTimeout(checkStorageQuota, 5000);

// ==================== 🛡️ 离线聊天数据安全读写 ====================
// 优先使用 IndexedDB，兼容 localStorage 旧数据

async function loadOfflineChatHistory(accountId, charId) {
    const lsKey = `offline_chat_${accountId}_${charId}`;
    try {
        // 优先从 IndexedDB 读取
        const record = await db.offline_chats.get(lsKey);
        if (record && record.messages) {
            return record.messages;
        }
    } catch (e) {
        console.warn('[OfflineChat] IndexedDB读取失败，回退到localStorage:', e);
    }
    // 回退到 localStorage（兼容旧数据）
    try {
        return JSON.parse(localStorage.getItem(lsKey) || '[]');
    } catch (e) {
        return [];
    }
}

async function saveOfflineChatHistory(accountId, charId, messages) {
    const lsKey = `offline_chat_${accountId}_${charId}`;
    try {
        // 写入 IndexedDB（主存储）
        await db.offline_chats.put({
            key: lsKey,
            accountId: accountId,
            charId: String(charId),
            messages: messages,
            updatedAt: Date.now()
        });
    } catch (e) {
        console.error('[OfflineChat] IndexedDB写入失败:', e);
    }
    // 同时写入 localStorage（兜底备份）
    try {
        localStorage.setItem(lsKey, JSON.stringify(messages));
    } catch (e) {
        console.warn('[OfflineChat] localStorage写入失败（可能空间不足）:', e);
    }
}

// ==================== 🛡️ 财务数据安全读写 ====================

async function loadFinanceData(key, defaultValue) {
    try {
        const record = await db.finance_data.get(key);
        if (record && record.value !== undefined) {
            return record.value;
        }
    } catch (e) {
        console.warn(`[Finance] IndexedDB读取失败(${key})，回退到localStorage:`, e);
    }
    // 回退到 localStorage
    try {
        const raw = localStorage.getItem(key);
        if (raw === null) return defaultValue;
        try { return JSON.parse(raw); } catch { return raw; }
    } catch (e) {
        return defaultValue;
    }
}

async function saveFinanceData(key, value) {
    try {
        await db.finance_data.put({
            key: key,
            value: value,
            updatedAt: Date.now()
        });
    } catch (e) {
        console.error(`[Finance] IndexedDB写入失败(${key}):`, e);
    }
    // 同时写入 localStorage 兜底
    try {
        localStorage.setItem(key, JSON.stringify(value));
    } catch (e) {
        console.warn(`[Finance] localStorage写入失败(${key}):`, e);
    }
}

