        // ===== 查手机 - 数据锁定功能 =====
        // 检查角色FP数据是否已锁定
        async function isFpDataLocked(roleCharId, accountId) {
            if (!roleCharId || !accountId) return false;
            const roleChar = await db.characters.get(parseInt(roleCharId));
            if (!roleChar) return false;
            if (!roleChar.fp_data_locked_by_user) return false;
            return !!roleChar.fp_data_locked_by_user[accountId];
        }

        // 切换锁定状态
        async function toggleFpDataLock() {
            const roleId = window._fpWechatRoleId;
            const accountId = findPhoneTargetAccountId;
            if (!roleId || !accountId) { showToast('参数缺失'); return; }

            const roleChar = await db.characters.get(parseInt(roleId));
            if (!roleChar) { showToast('角色不存在'); return; }

            if (!roleChar.fp_data_locked_by_user) roleChar.fp_data_locked_by_user = {};
            const currentLocked = !!roleChar.fp_data_locked_by_user[accountId];

            if (currentLocked) {
                // 解锁 - 确认操作
                if (!confirm('解锁后，下次点击"AI生成数据"将重新生成所有数据（聊天记录、钱包、朋友圈等），之前的数据会被覆盖。\n\n确定要解锁吗？')) {
                    return;
                }
                roleChar.fp_data_locked_by_user[accountId] = false;
                await safeCharacterPut(roleChar);
                showToast('已解锁，数据可重新生成');
            } else {
                // 检查是否有已生成的数据
                const walletData = getFpWalletData(roleChar, accountId);
                const hasData = (walletData.balance !== '0.00') || (walletData.transactions && walletData.transactions.length > 0);
                const contactIds = getRolePhoneContacts(roleChar, accountId);
                const hasContacts = contactIds.length > 0;

                if (!hasData && !hasContacts) {
                    showToast('请先点击"AI生成数据"生成数据后再锁定');
                    return;
                }

                roleChar.fp_data_locked_by_user[accountId] = true;
                await safeCharacterPut(roleChar);
                showToast('已锁定！再次生成时将在现有数据基础上追加');
            }

            // 刷新"我"页面以更新按钮状态
            const content = document.getElementById('fp-wechat-content');
            if (content) {
                await renderFpMePage(content);
            }
        }

        // ===== 查手机WeChat - 服务页面 =====

        function showFpServicePage() {
            const page = document.getElementById('fp-service-page');
            page.style.display = 'flex';
            page.offsetHeight;
            page.classList.add('slide-in');
        }

        function hideFpServicePage() {
            const page = document.getElementById('fp-service-page');
            page.classList.remove('slide-in');
            setTimeout(() => { page.style.display = 'none'; }, 300);
        }

        async function showFpWalletPage() {
            const page = document.getElementById('fp-wallet-page');
            page.style.display = 'flex';
            page.offsetHeight;
            page.classList.add('active');
            // 更新余额显示
            await updateFpWalletBalance();
        }

        function hideFpWalletPage() {
            const page = document.getElementById('fp-wallet-page');
            page.classList.remove('active');
            setTimeout(() => { page.style.display = 'none'; }, 350);
        }

        async function showFpBalancePage() {
            const page = document.getElementById('fp-balance-page');
            page.style.display = 'flex';
            page.offsetHeight;
            page.classList.add('active');
            await updateFpWalletBalance();
        }

        function hideFpBalancePage() {
            const page = document.getElementById('fp-balance-page');
            page.classList.remove('active');
            setTimeout(() => { page.style.display = 'none'; }, 350);
        }

        function showFpBillPage() {
            const page = document.getElementById('fp-bill-page');
            page.style.display = 'flex';
            page.offsetHeight;
            page.classList.add('active');
            renderFpBillList();
        }

        function hideFpBillPage() {
            const page = document.getElementById('fp-bill-page');
            page.classList.remove('active');
            setTimeout(() => { page.style.display = 'none'; }, 350);
        }

        // 获取/设置角色的fp钱包数据（存储在 roleChar.fp_wallet_by_user[accountId] 中）
        function getFpWalletData(roleChar, accountId) {
            if (!roleChar || !accountId) return { balance: '0.00', transactions: [] };
            if (!roleChar.fp_wallet_by_user) roleChar.fp_wallet_by_user = {};
            if (!roleChar.fp_wallet_by_user[accountId]) roleChar.fp_wallet_by_user[accountId] = { balance: '0.00', transactions: [] };
            return roleChar.fp_wallet_by_user[accountId];
        }

        async function setFpWalletData(roleChar, accountId, data) {
            if (!roleChar.fp_wallet_by_user) roleChar.fp_wallet_by_user = {};
            roleChar.fp_wallet_by_user[accountId] = data;
            await safeCharacterPut(roleChar);
        }

        // ===== FP钱包交易：检查余额、扣款/加款、记账 =====
        // type: 'income' 或 'expense'
        // force: true 时强制执行（允许负余额），AI发起的操作使用
        // 返回 { success: true/false, balance: 当前余额 }
        async function fpWalletTransaction(roleCharId, accountId, type, amount, title, desc, force = false) {
            if (!roleCharId || !accountId) return { success: false, balance: 0 };
            const roleChar = await db.characters.get(parseInt(roleCharId));
            if (!roleChar) return { success: false, balance: 0 };
            const walletData = getFpWalletData(roleChar, accountId);
            let balance = parseFloat(walletData.balance) || 0;
            const amountNum = parseFloat(amount) || 0;

            // ★ 只有锁定时才校验余额，未锁定时不校验（允许随意交易）
            const locked = !!(roleChar.fp_data_locked_by_user && roleChar.fp_data_locked_by_user[accountId]);

            if (type === 'expense') {
                if (locked && !force && balance < amountNum) {
                    return { success: false, balance: balance };
                }
                balance -= amountNum;
            } else {
                balance += amountNum;
            }

            walletData.balance = balance.toFixed(2);
            if (!walletData.transactions) walletData.transactions = [];
            walletData.transactions.push({
                type,
                amount: amountNum.toFixed(2),
                title: title || (type === 'income' ? '收款' : '转账'),
                desc: desc || '',
                time: Date.now()
            });
            // 只保留最近100条
            if (walletData.transactions.length > 100) {
                walletData.transactions = walletData.transactions.slice(-100);
            }

            await setFpWalletData(roleChar, accountId, walletData);
            // 如果钱包页面正在显示，刷新余额
            await updateFpWalletBalance();
            return { success: true, balance: balance };
        }

        // 获取FP钱包余额（只查询，不修改）
        async function getFpWalletBalance(roleCharId, accountId) {
            if (!roleCharId || !accountId) return 0;
            const roleChar = await db.characters.get(parseInt(roleCharId));
            if (!roleChar) return 0;
            const walletData = getFpWalletData(roleChar, accountId);
            return parseFloat(walletData.balance) || 0;
        }

        async function updateFpWalletBalance() {
            const roleId = window._fpWechatRoleId;
            const accountId = findPhoneTargetAccountId;
            if (!roleId || !accountId) return;
            const roleChar = await db.characters.get(parseInt(roleId));
            if (!roleChar) return;
            const walletData = getFpWalletData(roleChar, accountId);
            const balanceStr = '¥' + (walletData.balance || '0.00');
            const el1 = document.getElementById('fp-wallet-balance');
            const el2 = document.getElementById('fp-balance-amount-display');
            if (el1) el1.textContent = balanceStr;
            if (el2) el2.textContent = balanceStr;
        }

        async function renderFpBillList() {
            const roleId = window._fpWechatRoleId;
            const accountId = findPhoneTargetAccountId;
            const listEl = document.getElementById('fp-bill-list');
            const emptyEl = document.getElementById('fp-bill-empty');
            if (!roleId || !accountId) { listEl.innerHTML = ''; emptyEl.style.display = 'block'; return; }
            const roleChar = await db.characters.get(parseInt(roleId));
            if (!roleChar) { listEl.innerHTML = ''; emptyEl.style.display = 'block'; return; }
            const walletData = getFpWalletData(roleChar, accountId);
            const transactions = walletData.transactions || [];
            if (transactions.length === 0) {
                listEl.innerHTML = '';
                emptyEl.style.display = 'block';
                return;
            }
            emptyEl.style.display = 'none';
            // 按时间倒序
            const sorted = [...transactions].sort((a, b) => (b.time || 0) - (a.time || 0));
            listEl.innerHTML = sorted.map(t => {
                const isIncome = t.type === 'income';
                const sign = isIncome ? '+' : '-';
                const color = isIncome ? '#07c160' : '#333';
                const timeStr = t.time ? new Date(t.time).toLocaleDateString('zh-CN', { month:'numeric', day:'numeric', hour:'numeric', minute:'numeric' }) : '';
                return `<div style="background:#fff; padding:14px 16px; display:flex; align-items:center; justify-content:space-between;">
                    <div>
                        <div style="font-size:15px; color:#333;">${t.title || '未知'}</div>
                        <div style="font-size:12px; color:#999; margin-top:4px;">${timeStr} ${t.desc || ''}</div>
                    </div>
                    <div style="font-size:16px; font-weight:600; color:${color};">${sign}¥${t.amount}</div>
                </div>`;
            }).join('');
        }

        // ===== 查手机 - AI生成角色数据（一次性生成所有数据，仅调用一次AI） =====
        async function generateFpRoleData() {
            const roleId = window._fpWechatRoleId;
            const accountId = findPhoneTargetAccountId;
            if (!roleId || !accountId) { showToast('参数缺失'); return; }

            // ★ 检查是否已锁定 - 锁定后追加而非覆盖
            const isLocked = await isFpDataLocked(roleId, accountId);

            let roleChar = await db.characters.get(parseInt(roleId));
            if (!roleChar) { showToast('角色不存在'); return; }

            const roleName = roleChar.nick || roleChar.name || '未知角色';
            const roleDesc = roleChar.description || roleChar.desc || '';

            // ★ 先自动将关联NPC填充到通讯录
            roleChar = await autoPopulateRelationshipContacts(roleChar, accountId);

            // 获取现有通讯录NPC（现在已包含关联NPC）
            let contactIds = getRolePhoneContacts(roleChar, accountId);
            const allChars = await db.characters.toArray();
            let npcContacts = [];
            for (const cid of contactIds) {
                const c = allChars.find(ch => ch.id === cid);
                if (c && c.type !== 'user' && String(c.id) !== String(roleId)) {
                    npcContacts.push(c);
                }
            }
            
            // ★ 收集被删除/拉黑的NPC联系人信息（锁定模式下AI可能自己把他们加回来）
            const deletedContactIds = roleChar.fp_deleted_contacts_by_user?.[accountId] || [];
            const blockedContactIds = roleChar.fp_blocked_contacts_by_user?.[accountId] || [];
            let deletedNpcs = [];
            for (const dId of deletedContactIds) {
                const dChar = allChars.find(ch => ch.id === dId);
                if (dChar && dChar.type !== 'user' && String(dChar.id) !== String(roleId)) {
                    const isBlocked = blockedContactIds.includes(dId);
                    deletedNpcs.push({ char: dChar, isBlocked });
                }
            }
            
            // ★ 构建关联NPC的关系描述（用于AI生成更准确的聊天记录）
            let relationshipContext = '';
            if (roleChar.relationships && roleChar.relationships.length > 0) {
                const relDescs = roleChar.relationships.map(r => {
                    const npc = npcContacts.find(n => n.id === r.targetId);
                    const npcNick = npc ? (npc.nick || npc.name) : r.targetName;
                    return `- ${npcNick}：${r.relation}${r.desc ? '（' + r.desc + '）' : ''}`;
                }).filter(Boolean);
                if (relDescs.length > 0) {
                    relationshipContext = `\n关联NPC与角色的关系：\n${relDescs.join('\n')}\n`;
                }
            }

            const userChar = await db.characters.get(parseInt(accountId));
            const userName = userChar ? (userChar.nick || userChar.name) : '用户';

            // 显示loading
            const btn = document.getElementById('fp-generate-btn');
            if (btn) {
                btn.disabled = true;
                btn.innerHTML = '<div class="loading-spinner" style="display:inline-block; width:16px; height:16px; border-width:2px; border-color:var(--ins-pink); border-top-color:transparent;"></div> 生成中...';
            }

            try {
                // ★ 锁定时不生成新NPC，使用现有的
                const needNpcs = !isLocked && npcContacts.length === 0;
                const npcCount = needNpcs ? (Math.floor(Math.random() * 3) + 2) : 0; // 2~4个NPC

                // ★ 锁定模式下，收集已有数据的摘要，告诉AI在此基础上继续
                let lockedContextSection = '';
                let existingWalletBalance = '0.00';
                if (isLocked) {
                    // 收集已有聊天记录的最后几条，让AI知道上下文
                    const roleCharSnap = await db.characters.get(parseInt(roleId));
                    let chatSummaries = [];
                    for (const npc of npcContacts) {
                        const fpNpcKey = 'fp_npc_' + npc.id;
                        const existHist = roleCharSnap?.chat_history_by_user?.[fpNpcKey] || [];
                        if (existHist.length > 0) {
                            const lastMsgs = existHist.slice(-3).map(m => {
                                const who = m.role === 'char' ? roleName : (npc.nick || npc.name);
                                return `${who}: ${(m.content || '').substring(0, 30)}`;
                            }).join(' / ');
                            chatSummaries.push(`- ${npc.nick || npc.name}: 最近消息 [${lastMsgs}]`);
                        }
                    }

                    // 获取现有钱包余额
                    const walletData = getFpWalletData(roleCharSnap, accountId);
                    existingWalletBalance = walletData.balance || '0.00';
                    const recentTx = (walletData.transactions || []).slice(-3).map(tx => {
                        return `${tx.type === 'income' ? '收入' : '支出'} ¥${tx.amount} (${tx.title})`;
                    }).join('、');

                    // 获取现有朋友圈最近内容
                    const existingMoments = roleCharSnap?.fp_moments_by_user?.[accountId] || [];
                    const recentMoments = existingMoments.slice(0, 3).map(m => {
                        return `${m.author}: ${(m.content || '').substring(0, 20)}`;
                    }).join('、');

                    // 获取现有NPC群聊摘要
                    const existingGroupChats = roleCharSnap?.fp_npc_group_chats_by_user?.[accountId] || [];
                    let groupChatSummaries = '';
                    if (existingGroupChats.length > 0) {
                        groupChatSummaries = existingGroupChats.map(g => {
                            const lastMsgs = (g.chat_history || []).slice(-2).map(m => {
                                return `${m.sender}: ${(m.content || '').substring(0, 20)}`;
                            }).join(' / ');
                            return `- "${g.name}" 成员:[${(g.members || []).join(',')}] 最近: [${lastMsgs}]`;
                        }).join('\n');
                    }

                    // ★ 收集被删除/拉黑的NPC信息，让AI决定是否加回来
                    let deletedNpcContext = '';
                    if (deletedNpcs.length > 0) {
                        const deletedList = deletedNpcs.map(d => {
                            const rel = roleChar.relationships?.find(r => r.targetId === d.char.id);
                            const relInfo = rel ? `[${rel.relation}] ` : '';
                            const status = d.isBlocked ? '被拉黑' : '被删除';
                            return `- ${d.char.nick || d.char.name}（${status}）: ${relInfo}${d.char.description || '好友'}`;
                        }).join('\n');
                        deletedNpcContext = `
★ 以下好友曾被${roleName}删除或拉黑：
${deletedList}
你可以让${roleName}主动把他们重新加回来（比如后悔了、想和好了、有事找对方等）。
如果要加回来，请在JSON中添加 "re_add_contacts" 字段，值为要加回来的好友nick数组。
被加回来的好友也要在chats中生成新的聊天记录（比如"我想了想还是加回你了"之类的）。
不加回来也可以，根据${roleName}的性格和与对方的关系来判断。
`;
                    }

                    lockedContextSection = `
★★★ 重要：这是一次追加生成（数据已锁定），请在已有数据的时间线之后继续生成新内容 ★★★
不要重复已有内容，要生成发生在"现在"的新消息和新动态。

已有数据概要：
- 当前钱包余额：¥${existingWalletBalance}
${chatSummaries.length > 0 ? '- 各好友最近聊天：\n' + chatSummaries.join('\n') : ''}
${recentTx ? '- 最近交易记录：' + recentTx : ''}
${recentMoments ? '- 最近朋友圈：' + recentMoments : ''}
${groupChatSummaries ? '- 已有NPC群聊：\n' + groupChatSummaries : ''}
${deletedNpcContext}
请基于以上已有情况，生成后续的新消息、新交易、新朋友圈、新群聊消息。
钱包的wallet.balance字段请填写在当前余额¥${existingWalletBalance}的基础上，加减新交易后的最终余额。
新生成的transactions只包含新交易（不要重复旧交易）。
`;
                }

                // ★ 构建一次性 prompt，包含所有数据的生成 ★
                let npcSection = '';
                if (needNpcs) {
                    npcSection = `
一、生成${npcCount}个微信好友NPC
每个NPC需要：
- name: 真实的中文全名（如"李婷"、"王浩然"、"赵小雪"），要像真人名字
- nick: 真实的微信昵称（如"小婷子🌸"、"浩然"、"雪雪"），像真人的微信名
- relation: 与主角色的具体关系（如：大学室友、公司同事、高中闺蜜、前男友等）
- desc: 一句话人设描述（如：活泼开朗的90后设计师，喜欢摄影和旅行）

`;
                }

                const existingNpcList = !needNpcs ? npcContacts.map(n => {
                    // ★ 优先使用关系描述来描述NPC
                    const rel = roleChar.relationships?.find(r => r.targetId === n.id);
                    const relInfo = rel ? `[${rel.relation}] ` : '';
                    return `- ${n.nick || n.name}: ${relInfo}${n.description || '好友'}`;
                }).join('\n') : '（将在npcs字段中生成）';
                const existingNpcNames = !needNpcs ? npcContacts.map(n => n.nick || n.name).join('、') : '';

                // ★ 获取世界书上下文（用于没有关联NPC时根据世界观生成）
                let fpLoreContext = '';
                try {
                    const lorebookIds = roleChar.lorebookIds || (roleChar.lorebookId ? [roleChar.lorebookId] : []);
                    if (lorebookIds.length > 0) {
                        fpLoreContext = await getLorebookContext(lorebookIds, roleName);
                    }
                } catch (e) {
                    console.warn('[FP生成] 获取世界书失败:', e);
                }

                const combinedPrompt = `你是一个辅助生成角色手机数据的AI助手。请一次性生成以下所有数据。

主角色信息：
角色名称：${roleName}
角色描述：${roleDesc || '暂无描述'}
关联用户：${userName}
${relationshipContext}${fpLoreContext ? `\n世界观背景：\n${fpLoreContext}\n` : ''}
${lockedContextSection}请生成以下所有内容：
${npcSection}${needNpcs ? '二' : '一'}、为主角色与每个NPC好友之间各生成${isLocked ? '2~4' : '3~6'}条简短的日常聊天记录${isLocked ? '（这是新消息，接续之前的对话）' : ''}
${needNpcs ? '好友列表将在npcs中生成，chats的key要用NPC的nick' : '好友列表：\n' + existingNpcList + '\nchats的key要用NPC的nick（即：' + existingNpcNames + '）'}
每条消息role: "user"(NPC发的) 或 "char"(主角色发的)

⚠️ 聊天记录气泡分割规则（极其重要！必须遵守！仅限chats聊天记录！）：
- 真人发微信不会把话堆在一条里，而是一句话一个气泡
- 仅在chats聊天记录的content字段内，用 ||| 分隔多个短句，每个短句会显示为独立的气泡
- 同一个人可以连续发多条消息（连续多个相同role的消息是允许的！）
- 每个气泡不超过15个字，短促、碎片化、口语化
- 少用标点，不要在句尾加句号
- content内禁止使用逗号（但 {{}} 标签内的逗号例外），想表达停顿就用|||分割
- ⚠️ ||| 只能出现在chats中！朋友圈content、评论text、likes中绝对禁止使用|||

示例（正确）：
{"role":"user","content":"在干嘛|||刚下课好无聊"}
{"role":"char","content":"在打游戏|||等下就好"}
{"role":"user","content":"又打游戏|||天天打"}
{"role":"char","content":"哈哈哈|||最后一把了|||马上来找你"}

错误示例（禁止）：
{"role":"user","content":"在干嘛？刚下课好无聊啊"} ← 多句话挤一个气泡
{"role":"char","content":"我在打游戏，等下就好了"} ← 用逗号连接，没分割

${needNpcs ? '三' : '二'}、生成钱包数据
${isLocked ? `当前余额为¥${existingWalletBalance}，在此基础上生成2~4笔新交易(收入/支出)，balance字段填加减新交易后的最终余额` : '余额要符合角色经济状况，生成3~6笔交易(收入/支出)，贴合日常生活'}

${isLocked ? '' : `${needNpcs ? '四' : '三'}、生成角色对用户"${userName}"的微信备注名
备注要符合关系（恋人用昵称/爱称，朋友用外号等），最多8个字

`}${needNpcs ? (isLocked ? '三' : '五') : (isLocked ? '三' : '四')}、生成好友们发的朋友圈动态（不是主角色发的，是好友NPC发的！）
总共生成${isLocked ? '3~5' : '5~8'}条朋友圈动态，分散在不同的NPC好友身上。${isLocked ? '（这是新动态，与之前不重复）' : ''}
每条动态的author字段填NPC好友的nick。
内容要符合对应NPC的人设和性格，包含日常生活、心情、分享等。
⚠️ 大多数朋友圈应该是纯文字的（不带images字段），只有少数（约1/3）可以带图片。
带图片时用images字段，方括号包裹图片描述，如"[自拍照]"、"[咖啡拉花]"。不带图片时不要写images字段。
部分动态可以有其他好友的点赞（用nick）和评论。主角色"${roleName}"也可能会点赞或评论好友的动态。

${needNpcs ? (isLocked ? '四' : '六') : (isLocked ? '四' : '五')}、生成角色自己的群聊（用户"${userName}"不在群里的NPC群聊）
${roleName}和一些NPC好友可能有自己的小群（比如闺蜜群、同事群、高中同学群、游戏开黑群等）。
${isLocked ? '为已有的群聊生成新的聊天消息（接续之前的对话）。如果没有已有群聊，则生成1~2个新群聊。' : '生成1~2个群聊，每个群聊由2~4个NPC好友组成（加上主角色${roleName}自己）。'}
每个群聊需要：
- name: 群名（像真人取的群名，如"闺蜜群🌸"、"高中三傻"、"干饭小分队"等）
- members: 群成员的nick数组（必须包含主角色"${roleName}"和至少2个NPC好友的nick）
- chat_history: ${isLocked ? '2~4' : '4~8'}条群聊消息
  - 每条消息：{"sender":"发送者nick","content":"消息内容"}
  - sender 必须是 members 中的某个nick
  - 群聊中多个人会交叉发言，不要只有两个人在聊

⚠️ 群聊的聊天记录也要遵守 ||| 气泡分割规则（和chats一样）！

请严格按照以下JSON格式返回，不要有任何其他文字：
{
  ${needNpcs ? '"npcs": [{"name":"李婷","nick":"小婷子🌸","relation":"大学室友","desc":"活泼开朗的90后设计师"}],' : ''}
  "chats": {
    "${needNpcs ? '小婷子🌸' : (npcContacts[0]?.nick || npcContacts[0]?.name || 'NPC昵称')}": [{"role":"user","content":"在干嘛|||好无聊"},{"role":"char","content":"在看剧|||你呢"},{"role":"user","content":"出来玩吧"},{"role":"char","content":"好啊|||去哪"}]
  },
  "wallet": {
    "balance": "${isLocked ? existingWalletBalance : '1234.56'}",
    "transactions": [{"type":"expense","amount":"25.00","title":"外卖","desc":"美团外卖"},{"type":"income","amount":"5000.00","title":"工资","desc":"XX公司"}]
  },
  ${isLocked ? '' : '"remark": "备注名",'}${isLocked && deletedNpcs.length > 0 ? '\n  "re_add_contacts": ["被加回的好友nick"],\n' : ''}  "moments": [
    {"author":"${needNpcs ? '小婷子🌸' : (npcContacts[0]?.nick || npcContacts[0]?.name || 'NPC昵称')}","content":"今天天气真好～出去走走","likes":["${roleName}","其他好友nick"],"comments":[{"name":"${roleName}","text":"好美啊"}]},
    {"author":"另一个好友nick","content":"加班到现在...","likes":[],"comments":[]},
    {"author":"好友nick","content":"周末出去玩","images":["[出游的照片]"],"likes":["${roleName}"],"comments":[]}
  ],
  "group_chats": [
    {"name":"闺蜜群🌸","members":["${roleName}","小婷子🌸","雪雪"],"chat_history":[{"sender":"小婷子🌸","content":"今晚谁有空|||出来吃饭"},{"sender":"${roleName}","content":"我可以|||去哪吃"},{"sender":"雪雪","content":"我也要去|||等我化个妆"}]}
  ]
}`;

                // ★ 仅调用一次AI ★
                const aiResult = await callAI([
                    { role: 'system', content: combinedPrompt },
                    { role: 'user', content: isLocked ? '请基于已有数据，生成后续的新内容，只返回JSON。' : '请一次性生成所有数据，只返回JSON。' }
                ]);

                let parsedData = {};
                try {
                    const jsonMatch = aiResult.match(/\{[\s\S]*\}/);
                    if (jsonMatch) {
                        parsedData = JSON.parse(jsonMatch[0]);
                    }
                } catch(e) {
                    console.error('[FP生成] JSON解析失败:', e, aiResult);
                    showToast('生成失败：数据格式错误');
                    return;
                }

                // ===== 处理NPC数据 =====
                let generatedNpcs = [];
                if (needNpcs && parsedData.npcs && Array.isArray(parsedData.npcs)) {
                    for (const npc of parsedData.npcs) {
                        const newChar = {
                            name: npc.name || '未知NPC',
                            nick: npc.nick || npc.name || '好友',
                            description: `[${npc.relation || '好友'}] ${npc.desc || ''}`,
                            avatar: '',
                            type: 'npc',
                            created_at: Date.now()
                        };
                        const id = await db.characters.add(newChar);
                        newChar.id = id;
                        npcContacts.push(newChar);
                        generatedNpcs.push(newChar);
                        await addRolePhoneContact(roleId, accountId, id);
                    }
                }

                // ===== 处理被加回来的好友（re_add_contacts） =====
                if (isLocked && parsedData.re_add_contacts && Array.isArray(parsedData.re_add_contacts) && parsedData.re_add_contacts.length > 0) {
                    const reAddNicks = parsedData.re_add_contacts;
                    console.log('[FP生成] AI决定加回好友:', reAddNicks);
                    
                    const roleCharForReAdd = await db.characters.get(parseInt(roleId));
                    let reAddCount = 0;
                    
                    for (const nick of reAddNicks) {
                        // 在已删除的NPC中查找匹配的
                        const matched = deletedNpcs.find(d => {
                            const dNick = d.char.nick || d.char.name;
                            return dNick === nick || d.char.name === nick;
                        });
                        if (!matched) continue;
                        
                        const reAddId = matched.char.id;
                        
                        // 从删除名单中移除
                        if (roleCharForReAdd.fp_deleted_contacts_by_user?.[accountId]) {
                            roleCharForReAdd.fp_deleted_contacts_by_user[accountId] = 
                                roleCharForReAdd.fp_deleted_contacts_by_user[accountId].filter(id => id !== reAddId);
                        }
                        // 从黑名单中移除
                        if (roleCharForReAdd.fp_blocked_contacts_by_user?.[accountId]) {
                            roleCharForReAdd.fp_blocked_contacts_by_user[accountId] = 
                                roleCharForReAdd.fp_blocked_contacts_by_user[accountId].filter(id => id !== reAddId);
                        }
                        // 加回通讯录
                        if (!roleCharForReAdd.phone_contacts_by_user) roleCharForReAdd.phone_contacts_by_user = {};
                        if (!roleCharForReAdd.phone_contacts_by_user[accountId]) roleCharForReAdd.phone_contacts_by_user[accountId] = [];
                        if (!roleCharForReAdd.phone_contacts_by_user[accountId].includes(reAddId)) {
                            roleCharForReAdd.phone_contacts_by_user[accountId].push(reAddId);
                        }
                        
                        // 加入当前npcContacts以便后续生成聊天记录
                        if (!npcContacts.find(n => n.id === reAddId)) {
                            npcContacts.push(matched.char);
                        }
                        
                        reAddCount++;
                        console.log(`[FP生成] ✅ 角色自己加回了好友: ${nick} (id=${reAddId})`);
                    }
                    
                    if (reAddCount > 0) {
                        await safeCharacterPut(roleCharForReAdd);
                        showToast(`角色自己加回了 ${reAddCount} 个好友`);
                    }
                }

                // ===== 处理聊天记录 =====
                const chatsData = parsedData.chats || {};
                const roleCharForChat = await db.characters.get(parseInt(roleId));
                if (!roleCharForChat.chat_history_by_user) roleCharForChat.chat_history_by_user = {};

                for (const npc of npcContacts) {
                    const npcKey = npc.nick || npc.name;
                    const messages = chatsData[npcKey] || [];
                    if (messages.length === 0) continue;

                    const fpNpcKey = 'fp_npc_' + npc.id;

                    // 🚀 拆分含 ||| 的消息为多条独立消息（让聊天记录更像真人）
                    const expandedMessages = [];
                    for (const m of messages) {
                        const content = (m.content || '').trim();
                        if (!content) continue;
                        if (content.includes('|||')) {
                            const segments = content.split('|||').map(s => s.trim()).filter(s => s.length > 0);
                            for (const seg of segments) {
                                expandedMessages.push({ role: m.role || 'user', content: seg });
                            }
                        } else {
                            expandedMessages.push({ role: m.role || 'user', content: content });
                        }
                    }

                    if (isLocked) {
                        // ★ 锁定模式：追加到已有记录之后
                        const existingHist = roleCharForChat.chat_history_by_user[fpNpcKey] || [];
                        // 新消息的时间从已有最后一条之后开始
                        const lastTime = existingHist.length > 0 ? (existingHist[existingHist.length - 1].time || Date.now()) : Date.now();
                        // 🚀 同一角色连续消息间隔短（3-8秒），不同角色间隔长（1-5分钟）
                        let currentTime = lastTime;
                        const newMsgs = expandedMessages.map((m, idx) => {
                            if (idx > 0) {
                                const prevRole = expandedMessages[idx - 1].role;
                                if (m.role === prevRole) {
                                    // 同一个人连续发消息，间隔3-8秒（模拟打字速度）
                                    currentTime += (3000 + Math.random() * 5000);
                                } else {
                                    // 不同人回复，间隔1-5分钟
                                    currentTime += (60000 + Math.random() * 240000);
                                }
                            } else {
                                currentTime += 600000; // 第一条消息间隔10分钟
                            }
                            return { role: m.role, content: m.content, time: currentTime };
                        });
                        roleCharForChat.chat_history_by_user[fpNpcKey] = [...existingHist, ...newMsgs];
                    } else {
                        // ★ 未锁定：替换（原始行为）
                        const baseTime = Date.now() - 3600000 * 24;
                        // 🚀 同一角色连续消息间隔短（3-8秒），不同角色间隔长（5-15分钟）
                        let currentTime = baseTime;
                        const hist = expandedMessages.map((m, idx) => {
                            if (idx > 0) {
                                const prevRole = expandedMessages[idx - 1].role;
                                if (m.role === prevRole) {
                                    // 同一个人连续发消息，间隔3-8秒
                                    currentTime += (3000 + Math.random() * 5000);
                                } else {
                                    // 不同人回复，间隔5-15分钟
                                    currentTime += (300000 + Math.random() * 600000);
                                }
                            }
                            return { role: m.role, content: m.content, time: currentTime };
                        });
                        roleCharForChat.chat_history_by_user[fpNpcKey] = hist;
                    }
                }
                await safeCharacterPut(roleCharForChat);

                // ===== 处理钱包数据 =====
                let walletResult = parsedData.wallet || { balance: '0.00', transactions: [] };
                const charForWallet = await db.characters.get(parseInt(roleId));

                if (isLocked) {
                    // ★ 锁定模式：保留已有交易记录，追加新交易
                    const existingWallet = getFpWalletData(charForWallet, accountId);
                    const existingTx = existingWallet.transactions || [];
                    // 新交易的时间从现在开始
                    const newTx = (walletResult.transactions || []).map((tx, idx) => ({
                        ...tx,
                        time: Date.now() + idx * 3600000 * 2 // 每笔间隔2小时
                    }));
                    // 合并：保留旧交易 + 追加新交易
                    walletResult = {
                        balance: walletResult.balance || existingWallet.balance, // AI计算的新余额
                        transactions: [...existingTx, ...newTx]
                    };
                    // 只保留最近100条
                    if (walletResult.transactions.length > 100) {
                        walletResult.transactions = walletResult.transactions.slice(-100);
                    }
                } else {
                    // ★ 未锁定：覆盖（原始行为）
                    const txBaseTime = Date.now() - 3600000 * 72;
                    if (walletResult.transactions) {
                        walletResult.transactions.forEach((tx, idx) => {
                            tx.time = txBaseTime + idx * 3600000 * 8;
                        });
                    }
                }
                await setFpWalletData(charForWallet, accountId, walletResult);
                await updateFpWalletBalance();

                // ===== 处理备注（锁定时不覆盖已有备注） =====
                if (!isLocked) {
                    const remark = (parsedData.remark || '').trim().replace(/["""]/g, '').substring(0, 20);
                    if (remark) {
                        const charForRemark = await db.characters.get(parseInt(roleId));
                        if (!charForRemark.fp_remark_by_user) charForRemark.fp_remark_by_user = {};
                        charForRemark.fp_remark_by_user[accountId] = remark;
                        await safeCharacterPut(charForRemark);
                        console.log('[FP生成] 备注生成:', remark);
                    }
                }

                // ===== 处理朋友圈数据（好友NPC发的朋友圈） =====
                const momentsArr = parsedData.moments || [];
                if (momentsArr.length > 0) {
                    const charForMoments = await db.characters.get(parseInt(roleId));
                    if (!charForMoments.fp_moments_by_user) charForMoments.fp_moments_by_user = {};
                    
                    const existingMoments = isLocked ? (charForMoments.fp_moments_by_user[accountId] || []) : [];
                    // 新动态时间：锁定模式从现在起，非锁定从48小时前起
                    const momentBaseTime = isLocked ? Date.now() : (Date.now() - 3600000 * 48);
                    const processedMoments = momentsArr.map((m, idx) => ({
                        author: m.author || '好友',
                        // 🔧 安全过滤：去除可能泄露的 ||| 分隔符
                        content: (m.content || '').replace(/\|\|\|/g, ' '),
                        images: (m.images || []).map(img => {
                            // 如果图片描述没有方括号，加上
                            if (typeof img === 'string' && !img.startsWith('[')) return '[' + img + ']';
                            return img;
                        }),
                        likes: m.likes || [],
                        comments: (m.comments || []).map(c => ({
                            name: c.name || '好友',
                            // 🔧 安全过滤：去除可能泄露的 ||| 分隔符
                            text: (c.text || '').replace(/\|\|\|/g, ' ')
                        })),
                        time: momentBaseTime + idx * 3600000 * 2 // 锁定模式间隔2小时，非锁定间隔6小时
                    }));

                    // 合并已有 + 新动态，按时间倒序排列
                    const allMoments = [...existingMoments, ...processedMoments];
                    allMoments.sort((a, b) => b.time - a.time);
                    charForMoments.fp_moments_by_user[accountId] = allMoments;
                    await safeCharacterPut(charForMoments);
                    console.log(`[FP生成] 朋友圈${isLocked ? '追加' : '生成'}:`, processedMoments.length, '条，总计:', allMoments.length, '条');
                }

                // ===== 处理NPC群聊数据 =====
                const groupChatsArr = parsedData.group_chats || [];
                if (groupChatsArr.length > 0) {
                    const charForGroups = await db.characters.get(parseInt(roleId));
                    if (!charForGroups.fp_npc_group_chats_by_user) charForGroups.fp_npc_group_chats_by_user = {};
                    
                    const existingGroups = isLocked ? (charForGroups.fp_npc_group_chats_by_user[accountId] || []) : [];
                    const groupBaseTime = isLocked ? Date.now() : (Date.now() - 3600000 * 24);
                    
                    for (const gData of groupChatsArr) {
                        if (!gData.name || !gData.members || !gData.chat_history) continue;
                        
                        // 拆分 ||| 并生成时间戳
                        const expandedHistory = [];
                        for (const msg of gData.chat_history) {
                            const content = (msg.content || '').trim();
                            if (!content) continue;
                            const sender = msg.sender || '未知';
                            if (content.includes('|||')) {
                                const segments = content.split('|||').map(s => s.trim()).filter(s => s.length > 0);
                                for (const seg of segments) {
                                    expandedHistory.push({ sender, content: seg });
                                }
                            } else {
                                expandedHistory.push({ sender, content });
                            }
                        }
                        
                        if (isLocked) {
                            // 锁定模式：尝试匹配已有群聊并追加消息
                            const existingGroup = existingGroups.find(eg => eg.name === gData.name);
                            if (existingGroup) {
                                const lastTime = existingGroup.chat_history.length > 0 
                                    ? (existingGroup.chat_history[existingGroup.chat_history.length - 1].time || Date.now()) 
                                    : Date.now();
                                let currentTime = lastTime;
                                const newMsgs = expandedHistory.map((m, idx) => {
                                    if (idx > 0) {
                                        const prevSender = expandedHistory[idx - 1].sender;
                                        currentTime += (m.sender === prevSender) ? (3000 + Math.random() * 5000) : (60000 + Math.random() * 240000);
                                    } else {
                                        currentTime += 600000;
                                    }
                                    return { sender: m.sender, content: m.content, time: currentTime };
                                });
                                existingGroup.chat_history = [...existingGroup.chat_history, ...newMsgs];
                                // 更新成员列表（可能有新成员加入）
                                for (const member of gData.members) {
                                    if (!existingGroup.members.includes(member)) {
                                        existingGroup.members.push(member);
                                    }
                                }
                                console.log(`[FP生成] 群聊"${gData.name}"追加 ${newMsgs.length} 条消息`);
                                continue;
                            }
                        }
                        
                        // 新建群聊
                        let currentTime = groupBaseTime;
                        const processedHistory = expandedHistory.map((m, idx) => {
                            if (idx > 0) {
                                const prevSender = expandedHistory[idx - 1].sender;
                                currentTime += (m.sender === prevSender) ? (3000 + Math.random() * 5000) : (300000 + Math.random() * 600000);
                            }
                            return { sender: m.sender, content: m.content, time: currentTime };
                        });
                        
                        existingGroups.push({
                            id: Date.now() + Math.floor(Math.random() * 10000),
                            name: gData.name,
                            members: gData.members,
                            chat_history: processedHistory,
                            created_at: groupBaseTime
                        });
                    }
                    
                    charForGroups.fp_npc_group_chats_by_user[accountId] = existingGroups;
                    await safeCharacterPut(charForGroups);
                    console.log(`[FP生成] NPC群聊${isLocked ? '追加' : '生成'}完成，共 ${existingGroups.length} 个群聊`);
                }

                if (isLocked) {
                    showToast('✅ 新数据已追加（已保留旧数据）');
                } else {
                    showToast('✅ 数据生成完成');
                    if (generatedNpcs.length > 0) {
                        showToast(`已生成 ${generatedNpcs.length} 个好友和聊天记录`);
                    }
                }

            } catch(e) {
                console.error('[FP生成] 整体失败:', e);
                showToast('生成失败：' + (e.message || '未知错误'));
            } finally {
                if (btn) {
                    btn.disabled = false;
                    if (isLocked) {
                        btn.innerHTML = '<svg class="svg-icon" style="width:16px;height:16px;" viewBox="0 0 24 24"><path d="M12 5v14M5 12h14"></path></svg> 继续生成新数据';
                    } else {
                        btn.innerHTML = '<svg class="svg-icon" style="width:16px;height:16px;" viewBox="0 0 24 24"><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"></path><line x1="21" y1="2" x2="12" y2="11"></line></svg> AI生成数据';
                    }
                }
            }
        }

        // ===== 角色自主手机活动生成 =====
        
        /**
         * 根据AI指令生成角色的手机活动数据
         * 追加到已有的 fp_npc_ 聊天记录中，不覆盖用户通过查手机生成的数据
         * @param {number} charId - 角色ID
         * @param {string} accountId - 用户账号ID
         * @param {string} activityDesc - AI输出的活动描述
         */
        async function generateCharAutonomousActivity(charId, accountId, activityDesc) {
            console.log('[自主活动] 开始生成，角色ID:', charId, '描述:', activityDesc);
            
            const char = await db.characters.get(charId);
            if (!char) {
                console.warn('[自主活动] 角色不存在:', charId);
                return;
            }
            
            const roleName = char.nick || char.name || '角色';
            const roleDesc = char.description || '';
            
            // 获取该角色手机通讯录中的NPC联系人
            const phoneContacts = char.phone_contacts_by_user || {};
            const contactIds = phoneContacts[accountId] || [];
            const allChars = await db.characters.toArray();
            const npcContacts = contactIds
                .map(cid => allChars.find(ch => ch.id === cid))
                .filter(ch => ch && ch.type !== 'user');
            
            if (npcContacts.length === 0) {
                console.log('[自主活动] 角色没有手机联系人，跳过');
                return;
            }
            
            // 构建现有聊天摘要（让AI知道之前的对话内容，以便接着写）
            const existingChatsContext = [];
            if (!char.chat_history_by_user) char.chat_history_by_user = {};
            
            for (const npc of npcContacts) {
                const fpNpcKey = 'fp_npc_' + npc.id;
                const existingHistory = char.chat_history_by_user[fpNpcKey] || [];
                const recentMsgs = existingHistory.slice(-5); // 取最近5条作为上下文
                if (recentMsgs.length > 0) {
                    const lines = recentMsgs.map(m => {
                        const speaker = m.role === 'char' ? roleName : (npc.nick || npc.name);
                        return `${speaker}: ${(m.content || '').substring(0, 50)}`;
                    }).join('\n');
                    existingChatsContext.push(`与「${npc.nick || npc.name}」(${npc.description || '好友'}) 的最近对话:\n${lines}`);
                } else {
                    existingChatsContext.push(`与「${npc.nick || npc.name}」(${npc.description || '好友'}) 暂无对话记录`);
                }
            }
            
            // 获取用户名称
            const myChar = accountId ? await db.characters.get(parseInt(accountId)) : null;
            const userName = myChar?.name || '用户';
            
            // 构建prompt
            const prompt = `你是一个辅助生成角色手机活动数据的AI助手。

角色信息：
- 名字：${roleName}
- 人设：${roleDesc || '暂无'}

当前活动描述：${activityDesc}

角色的手机好友列表：
${npcContacts.map(n => `- ${n.nick || n.name}: ${n.description || '好友'}`).join('\n')}

已有的聊天上下文：
${existingChatsContext.join('\n\n')}

请根据"${activityDesc}"这个活动描述，生成角色在手机上产生的新活动数据。
要求：
1. 新的聊天消息要**接着**已有对话自然地继续，不要重复已有内容
2. 消息内容要符合角色人设和性格
3. 每段对话生成2-5条新消息
4. 不需要对所有好友都生成，根据活动描述选择1-2个相关好友即可
5. role为"char"表示角色（${roleName}）发的，"user"表示好友NPC回复的

请严格按以下JSON格式返回，不要有其他文字：
{
  "chats": {
    "${npcContacts[0]?.nick || npcContacts[0]?.name || 'NPC'}": [
      {"role": "char", "content": "角色发的消息"},
      {"role": "user", "content": "好友的回复"}
    ]
  }${activityDesc.includes('朋友圈') ? `,
  "moments": [
    {"content": "朋友圈文字内容", "images": ["[图片描述]"]}
  ]` : ''}
}`;

            try {
                const aiResult = await callAI([
                    { role: 'system', content: prompt },
                    { role: 'user', content: '请生成活动数据，只返回JSON。' }
                ]);
                
                let parsedData = {};
                try {
                    const jsonMatch = aiResult.match(/\{[\s\S]*\}/);
                    if (jsonMatch) {
                        parsedData = JSON.parse(jsonMatch[0]);
                    }
                } catch (e) {
                    console.error('[自主活动] JSON解析失败:', e);
                    return;
                }
                
                // ===== 追加聊天记录（不覆盖已有数据）=====
                const chatsData = parsedData.chats || {};
                const now = Date.now();
                const freshChar = await db.characters.get(charId);
                if (!freshChar) return;
                if (!freshChar.chat_history_by_user) freshChar.chat_history_by_user = {};
                
                let totalNewMsgs = 0;
                for (const npc of npcContacts) {
                    const npcKey = npc.nick || npc.name;
                    const newMessages = chatsData[npcKey] || [];
                    if (newMessages.length === 0) continue;
                    
                    const fpNpcKey = 'fp_npc_' + npc.id;
                    const existingHistory = freshChar.chat_history_by_user[fpNpcKey] || [];
                    
                    // 追加新消息，时间从现在开始递增
                    newMessages.forEach((m, idx) => {
                        existingHistory.push({
                            role: m.role || 'char',
                            content: m.content || '',
                            time: now + idx * 30000 // 每条消息间隔30秒
                        });
                    });
                    
                    freshChar.chat_history_by_user[fpNpcKey] = existingHistory;
                    totalNewMsgs += newMessages.length;
                }
                
                // ===== 追加朋友圈数据 =====
                if (parsedData.moments && Array.isArray(parsedData.moments) && parsedData.moments.length > 0) {
                    if (!freshChar.fp_moments_by_user) freshChar.fp_moments_by_user = {};
                    const existingMoments = freshChar.fp_moments_by_user[accountId] || [];
                    
                    for (const m of parsedData.moments) {
                        existingMoments.push({
                            author: roleName,
                            content: m.content || '',
                            images: (m.images || []).map(img => {
                                if (typeof img === 'string' && !img.startsWith('[')) return '[' + img + ']';
                                return img;
                            }),
                            likes: m.likes || [],
                            comments: m.comments || [],
                            time: now
                        });
                    }
                    
                    // 按时间倒序排列
                    existingMoments.sort((a, b) => (b.time || 0) - (a.time || 0));
                    freshChar.fp_moments_by_user[accountId] = existingMoments;
                    console.log('[自主活动] 朋友圈追加:', parsedData.moments.length, '条');
                }
                
                // 🛡️ 使用 update() 只更新聊天记录和朋友圈，防止覆盖设置
                const actUpdatePayload = {};
                // 写入各NPC聊天记录
                for (const npc of npcContacts) {
                    const fpNpcKey = 'fp_npc_' + npc.id;
                    if (freshChar.chat_history_by_user[fpNpcKey]) {
                        actUpdatePayload[`chat_history_by_user.${fpNpcKey}`] = freshChar.chat_history_by_user[fpNpcKey];
                    }
                }
                // 写入朋友圈
                if (freshChar.fp_moments_by_user && freshChar.fp_moments_by_user[accountId]) {
                    actUpdatePayload[`fp_moments_by_user.${accountId}`] = freshChar.fp_moments_by_user[accountId];
                }
                if (Object.keys(actUpdatePayload).length > 0) {
                    await safeDexieUpdate(db.characters, charId, actUpdatePayload, `自主活动数据[${freshChar.name}]`);
                }
                console.log('[自主活动] ✅ 数据生成完成，新增聊天消息:', totalNewMsgs);
                
            } catch (e) {
                console.error('[自主活动] AI调用失败:', e);
            }
        }
        
        // ===== 查手机WeChat - 聊天详情（直接复用真实chat-window，通过 _fpChatMode 标记控制） =====
        
        // 打开聊天详情 - 直接复用真实 chat-window，设置 fp 模式标记
        async function openFpChatDetail(contactCharId) {
            const roleId = window._fpWechatRoleId;
            const accountId = findPhoneTargetAccountId;
            
            console.log('[openFpChatDetail] contactCharId=', contactCharId, 'roleId=', roleId, 'accountId=', accountId, 'getCurrentAccountId=', getCurrentAccountId());
            
            const roleChar = await db.characters.get(parseInt(roleId));
            const contactChar = await db.characters.get(parseInt(contactCharId));
            
            if (!roleChar || !contactChar) { console.error('[openFpChatDetail] 角色或联系人不存在'); return; }
            
            // ★ 设置 fp 聊天模式标记 ★
            window._fpChatMode = true;
            window._fpRoleCharId = parseInt(roleId);          // 角色（手机主人，消息右侧=自己）
            window._fpContactCharId = parseInt(contactCharId); // 联系人（消息左侧=对方）
            // NPC联系人使用特殊key存储聊天记录，用户联系人使用正常accountId
            window._fpAccountId = (contactChar.type === 'user') ? accountId : ('fp_npc_' + contactCharId);
            
            // 缓存头像信息供 renderChatBody 和 appendMessageToUI 使用
            window._fpRoleAvatar = getCharAvatar(roleChar, accountId) || roleChar.avatar || '';
            window._fpContactAvatar = contactChar.type === 'user' 
                ? (contactChar.avatar || '') 
                : (getCharAvatar(contactChar, accountId) || contactChar.avatar || '');
            // 联系人名称：如果是用户，优先用角色设置的备注；NPC优先用fp_contact_remarks
            const fpRemarkForUser = roleChar?.fp_remark_by_user?.[accountId] || '';
            if (contactChar.type === 'user') {
                window._fpContactName = fpRemarkForUser || contactChar.nick || contactChar.name || '未知';
            } else {
                window._fpContactName = roleChar?.fp_contact_remarks?.[contactCharId] || getCharDisplayName(contactChar, accountId);
            }
            
            // 设置 currentChatCharId 为角色ID（聊天记录存储在角色身上）
            currentChatCharId = parseInt(roleId);
            window._currentChatCharId = currentChatCharId;
            window.currentGroupChatId = null;
            
            // 设置标题为联系人名称（点击可打开fp聊天详情）
            const titleEl = document.getElementById('chat-title');
            titleEl.innerText = window._fpContactName;
            titleEl.style.cursor = 'pointer';
            titleEl.onclick = () => showFpChatDetailPage();
            
            // 显示真实的 chat-window（z-index 需要高于 fp-wechat-page 的 320）
            const chatWin = document.getElementById('chat-window');
            chatWin.style.display = 'flex';
            chatWin.style.zIndex = '350';
            
            // 显示输入框
            const chatFooter = document.getElementById('chat-footer');
            chatFooter.style.display = 'flex';
            
            // 显示所有按钮（AI魔法棒、表情、菜单等）
            const aiMagicBtn = document.querySelector('.chat-input-bar .chat-icon-btn');
            if (aiMagicBtn) aiMagicBtn.style.display = '';
            const actionPanel = document.getElementById('action-panel');
            if (actionPanel) {
                const actionItems = actionPanel.querySelectorAll('.action-item');
                actionItems.forEach(item => { item.style.display = ''; });
            }
            
            // 重置输入框
            const chatInputBox = document.getElementById('chat-input-box');
            if (chatInputBox) {
                chatInputBox.placeholder = '发送消息...';
                chatInputBox.value = '';
                chatInputBox.readOnly = false;
                chatInputBox.style.opacity = '';
            }
            
            // 渲染聊天内容（renderChatBody 会检测 _fpChatMode 并翻转角色）
            await renderChatBody(roleChar, true);
            
            // 滚动到底部
            setTimeout(() => {
                const body = document.getElementById('chat-body');
                if (body) body.scrollTop = body.scrollHeight;
            }, 100);
        }

        // ===== 查手机WeChat - FP聊天详情页（修改备注、删除好友、拉黑好友） =====
        
        /**
         * 显示FP模式下的聊天详情页
         * 支持：查看联系人资料、修改备注、删除好友、拉黑好友
         */
        async function showFpChatDetailPage() {
            const roleId = window._fpRoleCharId;
            const contactId = window._fpContactCharId;
            const accountId = findPhoneTargetAccountId;
            
            if (!roleId || !contactId) { showToast('无法打开详情'); return; }
            
            const roleChar = await db.characters.get(roleId);
            const contactChar = await db.characters.get(contactId);
            if (!roleChar || !contactChar) { showToast('角色或联系人不存在'); return; }
            
            // 判断联系人类型
            const isUserContact = contactChar.type === 'user';
            
            // 获取联系人的显示信息
            const contactAvatar = isUserContact
                ? (contactChar.avatar || '')
                : (getCharAvatar(contactChar, accountId) || contactChar.avatar || '');
            const contactNickname = isUserContact
                ? (contactChar.nick || contactChar.name || '未知')
                : (getCharWxNickname(contactChar, accountId) || contactChar.nick || contactChar.name || '未知');
            const contactSignature = contactChar.wx_signature || '这个人什么也没有留下';
            
            // 获取当前备注：用户联系人用 fp_remark_by_user，NPC联系人用 fp_contact_remarks
            let currentRemark = '';
            if (isUserContact) {
                currentRemark = roleChar.fp_remark_by_user?.[accountId] || '';
            } else {
                currentRemark = roleChar.fp_contact_remarks?.[contactId] || getCharRemark(contactChar, accountId) || '';
            }
            
            // 移除已有的fp详情页
            const existingPage = document.getElementById('fp-chat-detail-overlay');
            if (existingPage) existingPage.remove();
            
            // 创建详情页
            const overlay = document.createElement('div');
            overlay.id = 'fp-chat-detail-overlay';
            overlay.style.cssText = 'position:fixed; top:0; left:0; right:0; bottom:0; z-index:400; background:#f5f5f5; display:flex; flex-direction:column; animation:slideInRight 0.25s ease;';
            
            const avatarStyle = contactAvatar ? `background-image:url(${contactAvatar}); background-size:cover; background-position:center;` : 'background:#e8e8e8;';
            
            overlay.innerHTML = `
                <style>
                    @keyframes slideInRight { from { transform: translateX(100%); } to { transform: translateX(0); } }
                    @keyframes slideOutRight { from { transform: translateX(0); } to { transform: translateX(100%); } }
                </style>
                <!-- 顶部标题栏 -->
                <div style="display:flex; align-items:center; height:88px; padding-top:44px; padding-bottom:10px; padding-left:16px; padding-right:16px; background:#fff; border-bottom:0.5px solid #e5e5e5; flex-shrink:0; box-sizing:border-box;">
                    <div id="fp-detail-back-btn" style="cursor:pointer; padding:4px; margin-right:8px;">
                        <svg viewBox="0 0 24 24" style="width:24px; height:24px; fill:none; stroke:#333; stroke-width:2; stroke-linecap:round; stroke-linejoin:round;"><polyline points="15 18 9 12 15 6"></polyline></svg>
                    </div>
                    <div style="flex:1; font-size:17px; font-weight:600; color:#1a1a1a; text-align:center;">聊天详情</div>
                    <div style="width:32px;"></div>
                </div>
                
                <!-- 联系人资料卡 -->
                <div style="flex:1; overflow-y:auto;">
                    <div style="display:flex; align-items:center; padding:20px 16px; background:#fff; gap:14px;">
                        <div style="width:64px; height:64px; border-radius:8px; flex-shrink:0; ${avatarStyle}"></div>
                        <div style="flex:1; min-width:0;">
                            <div style="font-size:18px; font-weight:600; color:#1a1a1a; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${contactNickname}</div>
                            <div style="font-size:13px; color:#999; margin-top:4px; line-height:1.4; overflow:hidden; text-overflow:ellipsis; display:-webkit-box; -webkit-line-clamp:2; -webkit-box-orient:vertical;">${contactSignature}</div>
                        </div>
                    </div>
                    
                    <!-- 备注设置 -->
                    <div style="margin-top:8px; background:#fff;">
                        <div style="display:flex; align-items:center; padding:14px 16px; border-bottom:0.5px solid #f0f0f0;">
                            <div style="font-size:15px; color:#333; min-width:60px;">备注</div>
                            <input type="text" id="fp-detail-remark-input" value="${currentRemark.replace(/"/g, '&quot;')}" placeholder="设置备注名" style="flex:1; border:none; background:transparent; text-align:right; font-size:15px; color:#333; outline:none;">
                        </div>
                        <div style="display:flex; align-items:center; padding:14px 16px;">
                            <div style="font-size:15px; color:#333; min-width:60px;">原名</div>
                            <div style="flex:1; text-align:right; font-size:15px; color:#999;">${contactChar.name || '未知'}</div>
                        </div>
                    </div>
                    
                    <!-- 保存备注按钮 -->
                    <div style="margin-top:8px; background:#fff; padding:14px 16px;">
                        <button id="fp-detail-save-remark-btn" style="width:100%; padding:12px; background:linear-gradient(135deg, #07c160, #06ad56); color:#fff; border:none; border-radius:8px; font-size:15px; font-weight:500; cursor:pointer;">保存备注</button>
                    </div>
                    
                    <!-- 危险操作区 -->
                    <div style="margin-top:24px; background:#fff;">
                        <div id="fp-detail-delete-btn" style="display:flex; align-items:center; justify-content:center; padding:14px 16px; cursor:pointer; border-bottom:0.5px solid #f0f0f0; transition:background 0.15s;" onmousedown="this.style.background='#f5f5f5'" onmouseup="this.style.background=''" onmouseleave="this.style.background=''">
                            <span style="font-size:16px; color:#ff3b30;">删除好友</span>
                        </div>
                        <div id="fp-detail-block-btn" style="display:flex; align-items:center; justify-content:center; padding:14px 16px; cursor:pointer; transition:background 0.15s;" onmousedown="this.style.background='#f5f5f5'" onmouseup="this.style.background=''" onmouseleave="this.style.background=''">
                            <span style="font-size:16px; color:#ff3b30; font-weight:600;">拉黑好友</span>
                        </div>
                    </div>
                    
                    <div style="height:40px;"></div>
                </div>
            `;
            
            document.body.appendChild(overlay);
            
            // 绑定返回按钮
            document.getElementById('fp-detail-back-btn').addEventListener('click', () => {
                overlay.style.animation = 'slideOutRight 0.25s ease forwards';
                setTimeout(() => overlay.remove(), 250);
            });
            
            // 绑定保存备注
            document.getElementById('fp-detail-save-remark-btn').addEventListener('click', async () => {
                const newRemark = document.getElementById('fp-detail-remark-input').value.trim();
                const freshRoleChar = await db.characters.get(roleId);
                if (!freshRoleChar) { showToast('角色不存在'); return; }
                
                if (isUserContact) {
                    // 用户联系人：保存到 fp_remark_by_user
                    if (!freshRoleChar.fp_remark_by_user) freshRoleChar.fp_remark_by_user = {};
                    freshRoleChar.fp_remark_by_user[accountId] = newRemark;
                } else {
                    // NPC联系人：保存到 fp_contact_remarks
                    if (!freshRoleChar.fp_contact_remarks) freshRoleChar.fp_contact_remarks = {};
                    freshRoleChar.fp_contact_remarks[contactId] = newRemark;
                }
                
                await safeCharacterPut(freshRoleChar);
                
                // 更新聊天窗口标题
                const displayName = newRemark || contactNickname;
                window._fpContactName = displayName;
                const titleEl = document.getElementById('chat-title');
                if (titleEl) titleEl.innerText = displayName;
                
                showToast('备注已保存');
            });
            
            // 绑定删除好友
            document.getElementById('fp-detail-delete-btn').addEventListener('click', async () => {
                const displayName = currentRemark || contactNickname;
                if (!confirm(`确定要删除好友"${displayName}"吗？\n\n删除后将从角色的通讯录和聊天列表中移除。\n聊天记录会保留，角色之后可能会自己把好友加回来。`)) return;
                
                await fpDeleteFriend(roleId, contactId, accountId, isUserContact);
                
                // 关闭详情页
                overlay.remove();
                // 关闭聊天窗口，返回查手机微信页面
                hideChatWindow();
                // 刷新查手机聊天列表（切回聊天tab）
                await switchFpWechatTab(0);
                showToast('已删除好友');
            });
            
            // 绑定拉黑好友
            document.getElementById('fp-detail-block-btn').addEventListener('click', async () => {
                const displayName = currentRemark || contactNickname;
                if (!confirm(`确定要拉黑"${displayName}"吗？\n\n拉黑后将从角色的通讯录中移除。`)) return;
                
                await fpBlockFriend(roleId, contactId, accountId, isUserContact);
                
                // 关闭详情页
                overlay.remove();
                // 关闭聊天窗口，返回查手机微信页面
                hideChatWindow();
                // 刷新查手机聊天列表（切回聊天tab）
                await switchFpWechatTab(0);
                showToast('已拉黑好友');
            });
        }
        
        /**
         * FP模式下删除好友
         * 从角色的通讯录中移除联系人，清空聊天记录
         */
        async function fpDeleteFriend(roleId, contactId, accountId, isUserContact) {
            const roleChar = await db.characters.get(roleId);
            if (!roleChar) return;
            
            // 1. 从角色通讯录中移除（不清空聊天记录，保留历史）
            if (roleChar.phone_contacts_by_user?.[accountId]) {
                roleChar.phone_contacts_by_user[accountId] = roleChar.phone_contacts_by_user[accountId].filter(id => id !== contactId);
            }
            
            // 2. 记录删除操作（锁定后AI生成新数据时，角色可能自己把好友加回来）
            if (!roleChar.fp_deleted_contacts_by_user) roleChar.fp_deleted_contacts_by_user = {};
            if (!roleChar.fp_deleted_contacts_by_user[accountId]) roleChar.fp_deleted_contacts_by_user[accountId] = [];
            if (!roleChar.fp_deleted_contacts_by_user[accountId].includes(contactId)) {
                roleChar.fp_deleted_contacts_by_user[accountId].push(contactId);
            }
            
            await safeCharacterPut(roleChar);
            console.log(`[FP删除好友] 角色${roleId}删除了联系人${contactId}（聊天记录已保留）`);
        }
        
        /**
         * FP模式下拉黑好友
         * 从角色的通讯录中移除联系人，添加到黑名单
         */
        async function fpBlockFriend(roleId, contactId, accountId, isUserContact) {
            const roleChar = await db.characters.get(roleId);
            if (!roleChar) return;
            
            // 1. 从角色通讯录中移除
            if (roleChar.phone_contacts_by_user?.[accountId]) {
                roleChar.phone_contacts_by_user[accountId] = roleChar.phone_contacts_by_user[accountId].filter(id => id !== contactId);
            }
            
            // 2. 添加到黑名单
            if (!roleChar.fp_blocked_contacts_by_user) roleChar.fp_blocked_contacts_by_user = {};
            if (!roleChar.fp_blocked_contacts_by_user[accountId]) roleChar.fp_blocked_contacts_by_user[accountId] = [];
            if (!roleChar.fp_blocked_contacts_by_user[accountId].includes(contactId)) {
                roleChar.fp_blocked_contacts_by_user[accountId].push(contactId);
            }
            
            // 3. 同时记录到删除名单
            if (!roleChar.fp_deleted_contacts_by_user) roleChar.fp_deleted_contacts_by_user = {};
            if (!roleChar.fp_deleted_contacts_by_user[accountId]) roleChar.fp_deleted_contacts_by_user[accountId] = [];
            if (!roleChar.fp_deleted_contacts_by_user[accountId].includes(contactId)) {
                roleChar.fp_deleted_contacts_by_user[accountId].push(contactId);
            }
            
            await safeCharacterPut(roleChar);
            console.log(`[FP拉黑好友] 角色${roleId}拉黑了联系人${contactId}`);
        }

        // ===== 查手机WeChat - 群聊详情（以角色视角查看群聊，复用真实chat-window） =====
        
        /**
         * 以角色视角打开群聊详情
         * 群聊数据完全复用用户已有数据，只是翻转视角：角色的消息显示在右侧，其他人在左侧
         * @param {number} groupId - 群聊ID
         */
        async function openFpGroupChatDetail(groupId) {
            const roleId = window._fpWechatRoleId;
            const accountId = findPhoneTargetAccountId;
            
            console.log('[openFpGroupChatDetail] groupId=', groupId, 'roleId=', roleId, 'accountId=', accountId);
            
            const group = await getCachedGroupChat(groupId);
            if (!group) { console.error('[openFpGroupChatDetail] 群聊不存在'); return; }
            
            const roleChar = await db.characters.get(parseInt(roleId));
            if (!roleChar) { console.error('[openFpGroupChatDetail] 角色不存在'); return; }
            
            // ★ 设置 fp 群聊模式标记 ★
            window._fpChatMode = true;
            window._fpGroupChatMode = true;
            window._fpRoleCharId = parseInt(roleId); // 群聊中"自己"的角色ID
            window.currentGroupChatId = groupId;
            currentChatCharId = null;
            
            // 缓存角色头像信息
            window._fpRoleAvatar = getCharAvatar(roleChar, accountId) || roleChar.avatar || '';
            
            // 设置标题为群聊名称
            const titleEl = document.getElementById('chat-title');
            titleEl.innerText = group.name || '群聊';
            titleEl.style.cursor = 'default';
            titleEl.onclick = null; // fp模式下不显示群聊详情
            
            // 显示真实的 chat-window（z-index 需要高于 fp-wechat-page 的 320）
            const chatWin = document.getElementById('chat-window');
            chatWin.style.display = 'flex';
            chatWin.style.zIndex = '350';
            
            // 显示输入框
            const chatFooter = document.getElementById('chat-footer');
            chatFooter.style.display = 'flex';
            
            // 显示所有按钮
            const aiMagicBtn = document.querySelector('.chat-input-bar .chat-icon-btn');
            if (aiMagicBtn) aiMagicBtn.style.display = '';
            const actionPanel = document.getElementById('action-panel');
            if (actionPanel) {
                const actionItems = actionPanel.querySelectorAll('.action-item');
                actionItems.forEach(item => { item.style.display = ''; });
            }
            
            // 重置输入框
            const chatInputBox = document.getElementById('chat-input-box');
            if (chatInputBox) {
                chatInputBox.placeholder = '发送消息...';
                chatInputBox.value = '';
                chatInputBox.readOnly = false;
                chatInputBox.style.opacity = '';
            }
            
            // 重置渲染缓存
            lastRenderedCharId = null;
            lastRenderedAccountId = null;
            lastRenderedHistoryLength = -1;
            lastRenderedAvatar = null;
            
            // ★ 渲染群聊内容（renderGroupChatBody 会检测 _fpGroupChatMode 并翻转视角）
            await renderGroupChatBody(group);
            
            // 滚动到底部
            setTimeout(() => {
                const body = document.getElementById('chat-body');
                if (body) body.scrollTop = body.scrollHeight;
            }, 100);
        }
        
        /**
         * 以角色视角打开NPC群聊详情（角色自己的群聊，用户不在其中）
         * 数据存储在角色的 fp_npc_group_chats_by_user 中
         * 使用独立的轻量级聊天展示（只读，不复用 chat-window）
         * @param {number} npcGroupId - NPC群聊ID
         */
        async function openFpNpcGroupChatDetail(npcGroupId) {
            const roleId = window._fpWechatRoleId;
            const accountId = findPhoneTargetAccountId;
            
            const roleChar = await db.characters.get(parseInt(roleId));
            if (!roleChar) return;
            
            const npcGroupChats = roleChar.fp_npc_group_chats_by_user?.[accountId] || [];
            const npcGroup = npcGroupChats.find(g => g.id === npcGroupId);
            if (!npcGroup) { showToast('群聊不存在'); return; }
            
            const roleName = roleChar.nick || roleChar.name || '角色';
            const roleAvatar = getCharAvatar(roleChar, accountId) || roleChar.avatar || '';
            
            // 构建成员头像映射（尝试从通讯录NPC中匹配）
            const allChars = await db.characters.toArray();
            const contactIds = getRolePhoneContacts(roleChar, accountId);
            const memberAvatars = {};
            for (const memberNick of npcGroup.members) {
                if (memberNick === roleName) {
                    memberAvatars[memberNick] = roleAvatar;
                    continue;
                }
                // 尝试从通讯录中匹配
                for (const cid of contactIds) {
                    const npc = allChars.find(ch => ch.id === cid);
                    if (npc && (npc.nick === memberNick || npc.name === memberNick)) {
                        memberAvatars[memberNick] = getCharAvatar(npc, accountId) || npc.avatar || '';
                        break;
                    }
                }
            }
            
            // 生成聊天气泡HTML
            let chatHtml = '';
            for (const msg of npcGroup.chat_history) {
                const isRole = (msg.sender === roleName);
                const avatar = memberAvatars[msg.sender] || '';
                const avatarStyle = avatar ? `background-image:url(${avatar}); background-size:cover; background-position:center;` : 'background-color:#e0e0e0;';
                const timeStr = msg.time ? new Date(msg.time).toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' }) : '';
                
                if (isRole) {
                    // 角色自己的消息 - 右侧
                    chatHtml += `
                        <div style="display:flex; justify-content:flex-end; align-items:flex-start; gap:8px; margin-bottom:12px; padding:0 12px;">
                            <div style="max-width:70%; display:flex; flex-direction:column; align-items:flex-end;">
                                <div style="font-size:11px; color:#999; margin-bottom:3px;">${msg.sender}</div>
                                <div style="background:#95ec69; padding:8px 12px; border-radius:12px 4px 12px 12px; font-size:14px; line-height:1.5; word-break:break-word; color:#000;">${msg.content}</div>
                                ${timeStr ? `<div style="font-size:10px; color:#bbb; margin-top:2px;">${timeStr}</div>` : ''}
                            </div>
                            <div style="width:36px; height:36px; border-radius:6px; flex-shrink:0; ${avatarStyle}"></div>
                        </div>
                    `;
                } else {
                    // 其他成员的消息 - 左侧
                    chatHtml += `
                        <div style="display:flex; justify-content:flex-start; align-items:flex-start; gap:8px; margin-bottom:12px; padding:0 12px;">
                            <div style="width:36px; height:36px; border-radius:6px; flex-shrink:0; ${avatarStyle}"></div>
                            <div style="max-width:70%; display:flex; flex-direction:column; align-items:flex-start;">
                                <div style="font-size:11px; color:#999; margin-bottom:3px;">${msg.sender}</div>
                                <div style="background:#fff; padding:8px 12px; border-radius:4px 12px 12px 12px; font-size:14px; line-height:1.5; word-break:break-word; color:#333; border:0.5px solid #e8e8e8;">${msg.content}</div>
                                ${timeStr ? `<div style="font-size:10px; color:#bbb; margin-top:2px;">${timeStr}</div>` : ''}
                            </div>
                        </div>
                    `;
                }
            }
            
            // 成员列表
            const memberListHtml = npcGroup.members.map(m => {
                const av = memberAvatars[m] || '';
                const avStyle = av ? `background-image:url(${av}); background-size:cover; background-position:center;` : 'background-color:#e0e0e0;';
                return `<div style="display:flex; flex-direction:column; align-items:center; gap:4px; width:50px;">
                    <div style="width:36px; height:36px; border-radius:6px; ${avStyle}"></div>
                    <div style="font-size:11px; color:#666; text-align:center; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; width:100%;">${m}</div>
                </div>`;
            }).join('');
            
            // 创建弹出层（覆盖在fp-wechat-page之上）
            let overlay = document.getElementById('fp-npc-group-overlay');
            if (!overlay) {
                overlay = document.createElement('div');
                overlay.id = 'fp-npc-group-overlay';
                document.body.appendChild(overlay);
            }
            
            overlay.style.cssText = 'position:fixed; top:0; left:0; width:100%; height:100%; z-index:400; display:flex; flex-direction:column; background:#f5f5f5;';
            overlay.innerHTML = `
                <div style="background:#fff; padding:12px 16px; display:flex; align-items:center; gap:12px; border-bottom:0.5px solid #e8e8e8; flex-shrink:0;">
                    <div onclick="document.getElementById('fp-npc-group-overlay').style.display='none'" style="cursor:pointer; display:flex; align-items:center;">
                        <svg viewBox="0 0 24 24" style="width:24px; height:24px; stroke:#333; fill:none; stroke-width:2;"><polyline points="15 18 9 12 15 6"></polyline></svg>
                    </div>
                    <div style="flex:1; font-size:17px; font-weight:600; color:#1a1a1a; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${npcGroup.name || '群聊'}(${npcGroup.members.length})</div>
                </div>
                
                <div style="flex:1; overflow-y:auto; padding:16px 0;" id="fp-npc-group-chat-body">
                    <!-- 群成员头像条 -->
                    <div style="display:flex; gap:8px; padding:0 16px 16px; overflow-x:auto; flex-wrap:nowrap; border-bottom:0.5px solid #eee; margin-bottom:16px;">
                        ${memberListHtml}
                    </div>
                    ${chatHtml || '<div style="text-align:center; color:#ccc; padding:40px; font-size:14px;">暂无消息</div>'}
                </div>
            `;
            
            // 滚动到底部
            setTimeout(() => {
                const chatBody = document.getElementById('fp-npc-group-chat-body');
                if (chatBody) chatBody.scrollTop = chatBody.scrollHeight;
            }, 100);
        }
        
        /**
         * 查手机fp群聊模式 - 以角色身份发送群聊消息
         * 消息保存为 role:'char', senderId 为角色ID
         */
        async function sendFpGroupMessage(text) {
            if (!text || !window.currentGroupChatId || !window._fpRoleCharId) return;
            
            const group = await getCachedGroupChat(window.currentGroupChatId);
            if (!group) return;
            
            const roleCharId = window._fpRoleCharId;
            const roleChar = await db.characters.get(roleCharId);
            if (!roleChar) { showToast('角色不存在'); return; }
            
            const input = document.getElementById('chat-input-box');
            input.value = '';
            handleChatInputChange(input);
            closeChatPanel();
            
            // ★ 以角色身份添加消息到群聊历史
            if (!group.chat_history) group.chat_history = [];
            const msg = {
                role: 'char',
                senderId: roleCharId,
                senderName: roleChar.remark || roleChar.wx_nickname || roleChar.nick || roleChar.name || '角色',
                content: text,
                time: Date.now(),
                fpSent: true // 标记为查手机模式发送
            };
            
            // 如果有引用
            if (currentQuote) {
                msg.quote = {
                    name: currentQuote.name,
                    content: currentQuote.content
                };
                cancelQuote();
            }
            
            group.chat_history.push(msg);
            group.updated_at = Date.now();
            
            await safeGroupChatPut(group);
            
            // 重新渲染群聊
            await renderGroupChatBody(group);
            
            // 滚动到底部
            setTimeout(() => {
                const body = document.getElementById('chat-body');
                if (body) body.scrollTop = body.scrollHeight;
            }, 50);
        }

        // ★ fp模式发送消息：以角色身份发送（role:'char'），消息存到角色的聊天记录中
        async function sendFpChatMessage() {
            const input = document.getElementById('chat-input-box');
            let text = input.value.trim();
            if (!text || !window._fpRoleCharId) return;
            
            const roleCharId = window._fpRoleCharId;
            const accountId = window._fpAccountId;
            
            console.log('[FP发送] roleCharId=', roleCharId, 'fpAccountId=', accountId, 'currentAccountId=', getCurrentAccountId());
            
            if (!accountId) {
                console.error('[FP发送] accountId为空！');
                showToast('发送失败：账号信息丢失');
                return;
            }
            
            const roleChar = await db.characters.get(roleCharId);
            if (!roleChar) { showToast('发送失败：角色不存在'); return; }
            
            // 清空输入框
            input.value = '';
            handleChatInputChange(input);
            closeChatPanel();
            
            // 获取聊天历史
            let history = getChatHistory(roleChar, accountId);
            
            // ★ 核心：消息以 role:'char' 保存（因为是角色在发消息），fpSent 标记为查手机模式发送
            const charMsg = { role: 'char', content: text, time: Date.now(), fpSent: true };
            
            // 如果有引用
            if (currentQuote) {
                charMsg.quote = {
                    name: currentQuote.name,
                    content: currentQuote.content
                };
                cancelQuote();
            }
            
            history.push(charMsg);
            
            try {
                await setChatHistory(roleChar, accountId, history);
                console.log('[FP发送] ✅ 保存成功 roleChar(id=' + roleCharId + ').chat_history_by_user[' + accountId + '], 历史长度=' + history.length);
            } catch (e) {
                console.error('[FP发送] ❌ 保存失败:', e);
                showToast('消息保存失败！');
                return;
            }
            
            // 重新渲染聊天（因为需要翻转角色，直接重新渲染最简单）
            await renderChatBody(roleChar, true);
            
            // 滚动到底部
            setTimeout(() => {
                const body = document.getElementById('chat-body');
                if (body) body.scrollTop = body.scrollHeight;
            }, 50);
        }
        
        // ★ 查手机NPC模式 - NPC视角AI回复
        // NPC以为是角色给他发消息，NPC用自己的人设回复
        async function triggerFpNpcReply() {
            console.log('[FP-NPC回复] ⚡ 触发NPC AI回复');
            
            // 🔧 防止重复调用（超时15秒自动解锁，防止手机端锁死）
            if (window._isGeneratingReply) {
                const elapsed = Date.now() - (window._isGeneratingReplyTime || 0);
                if (elapsed < 15000) {
                    console.log('[FP-NPC回复] 正在生成中，忽略 (已等待' + Math.round(elapsed/1000) + '秒)');
                    showToast('正在生成回复中，请稍候...');
                    return;
                }
                console.warn('[FP-NPC回复] ⚠️ 检测到锁超时，强制重置');
                window._isGeneratingReply = false;
                window._isGeneratingReplyTime = 0;
            }
            
            const roleCharId = window._fpRoleCharId;
            const npcCharId = window._fpContactCharId;
            const fpNpcKey = window._fpAccountId; // 'fp_npc_' + npcId
            
            if (!roleCharId || !npcCharId || !fpNpcKey) {
                console.error('[FP-NPC回复] 缺少必要参数');
                return;
            }
            
            // 🔧 手机端IndexedDB防卡死：用超时保护DB读取
            let roleChar, npcChar;
            try {
                [roleChar, npcChar] = await Promise.race([
                    Promise.all([db.characters.get(roleCharId), db.characters.get(npcCharId)]),
                    new Promise((_, reject) => setTimeout(() => reject(new Error('DB读取超时')), 8000))
                ]);
            } catch (dbErr) {
                console.error('[FP-NPC回复] 数据库读取失败或超时:', dbErr.message);
                showToast('数据读取超时，请重试');
                return;
            }
            if (!roleChar || !npcChar) {
                showToast('角色数据异常');
                return;
            }
            
            window._isGeneratingReply = true;
            window._isGeneratingReplyTime = Date.now();
            
            // 🔧 安全定时器：45秒后强制释放锁（防止await永久挂起导致手机端锁死）
            const _safetyFpLockTimer = setTimeout(() => {
                if (window._isGeneratingReply) {
                    console.warn('[FP-NPC回复] ⏰ 安全定时器触发(45s)，强制释放锁');
                    window._isGeneratingReply = false;
                    window._isGeneratingReplyTime = 0;
                }
            }, 45000);
            
            // 显示"正在输入"
            const chatTitleEl = document.getElementById('chat-title');
            const originalTitle = chatTitleEl ? chatTitleEl.innerText : '';
            if (chatTitleEl) chatTitleEl.innerText = '对方正在输入中...';
            
            try {
                const npcName = npcChar.nick || npcChar.name || 'NPC';
                const npcDesc = npcChar.description || '';
                const roleName = roleChar.nick || roleChar.name || '角色';
                const roleDesc = roleChar.description || '';
                
                // 获取聊天历史（存储在 roleChar.chat_history_by_user['fp_npc_' + npcId]）
                const fullHistory = getChatHistory(roleChar, fpNpcKey);
                console.log('[FP-NPC回复] 聊天历史条数:', fullHistory.length);
                
                // 构建NPC视角的系统提示
                const now = new Date();
                const timeStr = `${now.getFullYear()}年${now.getMonth()+1}月${now.getDate()}日 ${now.getHours()}:${String(now.getMinutes()).padStart(2,'0')}`;
                
                // 🔧 检查 NovelAI 自动生图是否开启，决定 imgcard 是否需要附带英文 tag
                const _novelaiAutoGenEnabledFp = await isNovelAIAutoGenerateEnabled();
                
                let systemPrompt = `# 角色扮演任务

【当前时间】
${timeStr}

---

## 你是谁

**你的名字**：${npcName}
**你的人设**：${npcDesc}

你不是AI助手。你是一个独立的人，有自己的生活、情绪和想法。

---

## 你的对话对象

**对方名字**：${roleName}
**对方信息**：${roleDesc}

你正在用微信和 ${roleName} 聊天。${roleName} 是给你发消息的人。

---

## 扮演原则

1. 完全沉浸在你的人设里，像真人一样聊天
2. 你有自己的情绪和想法
3. 根据你和${roleName}的关系来调整语气和态度
4. 对话要自然、口语化
5. **不要只回答！要主动分享、追问、延展话题**

---

## 微信聊天方式

你在用微信聊天，可以用：
- **文字**：直接说话
- **语音**：\`[voice:内容]\`
- **图片/卡片**：${_novelaiAutoGenEnabledFp ? `\`[imgcard:中文图片描述{{english, novelai, tags}}]\`（发图片时必须在 {{ }} 内写英文 NovelAI/Danbooru 风格 tag。根据角色性别用1boy或1girl，包含外貌特征、服装、表情、动作、场景，不加质量词，不超过25个tag）` : `\`[imgcard:图片描述]\``}
- **转账**：\`((TRANSFER: 金额, 备注))\`
- **购物送礼**：\`((SHOP_GIFT: 金额, 商品名))\`（给对方买礼物，可选分期）
- **表情包**：\`[sticker:描述]\`（如果有的话）

**图片使用规则**：发图片时，必须同时发送文字消息，用 \`|||\` 和文字组合。禁止只发一条图片卡片不说话。
${_novelaiAutoGenEnabledFp ? `例：\`嘿 刚洗完澡~|||[imgcard:洗完澡的自拍{{1girl, wet hair, towel, bathroom, mirror, smile, looking at viewer}}]|||好看吗\`` : `例：\`嘿 刚洗完澡~|||[imgcard:洗完澡的自拍]|||好看吗\``}

---

## 气泡分割（极其重要！）

真人在微信上不会把话堆在一条里，而是一句话一个气泡：
- 每句话单独一条消息，用 \`|||\` 分隔
- 一条消息只说一件事或一个语气，绝对不要把多句塞进同一条
- 像真人打字：短、快、口语化，少用标点

---

## 回复格式

用JSON格式返回（不要有markdown标记）：
\`\`\`
{
  "reply": "第一条消息|||第二条消息",
  "thought": "你此刻内心的想法"
}
\`\`\`

**重要**：
- reply 文本内禁止使用逗号（但 \`{{}}\` 标签内的逗号例外），JSON 字段之间的逗号必须保留
- **thought 字段是必填项！必须写出你此刻的真实心理活动（至少10个字）**
- thought 必须是真实情绪和内心想法，不要写系统分析

---

现在，作为 **${npcName}**，根据你的人设和对话历史，像真人一样回复 ${roleName} 吧。`;

                // 构建消息历史（从NPC视角看：char=角色发的→对NPC来说是user，user=NPC发的→对NPC来说是assistant）
                const contextCount = 20;
                const recentHistory = fullHistory
                    .slice(-contextCount)
                    .filter(m => m.role !== 'system')
                    .map(m => {
                        let content = m.content || '';
                        // 在这个聊天记录中：role:'char' = 角色发的（NPC视角的user），role:'user' = NPC发的（NPC视角的assistant）
                        const aiRole = m.role === 'char' ? 'user' : 'assistant';
                        
                        // 处理特殊消息格式
                        if (content.startsWith('[img:')) content = '（发送了一张图片/表情包）';
                        else if (content.startsWith('[imgcard:')) content = '（发送了一张图片卡片）';
                        else if (content.startsWith('[voice:')) {
                            const voiceContent = content.match(/\[voice:(.*?)\]/)?.[1] || '';
                            content = `（发送语音消息：${voiceContent}）`;
                        }
                        else if (m.type === 'transfer') {
                            try {
                                const t = JSON.parse(content);
                                content = aiRole === 'user' 
                                    ? `（对方给你转账了${t.amount}元，备注：${t.desc || '转账'}）`
                                    : `（你给对方转账了${t.amount}元，备注：${t.desc || '转账'}）`;
                            } catch(e) { content = '（一笔转账）'; }
                        }
                        else if (m.type === 'location') {
                            try {
                                const l = JSON.parse(content);
                                content = `（位置分享："${l.name}"）`;
                            } catch(e) { content = '（一条位置分享）'; }
                        }
                        
                        return { role: aiRole, content: content };
                    })
                    .filter(m => m.content && m.content.trim());
                
                // 如果最后一条是assistant（NPC发的），添加触发消息
                const messages = [
                    { role: 'system', content: systemPrompt },
                    ...recentHistory
                ];
                
                if (messages.length > 1) {
                    const lastMsg = messages[messages.length - 1];
                    if (lastMsg.role === 'assistant') {
                        messages.push({
                            role: 'user',
                            content: `[系统指令] ${roleName}没有回复，请你作为${npcName}继续这个话题。`
                        });
                    }
                }
                
                console.log('[FP-NPC回复] 发送给AI的消息数:', messages.length);
                
                // 调用AI
                const aiResponse = await callAI(messages);
                
                // 解析回复
                let replyText = '';
                let thought = '';
                
                const parsed = extractAndParseJSON(aiResponse);
                if (parsed) {
                    replyText = parsed.reply || parsed.content || parsed.message || '';
                    thought = parsed.thought || '';
                }
                if (!replyText) {
                    const replyMatch = aiResponse.match(/"reply"\s*:\s*"([\s\S]*?)"/);
                    if (replyMatch) {
                        replyText = replyMatch[1].replace(/\\n/g, '\n').replace(/\\"/g, '"').replace(/\\\\/g, '\\');
                    } else {
                        replyText = aiResponse.trim() || '(NPC 返回为空)';
                    }
                }
                
                // 清理回复文本
                replyText = replyText.replace(/\s*\[DONE\]\s*$/i, '').trim();
                replyText = replyText.replace(/(\|\|\|)+$/g, '').replace(/^\|\|\|/g, '').replace(/\|\|\|\|\|\|/g, '|||').trim();
                
                console.log('[FP-NPC回复] AI回复:', replyText);
                if (thought) console.log('[FP-NPC回复] NPC心声:', thought);
                
                // 分割消息并逐条保存
                const segments = replyText.split('|||').map(s => s.trim()).filter(s => s.length > 0);
                
                // 重新获取最新的roleChar
                const freshRoleChar = await db.characters.get(roleCharId);
                let history = getChatHistory(freshRoleChar, fpNpcKey);
                
                for (let i = 0; i < segments.length; i++) {
                    let seg = segments[i];
                    
                    // 检测转账
                    const transferMatch = seg.match(/\(\(TRANSFER:\s*(\d+(?:\.\d+)?)(?:,\s*(.+?))?\)\)/i);
                    // 检测购物送礼
                    const fpShopGiftMatch = !transferMatch ? seg.match(/\(\(SHOP_GIFT:\s*(\d+(?:\.\d+)?)(?:,\s*(.+?))?\)\)/i) : null;
                    
                    if (transferMatch) {
                        const amount = parseFloat(transferMatch[1]);
                        const note = transferMatch[2] || '转账';
                        const textBefore = seg.substring(0, transferMatch.index).trim();
                        
                        // 如果转账前有文字，先保存文字
                        if (textBefore) {
                            const textMsg = { role: 'user', content: textBefore, time: Date.now() + i * 2 };
                            history.push(textMsg);
                            await setChatHistory(freshRoleChar, fpNpcKey, history);
                            if (currentChatCharId === roleCharId) {
                                await renderChatBody(freshRoleChar, true);
                            }
                            await new Promise(r => setTimeout(r, 300));
                        }
                        
                        // 保存转账消息
                        const transferData = { amount: amount.toFixed(2), desc: note, status: 'sent' };
                        const transferMsg = { role: 'user', type: 'transfer', content: JSON.stringify(transferData), time: Date.now() + i * 2 + 1 };
                        history.push(transferMsg);
                        await setChatHistory(freshRoleChar, fpNpcKey, history);
                        if (currentChatCharId === roleCharId) {
                            await renderChatBody(freshRoleChar, true);
                        }
                        
                        // ✅ NPC给角色转账 → 角色FP钱包收入
                        const fpWalletAccId = findPhoneTargetAccountId || getCurrentAccountId();
                        if (fpWalletAccId) {
                            const npcDisplayName = npcChar?.nick || npcChar?.name || 'NPC联系人';
                            await fpWalletTransaction(roleCharId, fpWalletAccId, 'income', amount, '转账收款', `来自${npcDisplayName} - ${note}`);
                            console.log(`[FP-NPC转账] ✅ 角色收入 ¥${amount.toFixed(2)} (来自${npcDisplayName})`);
                        }
                    } else if (fpShopGiftMatch) {
                        const gAmt = parseFloat(fpShopGiftMatch[1]);
                        let gName = fpShopGiftMatch[2] || '购物礼物';
                        if (gName.length > 30) gName = gName.substring(0, 30);
                        const textBefore = seg.substring(0, fpShopGiftMatch.index).trim();
                        
                        if (textBefore) {
                            history.push({ role: 'user', content: textBefore, time: Date.now() + i * 2 });
                            await setChatHistory(freshRoleChar, fpNpcKey, history);
                            if (currentChatCharId === roleCharId) await renderChatBody(freshRoleChar, true);
                            await new Promise(r => setTimeout(r, 300));
                        }
                        
                        const giftCardData = { amount: gAmt.toFixed(2), items: gName, buyForName: '', installmentInfo: '', isGift: true, status: 'paid' };
                        const giftMsg = { role: 'user', type: 'shopPayRequest', content: JSON.stringify(giftCardData), time: Date.now() + i * 2 + 1 };
                        history.push(giftMsg);
                        await setChatHistory(freshRoleChar, fpNpcKey, history);
                        if (currentChatCharId === roleCharId) {
                            if (window._appendShopCardToChat) {
                                await window._appendShopCardToChat(roleCharId, giftMsg);
                            } else {
                                await renderChatBody(freshRoleChar, true);
                            }
                        }
                    } else {
                        // 普通消息：保存为 role:'user'（NPC发的消息在角色聊天记录中是user）
                        const npcMsg = { role: 'user', content: seg, time: Date.now() + i * 2 };
                        if (thought && i === 0) npcMsg.thought = thought;
                        history.push(npcMsg);
                        await setChatHistory(freshRoleChar, fpNpcKey, history);
                        
                        if (currentChatCharId === roleCharId) {
                            await renderChatBody(freshRoleChar, true);
                        }
                    }
                    
                    // 消息间延迟
                    if (i < segments.length - 1) {
                        await new Promise(r => setTimeout(r, 400 + Math.random() * 300));
                    }
                }
                
                // 滚动到底部
                setTimeout(() => {
                    const body = document.getElementById('chat-body');
                    if (body) body.scrollTop = body.scrollHeight;
                }, 100);
                
            } catch(e) {
                console.error('[FP-NPC回复] 失败:', e);
                showToast('NPC回复失败：' + (e.message || '未知错误'));
            } finally {
                clearTimeout(_safetyFpLockTimer);
                window._isGeneratingReply = false;
                window._isGeneratingReplyTime = 0;
                if (chatTitleEl) chatTitleEl.innerText = originalTitle;
            }
        }
        
        // 各项自定义方法（修改后自动保存到Dexie，上传图片自动压缩）
        function setWallpaper(input) {
            const file = input.files[0];
            if (file) {
                const reader = new FileReader();
                reader.onload = async e => {
                    const compressed = await compressImage(e.target.result, 1200, 0.8);
                    applyWallpaper(compressed);
                };
                reader.readAsDataURL(file);
            }
            input.value = '';
        }
        function selectIcon(iconId) {
            currentSelectIcon = iconId;
            document.getElementById('custom-icon-input').click();
        }
        function setCustomIcon(input) {
            const file = input.files[0];
            if (file && currentSelectIcon) {
                const reader = new FileReader();
                reader.onload = async e => {
                    const compressed = await compressImage(e.target.result, 256, 0.8);
                    applyIcon(currentSelectIcon, compressed);
                };
                reader.readAsDataURL(file);
            }
            input.value = '';
        }
        function setWidgetIcon(input) {
            const file = input.files[0];
            if (file) {
                const reader = new FileReader();
                reader.onload = async e => {
                    const compressed = await compressImage(e.target.result, 256, 0.8);
                    applyWidgetIcon(compressed);
                };
                reader.readAsDataURL(file);
            }
            input.value = '';
        }
        function setPhoto(pos, input) {
            const file = input.files[0];
            if (file) {
                const reader = new FileReader();
                reader.onload = async e => {
                    const compressed = await compressImage(e.target.result, 800, 0.75);
                    applyPhoto(pos, compressed);
                };
                reader.readAsDataURL(file);
            }
            input.value = '';
        }
        function setAvatar(id, input) {
            const file = input.files[0];
            if (file) {
                const reader = new FileReader();
                reader.onload = async e => {
                    const compressed = await compressImage(e.target.result, 400, 0.8);
                    applyAvatar(id, compressed);
                };
                reader.readAsDataURL(file);
            }
            input.value = '';
        }

        // ===== 统一 apply 函数（同时更新桌面 + 设置页预览） =====
        function applyWallpaper(url) {
            document.getElementById('desktop-body').style.backgroundImage = `url(${url})`;
            const preview = document.getElementById('wallpaper-preview');
            if (preview) { preview.style.backgroundImage = `url(${url})`; preview.innerText = ''; }
            autoSaveCustomization();
        }
        function applyIcon(iconId, url, triggerEl) {
            let iconDom = document.getElementById(`icon-${iconId}`)?.querySelector('.icon') || document.getElementById(`dock-${iconId}`)?.querySelector('.icon');
            if (iconDom) iconDom.style.backgroundImage = `url(${url})`;
            // 同步设置页图标预览
            const settingsItem = document.querySelector(`.icon-select-item[data-icon-id="${iconId}"] .icon`);
            if (settingsItem) settingsItem.style.backgroundImage = `url(${url})`;
            if (triggerEl) {
                const previewIcon = triggerEl.querySelector('.icon');
                if (previewIcon) previewIcon.style.backgroundImage = `url(${url})`;
            }
            autoSaveCustomization();
        }
        function applyWidgetIcon(url) {
            document.getElementById('widget-icon').style.backgroundImage = `url(${url})`;
            const preview = document.getElementById('widget-icon-preview');
            if (preview) preview.style.backgroundImage = `url(${url})`;
            autoSaveCustomization();
        }
        function applyPhoto(pos, url) {
            document.getElementById(`img-${pos}`).style.backgroundImage = `url(${url})`;
            const preview = document.getElementById(`photo-${pos}-preview`);
            if (preview) preview.style.backgroundImage = `url(${url})`;
            autoSaveCustomization();
        }
        function applyAvatar(id, url) {
            const img = document.getElementById(`avatar-img-${id}`);
            if (img) { img.style.backgroundImage = `url(${url})`; img.classList.add('has-image'); }
            const preview = document.getElementById(`avatar${id}-preview`);
            if (preview) preview.style.backgroundImage = `url(${url})`;
            autoSaveCustomization();
        }

        // ===== 统一图片选择弹窗 =====
        let _imgPickerCallback = null;
        function showImagePicker(config) {
            // config: { onApply: function(url) }
            const existing = document.getElementById('image-picker-modal');
            if (existing) existing.remove();
            _imgPickerCallback = config.onApply;

            const overlay = document.createElement('div');
            overlay.id = 'image-picker-modal';
            overlay.className = 'image-picker-overlay';
            overlay.innerHTML = `
                <div class="image-picker-card">
                    <div class="image-picker-title">选择图片来源</div>
                    <div class="image-picker-option" onclick="imagePickerFromGallery()">
                        <span style="font-size:20px;">📷</span>
                        <span>从相册选择</span>
                    </div>
                    <div class="image-picker-option" onclick="imagePickerShowUrlInput()">
                        <span style="font-size:20px;">🔗</span>
                        <span>粘贴图片链接</span>
                    </div>
                    <div class="image-picker-url-area" id="image-picker-url-area" style="display:none;">
                        <input type="text" class="image-picker-url-input" id="image-picker-url-input" placeholder="粘贴图片链接地址" oninput="imagePickerPreviewUrl(this.value)" onfocus="setTimeout(()=>this.scrollIntoView({behavior:'smooth',block:'center'}),300)" style="font-size:16px;">
                        <div class="image-picker-preview-box" id="image-picker-preview-box">图片预览</div>
                        <div class="image-picker-confirm" onclick="imagePickerConfirmUrl()">确认使用</div>
                    </div>
                    <div class="image-picker-cancel" onclick="closeImagePicker()">取消</div>
                </div>
            `;
            overlay.onclick = (e) => { if (e.target === overlay) closeImagePicker(); };
            document.body.appendChild(overlay);
        }
        function imagePickerFromGallery() {
            let input = document.getElementById('image-picker-file-input');
            if (!input) {
                input = document.createElement('input');
                input.type = 'file';
                input.id = 'image-picker-file-input';
                input.accept = 'image/*';
                input.style.display = 'none';
                document.body.appendChild(input);
            }
            input.onchange = function() {
                const file = this.files[0];
                if (file && _imgPickerCallback) {
                    const reader = new FileReader();
                    reader.onload = async e => {
                        const compressed = await compressImage(e.target.result, 1200, 0.8);
                        _imgPickerCallback(compressed);
                        closeImagePicker();
                    };
                    reader.readAsDataURL(file);
                }
                this.value = '';
            };
            input.click();
        }
        function imagePickerShowUrlInput() {
            const area = document.getElementById('image-picker-url-area');
            if (area) {
                area.style.display = 'flex';
                // 🔧 键盘适配：输入框显示后自动聚焦，并在键盘弹起后滚动到可见区域
                setTimeout(() => {
                    const urlInput = document.getElementById('image-picker-url-input');
                    if (urlInput) {
                        urlInput.focus();
                        urlInput.scrollIntoView({ behavior: 'smooth', block: 'center' });
                    }
                }, 300);
            }
        }
        function imagePickerPreviewUrl(url) {
            url = url.trim();
            const box = document.getElementById('image-picker-preview-box');
            if (!box) return;
            if (url) {
                box.style.backgroundImage = `url(${url})`;
                box.style.backgroundSize = 'cover';
                box.style.backgroundPosition = 'center';
                box.innerText = '';
            } else {
                box.style.backgroundImage = '';
                box.innerText = '图片预览';
            }
        }
        function imagePickerConfirmUrl() {
            const url = document.getElementById('image-picker-url-input')?.value?.trim();
            if (url && _imgPickerCallback) {
                _imgPickerCallback(url);
            }
            closeImagePicker();
        }
        function closeImagePicker() {
            const modal = document.getElementById('image-picker-modal');
            if (modal) modal.remove();
            _imgPickerCallback = null;
        }
        // 设置页图标点击 —— 弹出图片选择器
        function selectIconPicker(el, iconId) {
            showImagePicker({
                onApply: (url) => applyIcon(iconId, url, el)
            });
        }
        
        // 自动保存个性化设置（防抖，避免频繁写入）
        let _autoSaveTimer = null;
        function autoSaveCustomization() {
            if (_autoSaveTimer) clearTimeout(_autoSaveTimer);
            _autoSaveTimer = setTimeout(async () => {
                try {
                    // 保存所有图片相关的数据到Dexie
                    const saveItems = {};
                    
                    // 壁纸
                    const wallpaper = document.getElementById('desktop-body')?.style.backgroundImage?.replace(/url\(|\)|"/g, '') || '';
                    if (wallpaper) saveItems.wallpaper = wallpaper;
                    
                    // 小组件图标
                    const widgetIcon = document.getElementById('widget-icon')?.style.backgroundImage?.replace(/url\(|\)|"/g, '') || '';
                    if (widgetIcon) saveItems.widgetIcon = widgetIcon;
                    
                    // 拍立得
                    const photoLeft = document.getElementById('img-left')?.style.backgroundImage?.replace(/url\(|\)|"/g, '') || '';
                    const photoRight = document.getElementById('img-right')?.style.backgroundImage?.replace(/url\(|\)|"/g, '') || '';
                    if (photoLeft) saveItems.photoLeft = photoLeft;
                    if (photoRight) saveItems.photoRight = photoRight;
                    
                    // 头像
                    const avatar1 = document.getElementById('avatar-img-1')?.style.backgroundImage?.replace(/url\(|\)|"/g, '') || '';
                    const avatar2 = document.getElementById('avatar-img-2')?.style.backgroundImage?.replace(/url\(|\)|"/g, '') || '';
                    if (avatar1) saveItems.avatar1 = avatar1;
                    if (avatar2) saveItems.avatar2 = avatar2;
                    
                    // 应用图标
                    const iconIds = ['appstore','notes','remind','facetime','photo','xianyu','cabin','icity','findphone'];
                    iconIds.forEach(id => {
                        const el = document.getElementById(`icon-${id}`)?.querySelector('.icon');
                        if (el?.style.backgroundImage) {
                            const val = el.style.backgroundImage.replace(/url\(|\)|"/g, '');
                            if (val) saveItems[`icon${id.charAt(0).toUpperCase() + id.slice(1)}`] = val;
                        }
                    });
                    
                    // Dock图标
                    const dockIds = ['setting','custom','message','phone'];
                    dockIds.forEach(id => {
                        const el = document.getElementById(`dock-${id}`)?.querySelector('.icon');
                        if (el?.style.backgroundImage) {
                            const val = el.style.backgroundImage.replace(/url\(|\)|"/g, '');
                            if (val) saveItems[`dock${id.charAt(0).toUpperCase() + id.slice(1)}`] = val;
                        }
                    });
                    
                    // 写入Dexie
                    for (const [key, value] of Object.entries(saveItems)) {
                        await db.dexiData.put({ key, value });
                    }
                    
                    console.log('[AutoSave] ✓ 图标/壁纸自动保存成功');
                } catch (err) {
                    console.error('[AutoSave] ✗ 自动保存失败:', err);
                }
            }, 500); // 500ms 防抖
        }

