/**
 * 用户更换头像后，向所有角色的聊天记录中插入系统消息（类似拍一拍）
 * 同时附带新头像的图片数据，让AI能识别头像内容
 * @param {object} userChar - 用户角色对象
 */
async function notifyAvatarChanged(userChar) {
    if (!userChar) return;
    const userName = userChar.nick || userChar.name || '用户';
    const noticeText = `"${userName}" 更换了头像`;
    const accountId = getCurrentAccountId();
    // 获取用户当前新头像（已经更新后的）
    const newAvatarUrl = userChar.avatar || '';
    
    try {
        // 获取所有非用户角色（即聊天对象）
        const allChars = await db.characters.toArray();
        const chatChars = allChars.filter(c => c.type !== 'user' && c.id !== userChar.id);
        
        for (const char of chatChars) {
            try {
                let history = getChatHistory(char, accountId);
                // 只在有聊天记录的角色中插入通知（没聊过的不插入）
                if (history.length === 0) continue;
                
                const msgData = {
                    role: 'system',
                    content: noticeText,
                    time: Date.now(),
                    type: 'avatar_change'
                };
                // 附带新头像的图片URL，供AI识图使用
                if (newAvatarUrl) {
                    msgData.avatarImage = newAvatarUrl;
                }
                
                history.push(msgData);
                await setChatHistory(char, accountId, history);
                console.log(`[AvatarChange] ✅ 已向 ${char.name}(${char.id}) 的聊天中插入头像更换系统消息${newAvatarUrl ? '（含头像图片）' : ''}`);
            } catch (e) {
                console.error(`[AvatarChange] 向 ${char.name} 插入通知失败:`, e);
            }
        }
        
        console.log(`[AvatarChange] ✅ 头像更换通知已写入聊天记录（含头像图片，供AI识图）`);
    } catch (e) {
        console.error('[AvatarChange] 广播头像更换通知失败:', e);
    }
}

// 辅助函数：获取格式化的虚拟时间字符串
function getFormattedVirtualTime(offsetOrChar) {
    const offset = (typeof offsetOrChar === 'object' && offsetOrChar !== null)
        ? getEffectiveTimeOffset(offsetOrChar)
        : (offsetOrChar || 0);
    const now = Date.now();
    const virtualNow = new Date(now + offset);
    
    const year = virtualNow.getFullYear();
    const month = virtualNow.getMonth() + 1;
    const day = virtualNow.getDate();
    const hours = virtualNow.getHours().toString().padStart(2, '0');
    const mins = virtualNow.getMinutes().toString().padStart(2, '0');
    const weekDays = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
    const week = weekDays[virtualNow.getDay()];
    
    return `${year}年${month}月${day}日 ${hours}:${mins} (${week})`;
}

// 辅助函数：获取角色和用户最近的朋友圈动态，用于注入AI聊天上下文
async function getRecentMomentsContext(charId, accountId, maxCount = 10) {
    try {
        if (!charId || !accountId) return '';

        const allMoments = await db.moments.toArray();
        const charIdNum = parseInt(charId);
        const accountIdNum = parseInt(accountId);

        // 获取角色（NPC）自己发的朋友圈
        const charMoments = allMoments
            .filter(m => parseInt(m.userId) === charIdNum)
            .sort((a, b) => (b.time || 0) - (a.time || 0))
            .slice(0, maxCount);

        // 获取用户发的朋友圈
        const userMoments = allMoments
            .filter(m => parseInt(m.userId) === accountIdNum)
            .sort((a, b) => (b.time || 0) - (a.time || 0))
            .slice(0, maxCount);

        if (charMoments.length === 0 && userMoments.length === 0) return '';

        const formatMoment = (m) => {
            const t = m.time ? new Date(m.time).toLocaleString('zh-CN', {
                month: 'numeric', day: 'numeric', hour: '2-digit', minute: '2-digit'
            }) : '未知时间';
            let text = m.content || '（无文字）';
            let imgInfo = '';
            if (m.images && m.images.length > 0) imgInfo = `（附${m.images.length}张图）`;
            // 点赞和评论摘要
            let interaction = '';
            if (m.likes && m.likes.length > 0) {
                const likeNames = m.likes.map(l => typeof l === 'string' ? l : (l.name || '')).filter(Boolean).slice(0, 5).join('、');
                interaction += ` [${m.likes.length}人点赞${likeNames ? '：' + likeNames : ''}]`;
            }
            if (m.comments && m.comments.length > 0) {
                const commentPreview = m.comments.slice(0, 3).map(c => {
                    const cName = c.name || '好友';
                    const cText = (c.text || c.content || '').slice(0, 20);
                    return `${cName}: ${cText}`;
                }).join('；');
                interaction += ` [${m.comments.length}条评论：${commentPreview}]`;
            }
            return `  [${t}] ${text}${imgInfo}${interaction}`;
        };

        let context = '\n\n## 朋友圈动态\n';
        context += '以下是你和对方最近的朋友圈，你可以自然地在聊天中提到或回应这些内容。\n';

        if (charMoments.length > 0) {
            context += `\n【你自己最近发的朋友圈】\n`;
            charMoments.forEach(m => { context += formatMoment(m) + '\n'; });
        }
        if (userMoments.length > 0) {
            context += `\n【对方最近发的朋友圈】\n`;
            userMoments.forEach(m => { context += formatMoment(m) + '\n'; });
        }

        return context;
    } catch (e) {
        console.warn('[getRecentMomentsContext] 获取朋友圈上下文失败:', e);
        return '';
    }
}

