// 短信编辑模式状态
let isMessageEditMode = false;
let selectedMessageChats = new Set();

// 切换短信编辑模式
async function toggleMessageEditMode() {
    isMessageEditMode = !isMessageEditMode;
    selectedMessageChats.clear();
    
    const editBtn = document.getElementById('message-edit-btn');
    const listContainer = document.getElementById('message-chat-list-container');
    
    if (isMessageEditMode) {
        editBtn.textContent = '完成';
        if (listContainer) {
            listContainer.classList.add('edit-mode');
        }
        // 显示切换账号和删除按钮
        showMessageEditActions();
    } else {
        editBtn.textContent = '编辑';
        if (listContainer) {
            listContainer.classList.remove('edit-mode');
        }
        // 隐藏操作按钮
        hideMessageEditActions();
    }
    
    // 重新渲染列表以显示选择框
    await renderMessageList();
}

// 显示编辑模式操作按钮
function showMessageEditActions() {
    const actionsContainer = document.getElementById('message-edit-actions');
    if (actionsContainer) {
        actionsContainer.style.display = 'block';
    }
    updateMessageDeleteButton();
}

// 隐藏编辑模式操作按钮
function hideMessageEditActions() {
    const actionsContainer = document.getElementById('message-edit-actions');
    if (actionsContainer) {
        actionsContainer.style.display = 'none';
    }
    const deleteBtn = document.getElementById('message-delete-btn');
    if (deleteBtn) {
        deleteBtn.style.display = 'none';
    }
}

// 在编辑模式下显示切换账号按钮
async function showMessageSwitchAccount() {
    await showSwitchAccountModal();
}

// 切换短信聊天选择状态
async function toggleMessageChatSelection(chatId) {
    if (!isMessageEditMode) return;
    
    // 不允许选择欢迎小助手
    if (chatId === 'welcome') return;
    
    if (selectedMessageChats.has(chatId)) {
        selectedMessageChats.delete(chatId);
    } else {
        selectedMessageChats.add(chatId);
    }
    
    await renderMessageList();
    updateMessageDeleteButton();
}

// 更新删除按钮状态
function updateMessageDeleteButton() {
    const deleteBtn = document.getElementById('message-delete-btn');
    if (deleteBtn) {
        if (selectedMessageChats.size > 0) {
            deleteBtn.style.display = 'flex';
            deleteBtn.textContent = `删除(${selectedMessageChats.size})`;
        } else {
            deleteBtn.style.display = 'none';
        }
    }
}

// 删除选中的短信聊天
async function deleteSelectedMessageChats() {
    if (selectedMessageChats.size === 0) return;
    
    // 过滤掉欢迎小助手（不允许删除）
    const chatsToDelete = Array.from(selectedMessageChats).filter(id => id !== 'welcome');
    if (chatsToDelete.length === 0) return;
    
    if (!confirm(`确定要删除选中的 ${chatsToDelete.length} 个聊天吗？`)) {
        return;
    }
    
    const accountId = getCurrentAccountId();
    if (!accountId) return;
    
    // 从 Dexie 删除选中聊天的所有消息
    const allMessages = await db.sms_messages.where('accountId').equals(accountId).toArray();
    const idsToDelete = allMessages.filter(msg => {
        let chatId;
        if (msg.type === 'sent') {
            chatId = msg.number || msg.receiverId || msg.sender;
        } else {
            chatId = msg.number || msg.sender;
        }
        return chatsToDelete.includes(chatId);
    }).map(msg => msg.id);
    
    await db.sms_messages.bulkDelete(idsToDelete);
    
    // 如果当前打开的聊天被删除了，先返回列表页
    if (currentMessageChatId && selectedMessageChats.has(currentMessageChatId)) {
        goBackMessageList();
    }
    
    // 清空选择并退出编辑模式
    selectedMessageChats.clear();
    isMessageEditMode = false;
    
    const editBtn = document.getElementById('message-edit-btn');
    if (editBtn) editBtn.textContent = '编辑';
    
    const listContainer = document.getElementById('message-chat-list-container');
    if (listContainer) {
        listContainer.classList.remove('edit-mode');
    }
    
    hideMessageEditActions();
    
    // 重新渲染列表
    await renderMessageList();
}

// 渲染信息列表
async function renderMessageList() {
    const listContainer = document.getElementById('message-chat-list-container');
    if (!listContainer) return;
    
    // 🎯 从 Dexie 读取短信记录（按账号过滤）
    const accountId = getCurrentAccountId();
    let smsMessages = [];
    
    if (accountId) {
        smsMessages = await db.sms_messages.where('accountId').equals(accountId).toArray();
    }
    
    // 按聊天ID分组（修复：发送的消息使用接收者ID，接收的消息使用发送者ID）
    const groupedChats = {};
    
    // 预加载角色头像缓存
    const charAvatarCache = {};
    
    for (const msg of smsMessages) {
        // 🎯 修复：对于发送的消息，使用number（接收者ID）分组
        // 对于接收的消息，使用number或sender（发送者ID）分组
        let chatId;
        if (msg.type === 'sent') {
            // 发送的消息：使用number字段（应该是接收者的ID）
            chatId = msg.number || msg.receiverId || msg.sender;
        } else {
            // 接收的消息：使用发送者的ID
            chatId = msg.number || msg.sender;
        }
        
        if (!groupedChats[chatId]) {
            // 🎯 修复：显示接收者的名字（对于发送的消息，使用存储的接收者信息）
            let displayName = msg.sender;
            let displayAvatar = '';
            
            // 如果有 charId，从数据库获取角色头像
            if (msg.charId && !charAvatarCache[msg.charId]) {
                const char = await db.characters.get(msg.charId);
                if (char) {
                    charAvatarCache[msg.charId] = getCharAvatar(char, getCurrentAccountId());
                }
            }
            if (msg.charId && charAvatarCache[msg.charId]) {
                displayAvatar = charAvatarCache[msg.charId];
            }
            
            // 如果是发送的消息，使用存储的接收者信息
            if (msg.type === 'sent' && msg.receiverName) {
                displayName = msg.receiverName;
                // 查找同聊天中接收的消息，获取接收者头像
                const receivedMsg = smsMessages.find(m => 
                    (m.number || m.sender) === chatId && m.type !== 'sent'
                );
                if (receivedMsg && receivedMsg.charId) {
                    if (!charAvatarCache[receivedMsg.charId]) {
                        const char = await db.characters.get(receivedMsg.charId);
                        if (char) charAvatarCache[receivedMsg.charId] = getCharAvatar(char, getCurrentAccountId());
                    }
                    displayAvatar = charAvatarCache[receivedMsg.charId] || displayAvatar;
                }
            }
            
            groupedChats[chatId] = {
                id: chatId,
                name: displayName,
                avatar: displayAvatar,
                number: msg.number,
                messages: [],
                isBlocked: msg.isBlocked || false
            };
        }
        groupedChats[chatId].messages.push(msg);
    }
    
    // 转换成数组并按最新消息时间排序
    const chats = Object.values(groupedChats).map(chat => {
        // 🎯 修复：按时间排序，取最新的消息作为预览
        chat.messages.sort((a, b) => (a.time || a.timestamp || 0) - (b.time || b.timestamp || 0));
        const lastMsg = chat.messages[chat.messages.length - 1]; // 取最后一条（最新的）
        return {
            ...chat,
            time: formatMessageTime(lastMsg.time),
            preview: lastMsg.content,
            unread: !lastMsg.read
        };
    }).sort((a, b) => {
        // 按最新消息时间降序排列
        const aLastTime = a.messages[a.messages.length - 1].time || 0;
        const bLastTime = b.messages[b.messages.length - 1].time || 0;
        return bLastTime - aLastTime;
    });
    
    // 始终添加欢迎消息（确保它始终显示在列表中）
    // 检查是否已存在欢迎消息，如果不存在则添加
    const hasWelcome = chats.some(chat => chat.id === 'welcome');
    if (!hasWelcome) {
        chats.push({
            id: 'welcome',
            name: '欢迎小助手',
            avatar: 'https://img.icons8.com/color/96/chat.png',
            time: '刚刚',
            preview: '欢迎使用这个网页！',
            unread: false
        });
    }
    
    // 批量构建HTML后一次性插入，避免多次触发DOM回流
    const htmlParts = [];
    chats.forEach(chat => {
        const unreadClass = chat.unread ? 'message-unread' : '';
        const unreadDot = chat.unread ? `<div class="message-unread-dot"></div>` : '';
        const isSelected = selectedMessageChats.has(chat.id);
        const selectedClass = isSelected ? 'message-chat-selected' : '';
        
        // 欢迎小助手在编辑模式下不显示选择框，也不能被选择
        const isWelcome = chat.id === 'welcome';
        const showCheckbox = isMessageEditMode && !isWelcome;
        
        // 编辑模式下显示选择框，否则直接打开聊天（欢迎小助手始终可以打开）
        const onClickAction = showCheckbox
            ? `toggleMessageChatSelection('${chat.id}')`
            : `openMessageChat('${chat.id}')`;
        
        const checkbox = showCheckbox
            ? `<div class="message-chat-checkbox ${isSelected ? 'checked' : ''}">
                <svg viewBox="0 0 24 24" style="width:20px;height:20px;stroke:currentColor;fill:none;stroke-width:3;">
                    ${isSelected ? '<path d="M20 6L9 17l-5-5"></path>' : ''}
                </svg>
               </div>`
            : '';
        
        const defaultAvatarClass = chat.avatar ? '' : 'default-avatar';
        const avatarImg = chat.avatar 
            ? `<img src="${chat.avatar}" style="width:100%;height:100%;object-fit:cover;" onerror="this.style.display='none';this.parentElement.classList.add('default-avatar');">`
            : '';
        
        htmlParts.push(`
            <div class="message-chat-item ${unreadClass} ${selectedClass}" onclick="${onClickAction}">
                ${checkbox}
                <div class="message-avatar ${defaultAvatarClass}">
                    ${avatarImg}
                </div>
                <div class="message-chat-info">
                    <div class="message-chat-top">
                        <span class="message-chat-name">${chat.name}</span>
                        <div class="message-chat-time">
                            <span>${chat.time}</span>
                        </div>
                    </div>
                    <div class="message-chat-bottom">
                        <div class="message-chat-preview">${chat.preview}</div>
                        ${unreadDot}
                    </div>
                </div>
            </div>
        `);
    });
    listContainer.innerHTML = htmlParts.join('');
    
    // 更新删除按钮
    updateMessageDeleteButton();
}

// 格式化消息时间（列表视图用）
function formatMessageTime(timestamp, timeOffset = 0) {
    // 使用虚拟时间进行计算
    const virtualNow = Date.now() + timeOffset;
    const virtualTimestamp = timestamp + timeOffset;
    const diff = virtualNow - virtualTimestamp;
    const date = new Date(virtualTimestamp);
    
    const timeStr = date.getHours() + ':' + String(date.getMinutes()).padStart(2, '0');
    
    // 1分钟内
    if (diff < 60000) {
        return '刚刚';
    }
    // 1小时内
    if (diff < 3600000) {
        return Math.floor(diff / 60000) + '分钟前';
    }
    // 今天
    const today = new Date(virtualNow);
    if (date.getDate() === today.getDate() && 
        date.getMonth() === today.getMonth() && 
        date.getFullYear() === today.getFullYear()) {
        return timeStr;
    }
    // 昨天
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);
    if (date.getDate() === yesterday.getDate() && 
        date.getMonth() === yesterday.getMonth() && 
        date.getFullYear() === yesterday.getFullYear()) {
        return '昨天 ' + timeStr;
    }
    // 一周内
    if (diff < 7 * 24 * 3600000) {
        const days = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
        return days[date.getDay()] + ' ' + timeStr;
    }
    // 更早（同年显示月/日，不同年显示年/月/日）
    if (date.getFullYear() === today.getFullYear()) {
        return (date.getMonth() + 1) + '月' + date.getDate() + '日 ' + timeStr;
    }
    return date.getFullYear() + '/' + (date.getMonth() + 1) + '/' + date.getDate();
}

// 格式化短信详情页的时间戳（显示完整日期和时间）
function formatSmsDetailTime(timestamp) {
    if (!timestamp) return '';
    const date = new Date(timestamp);
    const now = new Date();
    
    const hours = date.getHours();
    const minutes = String(date.getMinutes()).padStart(2, '0');
    const timeStr = `${hours}:${minutes}`;
    
    // 今天：只显示时间
    if (date.getDate() === now.getDate() && 
        date.getMonth() === now.getMonth() && 
        date.getFullYear() === now.getFullYear()) {
        return `今天 ${timeStr}`;
    }
    
    // 昨天
    const yesterday = new Date(now);
    yesterday.setDate(yesterday.getDate() - 1);
    if (date.getDate() === yesterday.getDate() && 
        date.getMonth() === yesterday.getMonth() && 
        date.getFullYear() === yesterday.getFullYear()) {
        return `昨天 ${timeStr}`;
    }
    
    // 一周内
    const diff = now - date;
    if (diff < 7 * 24 * 3600000) {
        const days = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
        return `${days[date.getDay()]} ${timeStr}`;
    }
    
    // 今年
    if (date.getFullYear() === now.getFullYear()) {
        return `${date.getMonth() + 1}月${date.getDate()}日 ${timeStr}`;
    }
    
    // 更早
    return `${date.getFullYear()}年${date.getMonth() + 1}月${date.getDate()}日 ${timeStr}`;
}

// 当前短信聊天的联系人ID（全局变量）
let currentMessageChatId = null;
let currentMessageChatName = null;

// 打开聊天详情
async function openMessageChat(id) {
    console.log('openMessageChat called with id:', id);
    
    const accountId = getCurrentAccountId();
    
    // 🎯 从 Dexie 读取短信记录
    let smsMessages = [];
    if (accountId) {
        smsMessages = await db.sms_messages.where('accountId').equals(accountId).toArray();
    }
    
    // 查找该联系人的所有消息（修复：支持发送和接收的消息）
    const chatMessages = smsMessages.filter(msg => {
        if (msg.type === 'sent') {
            // 发送的消息：使用number（接收者ID）或receiverId匹配
            return (msg.number || msg.receiverId) === id;
        } else {
            // 接收的消息：使用发送者的ID匹配
            return (msg.number || msg.sender) === id;
        }
    });
    
    if (chatMessages.length === 0 && id !== 'welcome') {
        // 如果是从新建短信流程来的，允许打开空聊天
        if (window._smsSelectedCharId) {
            const targetChar = await db.characters.get(window._smsSelectedCharId);
            if (targetChar) {
                const _smsAid = getCurrentAccountId();
                const charName = getCharDisplayName(targetChar, _smsAid);
                const charAvatar = getCharAvatar(targetChar, _smsAid);
                currentMessageChatId = id;
                currentMessageChatName = charName;
                
                // 🔧 iOS修复：先显示详情页再延迟隐藏列表页，防止过渡时露出桌面
                const listPage = document.getElementById('message-list-page');
                const detailPage = document.getElementById('message-detail-page');
                detailPage.style.display = 'flex';
                setTimeout(() => {
                    detailPage.classList.add('active');
                }, 10);
                // 等详情页滑入动画完成后再隐藏列表页（0.4s动画 + 缓冲）
                setTimeout(() => {
                    if (listPage) listPage.style.display = 'none';
                }, 450);
                
                // 设置头像
                const avatarEl = document.getElementById('message-detail-avatar');
                if (avatarEl) {
                    const avatarContainer = avatarEl.parentElement;
                    if (charAvatar) {
                        avatarEl.src = charAvatar;
                        avatarEl.style.display = '';
                        avatarContainer.classList.remove('default-avatar');
                        avatarEl.onerror = function() {
                            this.style.display = 'none';
                            avatarContainer.classList.add('default-avatar');
                        };
                    } else {
                        avatarEl.style.display = 'none';
                        avatarContainer.classList.add('default-avatar');
                    }
                }
                document.getElementById('message-detail-name').innerText = charName;
                document.getElementById('message-container').innerHTML = '';
                
                // 初始化输入框状态
                const msgInput = document.getElementById('message-msg-input');
                if (msgInput) {
                    msgInput.value = '';
                    handleMessageInputChange(msgInput);
                }
                
                return;
            }
        }
        console.error('Chat not found:', id);
        return;
    }
    
    // 构建聊天对象
    let chat;
    if (id === 'welcome') {
        // 欢迎消息
        chat = {
            id: 'welcome',
            name: '欢迎小助手',
            avatar: 'https://img.icons8.com/color/96/chat.png',
            chatTimeLabel: '刚刚',
            messages: [{
                type: 'received',
                text: '欢迎使用这个网页！🎉\n\n这是一个仿 iOS 风格的信息应用，你可以在这里：\n\n• 查看和管理你的信息\n• 与好友聊天\n• 发送和接收消息\n\n希望你能喜欢这个设计！如有任何问题，随时告诉我。'
            }]
        };
        currentMessageChatId = null;
        currentMessageChatName = null;
    } else {
        // 真实短信
        console.log('[openMessageChat] 聊天消息数量:', chatMessages.length);
        console.log('[openMessageChat] 第一条消息:', chatMessages[0]);
        
        // 🎯 修复：找到接收消息来确定接收者信息（如果只有发送消息，使用存储的接收者信息）
        const receivedMsg = chatMessages.find(msg => msg.type !== 'sent');
        const firstMsg = receivedMsg || chatMessages[chatMessages.length - 1]; // 优先使用接收消息，否则用最早的消息
        
        console.log('[openMessageChat] 第一条消息内容:', firstMsg);
        
        // 确定显示的名字和头像（从角色数据库获取）
        let displayName = firstMsg.sender;
        let displayAvatar = '';
        
        // 如果有 charId，从数据库获取角色头像（按账号隔离）
        const _msgAid = getCurrentAccountId();
        if (firstMsg.charId) {
            const char = await db.characters.get(firstMsg.charId);
            if (char) {
                displayAvatar = getCharAvatar(char, _msgAid) || displayAvatar;
            }
        }
        
        // 如果第一条消息是发送的消息，使用存储的接收者信息
        if (firstMsg.type === 'sent' && firstMsg.receiverName) {
            displayName = firstMsg.receiverName;
            // 尝试从接收消息中获取头像
            const receivedMsgForAvatar = chatMessages.find(msg => msg.type !== 'sent');
            if (receivedMsgForAvatar && receivedMsgForAvatar.charId) {
                const char = await db.characters.get(receivedMsgForAvatar.charId);
                if (char) {
                    displayAvatar = getCharAvatar(char, _msgAid) || displayAvatar;
                }
            }
        }
        
        console.log('[openMessageChat] 显示名称:', displayName);
        console.log('[openMessageChat] 显示头像:', displayAvatar);
        
        // 🔥 修复：按时间戳排序，确保最早的消息在最上面
        chatMessages.sort((a, b) => (a.time || a.timestamp || 0) - (b.time || b.timestamp || 0));
        
        chat = {
            id: id,
            name: displayName,
            avatar: displayAvatar,
            chatTimeLabel: formatMessageTime(firstMsg.time || firstMsg.timestamp || Date.now()),
            messages: chatMessages.map((msg, idx) => {
                const msgText = msg.content || msg.message || '';
                console.log('[openMessageChat] 映射消息:', { type: msg.type, text: msgText });
                return {
                    id: msg.id || `msg_${idx}_${Date.now()}`,
                    type: msg.type || (msg.sender === displayName ? 'received' : 'sent'),
                    text: msgText,
                    time: msg.time || msg.timestamp || 0,
                    originalMsg: msg // 保存原始消息数据以便后续操作
                };
            })
        };
        
        console.log('[openMessageChat] 最终聊天对象:', chat);
        
        // 保存当前聊天信息
        currentMessageChatId = id;
        currentMessageChatName = displayName;
        
        // 标记为已读（修复：支持发送和接收的消息）
        const idsToUpdate = chatMessages.map(msg => msg.id);
        for (const msgId of idsToUpdate) {
            await db.sms_messages.update(msgId, { read: true });
        }
    }
    
    // 🔧 iOS修复：先显示详情页再延迟隐藏列表页，防止过渡时露出桌面
    const listPage = document.getElementById('message-list-page');
    
    // 显示详情页
    const detailPage = document.getElementById('message-detail-page');
    if (!detailPage) {
        console.error('Detail page not found');
        return;
    }
    
    // 先设置 display，再添加 active 类触发动画
    detailPage.style.display = 'flex';
    // 使用 setTimeout 确保 display 设置后再触发动画
    setTimeout(() => {
        detailPage.classList.add('active');
    }, 10);
    // 等详情页滑入动画完成后再隐藏列表页（0.4s动画 + 缓冲）
    setTimeout(() => {
        if (listPage) listPage.style.display = 'none';
    }, 450);
    
    // 设置聊天信息
    document.getElementById('message-detail-name').innerText = chat.name;
    const avatarEl = document.getElementById('message-detail-avatar');
    if (avatarEl) {
        const avatarContainer = avatarEl.parentElement;
        if (chat.avatar) {
            avatarEl.src = chat.avatar;
            avatarEl.style.display = '';
            avatarContainer.classList.remove('default-avatar');
            avatarEl.onerror = function() {
                this.style.display = 'none';
                avatarContainer.classList.add('default-avatar');
            };
        } else {
            avatarEl.style.display = 'none';
            avatarContainer.classList.add('default-avatar');
        }
    }
    
    // 渲染消息
    const msgContainer = document.getElementById('message-container');
    if (!msgContainer) {
        console.error('Message container not found');
        return;
    }
    
    // 渲染消息，在有时间间隔的地方插入时间戳
    const firstMsgTime = chat.messages.length > 0 && chat.messages[0].time ? chat.messages[0].time : 0;
    let htmlContent = `<div class="message-ts-group"><span class="message-ts-label">iMessage</span><span class="message-ts-time">${firstMsgTime ? formatSmsDetailTime(firstMsgTime) : (chat.chatTimeLabel || '今天')}</span></div>`;
    
    let lastTimestamp = firstMsgTime;
    chat.messages.forEach((msg, index) => {
        // 如果与上一条消息间隔超过5分钟，插入时间戳
        if (index > 0 && msg.time && lastTimestamp) {
            const gap = msg.time - lastTimestamp;
            if (gap > 5 * 60 * 1000) { // 5分钟
                htmlContent += `<div class="message-ts-group"><span class="message-ts-time">${formatSmsDetailTime(msg.time)}</span></div>`;
            }
        }
        if (msg.time) lastTimestamp = msg.time;
        
        htmlContent += `<div class="message-wrapper" data-msg-id="${msg.id}" data-msg-index="${index}">
            <div class="message-bubble ${msg.type === 'sent' ? 'message-sent' : 'message-received'}" 
                 data-msg-text="${escapeHtml(msg.text)}"
                 data-msg-type="${msg.type}">${msg.text.replace(/\n/g, '<br>')}</div>
        </div>`;
        if (msg.type === 'sent' && index === chat.messages.length - 1) {
            htmlContent += `<div class="message-delivery-text" style="opacity:1">已送达</div>`;
        }
    });
    
    msgContainer.innerHTML = htmlContent;
    
    // 为所有消息气泡添加长按事件
    attachMessageLongPressEvents();
    
    // 滚动到底部
    setTimeout(() => {
        const scrollArea = document.getElementById('message-area-scroll');
        if (scrollArea) {
            scrollArea.scrollTo({ top: scrollArea.scrollHeight, behavior: 'instant' });
        }
    }, 10);
    
    // 初始化输入框状态（隐藏发送按钮，显示麦克风）
    const msgInput = document.getElementById('message-msg-input');
    if (msgInput) {
        msgInput.value = '';
        handleMessageInputChange(msgInput);
    }
}

// ==================== 消息长按和多选功能 ====================
let messageMultiSelectMode = false;
let selectedMessageIds = new Set();
let currentEditingMessageId = null;

// HTML转义函数
function escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// 为消息气泡添加长按事件
function attachMessageLongPressEvents() {
    const messageBubbles = document.querySelectorAll('.message-bubble');
    let longPressTimer = null;
    let longPressTarget = null;
    
    messageBubbles.forEach(bubble => {
        // 清除之前的事件监听器
        const newBubble = bubble.cloneNode(true);
        bubble.parentNode.replaceChild(newBubble, bubble);
        
        // 长按开始
        newBubble.addEventListener('touchstart', function(e) {
            if (messageMultiSelectMode) return;
            longPressTarget = this;
            longPressTimer = setTimeout(() => {
                showMessageActionMenu(this, e);
                longPressTimer = null;
            }, 500); // 500ms长按
        });
        
        // 长按结束
        newBubble.addEventListener('touchend', function(e) {
            if (longPressTimer) {
                clearTimeout(longPressTimer);
                longPressTimer = null;
            }
        });
        
        // 移动时取消长按
        newBubble.addEventListener('touchmove', function(e) {
            if (longPressTimer) {
                clearTimeout(longPressTimer);
                longPressTimer = null;
            }
        });
        
        // 鼠标事件（桌面端）
        newBubble.addEventListener('contextmenu', function(e) {
            if (messageMultiSelectMode) return;
            e.preventDefault();
            showMessageActionMenu(this, e);
        });
    });
}

// 显示消息操作菜单
function showMessageActionMenu(bubble, event) {
    // 移除之前的菜单
    const existingMenu = document.getElementById('message-action-menu');
    if (existingMenu) {
        existingMenu.remove();
    }
    
    const msgWrapper = bubble.closest('.message-wrapper');
    const msgId = msgWrapper.getAttribute('data-msg-id');
    const msgText = bubble.getAttribute('data-msg-text');
    const msgType = bubble.getAttribute('data-msg-type');
    
    // 创建菜单
    const menu = document.createElement('div');
    menu.id = 'message-action-menu';
    menu.className = 'message-action-menu';
    menu.innerHTML = `
        <div class="message-action-item" onclick="copyMessage('${msgId}')">
            <svg viewBox="0 0 24 24" style="width:20px;height:20px;"><rect x="9" y="9" width="13" height="13" rx="2" ry="2" fill="none" stroke="currentColor" stroke-width="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" fill="none" stroke="currentColor" stroke-width="2"></path></svg>
            <span>复制</span>
        </div>
        ${msgType === 'sent' ? `
        <div class="message-action-item" onclick="editMessage('${msgId}')">
            <svg viewBox="0 0 24 24" style="width:20px;height:20px;"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7" fill="none" stroke="currentColor" stroke-width="2"></path><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z" fill="none" stroke="currentColor" stroke-width="2"></path></svg>
            <span>编辑</span>
        </div>
        ` : ''}
        <div class="message-action-item" onclick="deleteMessage('${msgId}')">
            <svg viewBox="0 0 24 24" style="width:20px;height:20px;"><polyline points="3 6 5 6 21 6" fill="none" stroke="currentColor" stroke-width="2"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2" fill="none" stroke="currentColor" stroke-width="2"></path></svg>
            <span>删除</span>
        </div>
        <div class="message-action-item" onclick="enterMultiSelectMode('${msgId}')">
            <svg viewBox="0 0 24 24" style="width:20px;height:20px;"><polyline points="9 11 12 14 22 4" fill="none" stroke="currentColor" stroke-width="2"></polyline><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11" fill="none" stroke="currentColor" stroke-width="2"></path></svg>
            <span>多选</span>
        </div>
    `;
    
    document.body.appendChild(menu);
    
    // 计算菜单位置
    const rect = bubble.getBoundingClientRect();
    const menuRect = menu.getBoundingClientRect();
    let left = rect.left + rect.width / 2 - menuRect.width / 2;
    let top = rect.top - menuRect.height - 10;
    
    // 确保菜单不超出屏幕
    if (left < 10) left = 10;
    if (left + menuRect.width > window.innerWidth - 10) {
        left = window.innerWidth - menuRect.width - 10;
    }
    if (top < 10) {
        top = rect.bottom + 10;
    }
    
    menu.style.left = left + 'px';
    menu.style.top = top + 'px';
    
    // 点击外部关闭菜单
    setTimeout(() => {
        const closeMenu = (e) => {
            if (!menu.contains(e.target)) {
                menu.remove();
                document.removeEventListener('click', closeMenu);
                document.removeEventListener('touchstart', closeMenu);
            }
        };
        document.addEventListener('click', closeMenu);
        document.addEventListener('touchstart', closeMenu);
    }, 100);
}

// 复制消息
function copyMessage(msgId) {
    const msgWrapper = document.querySelector(`.message-wrapper[data-msg-id="${msgId}"]`);
    if (!msgWrapper) return;
    
    const bubble = msgWrapper.querySelector('.message-bubble');
    const msgText = bubble.getAttribute('data-msg-text');
    
    // 解码HTML实体
    const textarea = document.createElement('textarea');
    textarea.value = msgText.replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&').replace(/<br>/g, '\n');
    document.body.appendChild(textarea);
    textarea.select();
    document.execCommand('copy');
    document.body.removeChild(textarea);
    
    // 显示提示
    showToast('已复制');
    document.getElementById('message-action-menu')?.remove();
}

// 编辑消息
async function editMessage(msgId) {
    const msgWrapper = document.querySelector(`.message-wrapper[data-msg-id="${msgId}"]`);
    if (!msgWrapper) return;
    
    const bubble = msgWrapper.querySelector('.message-bubble');
    const msgText = bubble.getAttribute('data-msg-text');
    const decodedText = msgText.replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&').replace(/<br>/g, '\n');
    
    // 显示编辑输入框
    const input = document.getElementById('message-msg-input');
    if (input) {
        input.value = decodedText;
        input.focus();
        currentEditingMessageId = msgId;
        handleMessageInputChange(input);
    }
    
    document.getElementById('message-action-menu')?.remove();
}

// 删除单条消息
async function deleteMessage(msgId) {
    if (!confirm('确定要删除这条消息吗？')) {
        document.getElementById('message-action-menu')?.remove();
        return;
    }
    
    const msgWrapper = document.querySelector(`.message-wrapper[data-msg-id="${msgId}"]`);
    if (!msgWrapper) return;
    
    // 从数据库删除
    try {
        await db.sms_messages.delete(msgId);
    } catch (e) {
        console.error('删除消息失败:', e);
    }
    
    // 从界面移除
    msgWrapper.remove();
    
    // 重新渲染消息列表
    if (currentMessageChatId) {
        await openMessageChat(currentMessageChatId);
    }
    
    document.getElementById('message-action-menu')?.remove();
    showToast('已删除');
}

// 进入多选模式
function enterMultiSelectMode(initialMsgId) {
    messageMultiSelectMode = true;
    selectedMessageIds.clear();
    if (initialMsgId) {
        selectedMessageIds.add(initialMsgId);
    }
    
    // 更新UI
    updateMessageSelectionUI();
    showMultiSelectToolbar();
    
    document.getElementById('message-action-menu')?.remove();
}

// 退出多选模式
function exitMultiSelectMode() {
    messageMultiSelectMode = false;
    selectedMessageIds.clear();
    updateMessageSelectionUI();
    hideMultiSelectToolbar();
}

// 切换消息选择状态
function toggleMessageSelection(msgId) {
    if (!messageMultiSelectMode) {
        enterMultiSelectMode(msgId);
        return;
    }
    
    if (selectedMessageIds.has(msgId)) {
        selectedMessageIds.delete(msgId);
    } else {
        selectedMessageIds.add(msgId);
    }
    
    updateMessageSelectionUI();
    updateMultiSelectToolbar();
}

// 更新消息选择UI
function updateMessageSelectionUI() {
    const msgWrappers = document.querySelectorAll('.message-wrapper');
    msgWrappers.forEach(wrapper => {
        const msgId = wrapper.getAttribute('data-msg-id');
        const bubble = wrapper.querySelector('.message-bubble');
        
        if (messageMultiSelectMode) {
            wrapper.classList.add('multi-select-mode');
            if (selectedMessageIds.has(msgId)) {
                wrapper.classList.add('selected');
                bubble.classList.add('selected');
            } else {
                wrapper.classList.remove('selected');
                bubble.classList.remove('selected');
            }
            
            // 添加点击事件切换选择
            bubble.onclick = (e) => {
                e.stopPropagation();
                toggleMessageSelection(msgId);
            };
        } else {
            wrapper.classList.remove('multi-select-mode', 'selected');
            bubble.classList.remove('selected');
            bubble.onclick = null;
        }
    });
}

// 显示多选工具栏
function showMultiSelectToolbar() {
    let toolbar = document.getElementById('message-multi-select-toolbar');
    if (!toolbar) {
        toolbar = document.createElement('div');
        toolbar.id = 'message-multi-select-toolbar';
        toolbar.className = 'message-multi-select-toolbar';
        toolbar.innerHTML = `
            <div class="multi-select-toolbar-left">
                <button class="multi-select-btn cancel-btn" onclick="exitMultiSelectMode()">取消</button>
            </div>
            <div class="multi-select-toolbar-center">
                <span class="multi-select-count">已选择 <span id="selected-count">0</span> 条</span>
            </div>
            <div class="multi-select-toolbar-right">
                <button class="multi-select-btn delete-btn" onclick="deleteSelectedMessages()" id="multi-delete-btn" disabled>删除</button>
            </div>
        `;
        document.getElementById('message-detail-page').appendChild(toolbar);
    }
    toolbar.style.display = 'flex';
    updateMultiSelectToolbar();
}

// 隐藏多选工具栏
function hideMultiSelectToolbar() {
    const toolbar = document.getElementById('message-multi-select-toolbar');
    if (toolbar) {
        toolbar.style.display = 'none';
    }
}

// 更新多选工具栏
function updateMultiSelectToolbar() {
    const count = selectedMessageIds.size;
    const countSpan = document.getElementById('selected-count');
    if (countSpan) {
        countSpan.textContent = count;
    }
    
    const deleteBtn = document.getElementById('multi-delete-btn');
    if (deleteBtn) {
        deleteBtn.disabled = count === 0;
    }
}

// 删除选中的消息
async function deleteSelectedMessages() {
    if (selectedMessageIds.size === 0) return;
    
    if (!confirm(`确定要删除选中的 ${selectedMessageIds.size} 条消息吗？`)) {
        return;
    }
    
    // 从数据库删除
    for (const msgId of selectedMessageIds) {
        try {
            await db.sms_messages.delete(msgId);
        } catch (e) {
            console.error('删除消息失败:', e);
        }
    }
    
    // 重新渲染
    if (currentMessageChatId) {
        await openMessageChat(currentMessageChatId);
    }
    
    exitMultiSelectMode();
    showToast(`已删除 ${selectedMessageIds.size} 条消息`);
}

// 显示提示
function showToast(message) {
    let toast = document.getElementById('message-toast');
    if (!toast) {
        toast = document.createElement('div');
        toast.id = 'message-toast';
        toast.className = 'message-toast';
        document.body.appendChild(toast);
    }
    toast.textContent = message;
    toast.style.display = 'block';
    setTimeout(() => {
        toast.style.display = 'none';
    }, 2000);
}

// 确保函数在全局作用域
window.openMessageChat = openMessageChat;
window.sendMessageDetail = sendMessageDetail;
window.handleMessageInputChange = handleMessageInputChange;
window.acceptMessageReply = acceptMessageReply;
window.toggleMessageEditMode = toggleMessageEditMode;
window.toggleMessageChatSelection = toggleMessageChatSelection;
window.deleteSelectedMessageChats = deleteSelectedMessageChats;
window.showMessageSwitchAccount = showMessageSwitchAccount;
window.copyMessage = copyMessage;
window.editMessage = editMessage;
window.deleteMessage = deleteMessage;
window.enterMultiSelectMode = enterMultiSelectMode;
window.exitMultiSelectMode = exitMultiSelectMode;
window.toggleMessageSelection = toggleMessageSelection;
window.deleteSelectedMessages = deleteSelectedMessages;

function showMessagePage() {
    document.getElementById('message-page').classList.add('active');
    // 默认显示列表页
    document.getElementById('message-list-page').style.display = 'flex';
    // 确保详情页和新建页隐藏
    const detailPage = document.getElementById('message-detail-page');
    if (detailPage) {
        detailPage.classList.remove('active');
        detailPage.style.display = 'none';
    }
    const composePage = document.getElementById('message-compose-page');
    if (composePage) {
        composePage.classList.remove('active');
        composePage.style.display = 'none';
    }
    // 渲染列表
    renderMessageList();
}

function hideMessagePage() {
    const msgPage = document.getElementById('message-page');
    msgPage.classList.remove('active');
    // 🔧 清除键盘适配状态
    msgPage.style.top = '';
    msgPage.style.removeProperty('height');
    msgPage.style.bottom = '';
    msgPage.classList.remove('keyboard-up');
    document.getElementById('message-list-page').style.display = 'none';
    document.getElementById('message-detail-page').classList.remove('active');
    document.getElementById('message-compose-page').classList.remove('active');
}

function goBackMessageList() {
    // 退出多选模式
    if (messageMultiSelectMode) {
        exitMultiSelectMode();
    }
    
    const detailPage = document.getElementById('message-detail-page');
    if (detailPage) {
        detailPage.classList.remove('active');
        // 等待动画完成后再隐藏
        setTimeout(() => {
            detailPage.style.display = 'none';
        }, 400);
    }
    
    // 🔧 清除键盘适配状态（返回列表时恢复全屏）
    const msgPage = document.getElementById('message-page');
    if (msgPage) {
        msgPage.style.top = '';
        msgPage.style.removeProperty('height');
        msgPage.style.bottom = '';
        msgPage.classList.remove('keyboard-up');
    }
    
    // 显示列表页
    const listPage = document.getElementById('message-list-page');
    if (listPage) {
        listPage.style.display = 'flex';
    }
}

// 新建短信：步骤式选择联系人 + 用户档案
let composeSelectedCharId = null; // 选中的角色ID

async function openComposeMessage() {
    composeSelectedCharId = null;
    
    // 重置UI
    document.getElementById('compose-step-title').textContent = '选择联系人';
    document.getElementById('compose-step-char').style.display = 'block';
    document.getElementById('compose-step-user').style.display = 'none';
    document.getElementById('compose-search-input').value = '';
    
    // 加载角色列表（好友角色）
    await loadComposeCharList();
    
    // 先设置 display，再添加 active 类触发动画
    const composePage = document.getElementById('message-compose-page');
    composePage.style.display = 'flex';
    setTimeout(() => {
        composePage.classList.add('active');
    }, 10);
}

function closeComposeMessage() {
    const composePage = document.getElementById('message-compose-page');
    composePage.classList.remove('active');
    // 等待动画完成后再隐藏
    setTimeout(() => {
        composePage.style.display = 'none';
    }, 400);
}

// 加载角色列表
async function loadComposeCharList() {
    const accountId = getCurrentAccountId();
    const allChars = await db.characters.toArray();
    // 🎯 修复：短信不受微信好友状态限制，好友/被删除/被拉黑都可以发短信
    const allowedStatuses = ['friend', 'deleted_by_char', 'blocked_by_char'];
    const friends = allChars.filter(c => {
        if (c.type === 'user') return false;
        const status = getFriendStatus(c, accountId);
        return allowedStatuses.includes(status);
    });
    
    const container = document.getElementById('compose-char-list');
    if (friends.length === 0) {
        container.innerHTML = '<div style="padding:40px 16px; text-align:center; color:#999; font-size:15px;">暂无好友</div>';
        return;
    }
    
    container.innerHTML = friends.map(f => {
        const displayName = getCharDisplayName(f, accountId);
        const phone = f.identity?.phone || '';
        const _compAvatar = getCharAvatar(f, accountId);
        const avatarStyle = _compAvatar ? `background-image:url(${_compAvatar})` : 'background-color:#ddd';
        const status = getFriendStatus(f, accountId);
        // 显示状态标签
        let statusBadge = '';
        if (status === 'deleted_by_char') {
            statusBadge = '<span style="font-size:11px; color:#ff9500; background:#fff5e6; padding:2px 6px; border-radius:4px; margin-left:8px;">被Ta删除</span>';
        } else if (status === 'blocked_by_char') {
            statusBadge = '<span style="font-size:11px; color:#ff3b30; background:#ffe5e5; padding:2px 6px; border-radius:4px; margin-left:8px;">被Ta拉黑</span>';
        }
        return `<div class="compose-contact-item" data-name="${displayName}" data-phone="${phone}" onclick="selectComposeChar(${f.id})">
            <div style="width:44px; height:44px; border-radius:50%; background-size:cover; background-position:center; flex-shrink:0; ${avatarStyle}"></div>
            <div style="flex:1; min-width:0; border-bottom:0.5px solid #f0f0f0; padding:14px 0; margin-left:12px;">
                <div style="display:flex; align-items:center;"><span style="font-size:16px; color:#000; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${displayName}</span>${statusBadge}</div>
                ${phone ? `<div style="font-size:13px; color:#8e8e93; margin-top:2px;">${phone}</div>` : ''}
            </div>
        </div>`;
    }).join('');
}

// 选择角色 → 进入步骤2选择用户档案
async function selectComposeChar(charId) {
    composeSelectedCharId = charId;
    const char = await db.characters.get(charId);
    const charName = getCharDisplayName(char, getCurrentAccountId());
    
    document.getElementById('compose-step-title').textContent = `发给 ${charName}`;
    document.getElementById('compose-step-char').style.display = 'none';
    document.getElementById('compose-step-user').style.display = 'block';
    document.getElementById('compose-search-input').value = '';
    
    // 加载用户档案列表
    await loadComposeUserList(charId);
}

// 加载用户档案列表
async function loadComposeUserList(charId) {
    const allChars = await db.characters.toArray();
    const users = allChars.filter(c => c.type === 'user');
    const targetChar = await db.characters.get(charId);
    
    const container = document.getElementById('compose-user-list');
    if (users.length === 0) {
        container.innerHTML = '<div style="padding:40px 16px; text-align:center; color:#999; font-size:15px;">暂无用户档案</div>';
        return;
    }
    
    container.innerHTML = users.map(u => {
        const avatarStyle = u.avatar ? `background-image:url(${u.avatar})` : 'background-color:#ddd';
        const phone = u.identity?.phone || '';
        
        // 检查这个用户和目标角色之间是否有微信聊天记录
        const hasContext = checkIfUserHasChatWithChar(u, targetChar);
        
        const contextLabel = hasContext 
            ? '<span style="font-size:11px; color:#07c160; background:#e8f8f0; padding:2px 6px; border-radius:4px; margin-left:8px;">有聊天记录</span>'
            : '<span style="font-size:11px; color:#ff9500; background:#fff5e6; padding:2px 6px; border-radius:4px; margin-left:8px;">陌生号码</span>';
        
        return `<div class="compose-contact-item" data-name="${u.name}" onclick="confirmComposeSms(${charId}, ${u.id})">
            <div style="width:44px; height:44px; border-radius:50%; background-size:cover; background-position:center; flex-shrink:0; ${avatarStyle}"></div>
            <div style="flex:1; min-width:0; border-bottom:0.5px solid #f0f0f0; padding:14px 0; margin-left:12px;">
                <div style="display:flex; align-items:center;">
                    <span style="font-size:16px; color:#000; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${u.name}</span>
                    ${contextLabel}
                </div>
                ${phone ? `<div style="font-size:13px; color:#8e8e93; margin-top:2px;">${phone}</div>` : ''}
            </div>
        </div>`;
    }).join('');
}

// 检查用户与角色之间是否有微信聊天记录
function checkIfUserHasChatWithChar(userChar, targetChar) {
    // 获取所有微信账号（每个用户可能对应一个currentMyCharId）
    // 检查该用户ID对应的聊天记录
    const accountId = String(userChar.id);
    const history = getChatHistory(targetChar, accountId);
    return history && history.length > 0;
}

// 确认选择，开始短信聊天
async function confirmComposeSms(charId, userId) {
    const char = await db.characters.get(charId);
    const userChar = await db.characters.get(userId);
    if (!char || !userChar) return;
    
    const charName = getCharDisplayName(char, getCurrentAccountId());
    const charPhone = char.identity?.phone || generateVirtualPhoneNumber(char.id);
    
    // 设置当前短信聊天的信息
    currentMessageChatId = charPhone;
    currentMessageChatName = charName;
    
    // 存储选中的用户档案ID，用于发信和AI上下文
    window._smsSelectedUserId = userId;
    window._smsSelectedCharId = charId;
    
    // 关闭选择页面
    closeComposeMessage();
    
    // 检查是否已有短信记录，如果没有则创建初始记录
    const accountId = getCurrentAccountId();
    
    // 直接打开短信详情页
    openMessageChat(charPhone);
}

// 搜索过滤
function filterComposeList() {
    const keyword = document.getElementById('compose-search-input').value.trim().toLowerCase();
    const step1Visible = document.getElementById('compose-step-char').style.display !== 'none';
    const containerId = step1Visible ? 'compose-char-list' : 'compose-user-list';
    const items = document.querySelectorAll(`#${containerId} .compose-contact-item`);
    
    items.forEach(item => {
        const name = (item.getAttribute('data-name') || '').toLowerCase();
        const phone = (item.getAttribute('data-phone') || '').toLowerCase();
        if (!keyword || name.includes(keyword) || phone.includes(keyword)) {
            item.style.display = 'flex';
        } else {
            item.style.display = 'none';
        }
    });
}

// 发送短信详情页的消息
async function sendMessageDetail() {
    const input = document.getElementById('message-msg-input');
    const text = input.value.trim();
    
    if (!text) return;
    
    // 如果没有当前聊天，不能发送
    if (!currentMessageChatId || currentMessageChatId === 'welcome') {
        alert('无法发送消息');
        return;
    }
    
    // 如果是编辑模式
    if (currentEditingMessageId) {
        try {
            // 更新消息内容
            await db.sms_messages.update(currentEditingMessageId, {
                content: text
            });
            
            // 重新渲染消息
            if (currentMessageChatId) {
                await openMessageChat(currentMessageChatId);
            }
            
            // 清空编辑状态
            currentEditingMessageId = null;
            input.value = '';
            handleMessageInputChange(input);
            showToast('消息已更新');
            return;
        } catch (e) {
            console.error('更新消息失败:', e);
            alert('更新消息失败');
            return;
        }
    }
    
    // 🎯 检查余额（每条短信0.1元）
    const SMS_COST = 0.1;
    const balance = getPhoneBalance();
    if (balance < SMS_COST) {
        const recharge = confirm(`余额不足（当前余额：¥${balance.toFixed(2)}）\n\n每条短信需要 ¥${SMS_COST.toFixed(2)}，请先充值。\n\n是否前往充值？`);
        if (recharge) {
            hideMessagePage();
            setTimeout(() => {
                showPhoneRechargePage();
            }, 300);
        }
        return;
    }
    
    // 获取当前用户信息
    const accountId = getCurrentAccountId();
    if (!accountId) {
        alert('请先登录');
        return;
    }
    
    const myChar = await db.characters.get(parseInt(accountId));
    if (!myChar) {
        alert('找不到用户信息');
        return;
    }
    
    // 🎯 扣费 - 支持选择支付方式
    const paymentResult = await showPaymentMethodSelection(SMS_COST, '短信费用');
    if (!paymentResult.success) {
        alert('支付失败，请重试');
        return;
    }
    
    // 清空输入框
    input.value = '';
    handleMessageInputChange(input);
    
    // 保存发送的消息到 Dexie
    const myPhoneNumber = myChar.identity?.phone || generateVirtualPhoneNumber(myChar.id);
    
    // 🎯 关键修复：使用当前聊天的ID（接收者的ID）作为聊天标识
    // 这样消息会归入正确的聊天，而不是创建新的聊天
    // 同时存储接收者信息，确保分组和显示正确
    const newMsgId = await db.sms_messages.add({
        accountId: accountId,
        charId: null, // 发送的消息不需要 charId
        sender: myChar.nick || myChar.name,
        number: currentMessageChatId, // 使用接收者的ID作为number，确保分组正确
        content: text,
        time: Date.now(),
        read: true,
        type: 'sent', // 标记为发送的消息
        receiverName: currentMessageChatName, // 存储接收者名字，用于显示
        receiverId: currentMessageChatId // 存储接收者ID
    });
    
    // 重新渲染消息列表
    renderMessageList();
    
    // 在详情页显示新消息
    const msgContainer = document.getElementById('message-container');
    if (msgContainer) {
        const scrollArea = document.getElementById('message-area-scroll');
        const wasAtBottom = scrollArea.scrollHeight - scrollArea.scrollTop <= scrollArea.clientHeight + 50;
        
        const newMsgHtml = `<div class="message-wrapper" data-msg-id="${newMsgId}" data-msg-index="${msgContainer.children.length}">
            <div class="message-bubble message-sent" 
                 data-msg-text="${escapeHtml(text)}"
                 data-msg-type="sent">${text.replace(/\n/g, '<br>')}</div>
        </div>`;
        msgContainer.innerHTML += newMsgHtml;
        
        // 为新消息添加长按事件
        attachMessageLongPressEvents();
        
        // 如果之前在底部，滚动到底部
        if (wasAtBottom) {
            setTimeout(() => {
                scrollArea.scrollTo({ top: scrollArea.scrollHeight, behavior: 'smooth' });
            }, 10);
        }
    }
}

// 处理短信输入框变化（切换麦克风和发送按钮）
function handleMessageInputChange(input) {
    const hasText = input.value.trim().length > 0;
    const micIcon = document.getElementById('message-icon-mic');
    const sendBtn = document.getElementById('message-btn-send');
    
    if (hasText) {
        if (micIcon) micIcon.style.display = 'none';
        if (sendBtn) sendBtn.style.display = 'flex';
    } else {
        if (micIcon) micIcon.style.display = 'flex';
        if (sendBtn) sendBtn.style.display = 'none';
    }
}

// 短信页面接受回复（调用API）
let _isAcceptingSmsReply = false;
let _isAcceptingSmsReplyTime = 0;
async function acceptMessageReply() {
    // 防止重复调用（超时15秒自动解锁，防止手机端锁死）
    if (_isAcceptingSmsReply) {
        const elapsed = Date.now() - (_isAcceptingSmsReplyTime || 0);
        if (elapsed < 15000) {
            console.log('[acceptMessageReply] ⏳ 正在处理中，忽略重复调用 (已等待' + Math.round(elapsed/1000) + '秒)');
            showToast('正在生成回复中，请稍候...');
            return;
        }
        console.warn('[acceptMessageReply] ⚠️ 检测到锁超时，强制重置');
        _isAcceptingSmsReply = false;
        _isAcceptingSmsReplyTime = 0;
    }
    
    if (!currentMessageChatId || currentMessageChatId === 'welcome') {
        alert('无法接受回复');
        return;
    }
    
    // 🔧 通过联系人名称或角色ID查找角色（手机端DB读取加超时保护）
    let allChars, targetChar = null;
    try {
        allChars = await Promise.race([
            db.characters.toArray(),
            new Promise((_, reject) => setTimeout(() => reject(new Error('DB读取超时')), 8000))
        ]);
    } catch (dbErr) {
        console.error('[acceptMessageReply] DB读取超时:', dbErr.message);
        showToast('数据读取超时，请重试');
        return;
    }
    
    // 优先通过存储的角色ID查找
    if (window._smsSelectedCharId) {
        try {
            targetChar = await Promise.race([
                db.characters.get(window._smsSelectedCharId),
                new Promise((_, reject) => setTimeout(() => reject(new Error('DB读取超时')), 8000))
            ]);
        } catch (dbErr) {
            console.error('[acceptMessageReply] DB读取超时:', dbErr.message);
            showToast('数据读取超时，请重试');
            return;
        }
    }
    
    // 回退：通过名字查找
    if (!targetChar) {
        const _smsAid = getCurrentAccountId();
        targetChar = allChars.find(char => 
            (char.nick || char.name) === currentMessageChatName ||
            getCharDisplayName(char, _smsAid) === currentMessageChatName
        );
    }
    
    // 再回退：通过手机号查找
    if (!targetChar) {
        targetChar = allChars.find(char => 
            char.identity?.phone === currentMessageChatId
        );
    }
    
    if (!targetChar) {
        alert('找不到对应的角色');
        return;
    }
    
    const accountId = getCurrentAccountId();
    if (!accountId) {
        alert('请先登录');
        return;
    }
    
    const myChar = await db.characters.get(parseInt(accountId));
    if (!myChar) {
        alert('找不到用户信息');
        return;
    }
    
    // 确定使用的用户档案：优先用选择的用户档案，否则用当前账号
    const smsUserId = window._smsSelectedUserId || null;
    let smsUserChar = null;
    let contextAccountId = accountId; // 用于获取微信聊天上下文的账号ID
    
    if (smsUserId) {
        smsUserChar = await db.characters.get(smsUserId);
        if (smsUserChar) {
            contextAccountId = String(smsUserId);
        }
    }
    
    console.log('[acceptMessageReply] ⚡ 开始接受短信回复');
    console.log('[acceptMessageReply] 角色名称:', targetChar.name);
    console.log('[acceptMessageReply] 账号 ID:', accountId);
    console.log('[acceptMessageReply] 用户档案 ID:', smsUserId || '使用当前账号');
    
    _isAcceptingSmsReply = true;
    _isAcceptingSmsReplyTime = Date.now();
    
    // 🔧 安全定时器：45秒后强制释放锁（防止await永久挂起导致手机端锁死）
    const _safetySmsLockTimer = setTimeout(() => {
        if (_isAcceptingSmsReply) {
            console.warn('[acceptMessageReply] ⏰ 安全定时器触发(45s)，强制释放锁');
            _isAcceptingSmsReply = false;
            _isAcceptingSmsReplyTime = 0;
        }
    }, 45000);
    
    // 🎯 显示"对方正在输入中..."提示
    const smsNameEl = document.getElementById('message-detail-name');
    const originalSmsName = smsNameEl ? smsNameEl.innerText : getCharDisplayName(targetChar, getCurrentAccountId());
    if (smsNameEl) {
        smsNameEl.innerText = "对方正在输入中...";
        smsNameEl.style.fontSize = "12px";
    }
    
    try {
        // 1. 获取用户信息 - 使用选择的用户档案
        console.log('[acceptMessageReply] 📖 开始加载上下文信息...');
        
        let userDesc = "";
        let userName = "用户";
        let isStranger = false;
        
        if (smsUserChar) {
            // 使用选择的用户档案
            userName = smsUserChar.name;
            userDesc = `\n\n【对话对象(User)信息】\n名字：${smsUserChar.name}\n设定：${smsUserChar.description || '无'}`;
            console.log('[acceptMessageReply] ✅ 选择的用户档案:', userName);
            
            // 检查是否有微信聊天记录
            const wechatHistoryCheck = getChatHistory(targetChar, contextAccountId);
            if (!wechatHistoryCheck || wechatHistoryCheck.length === 0) {
                isStranger = true;
                console.log('[acceptMessageReply] ⚠️ 该用户与角色无微信聊天记录 → 陌生号码');
            }
        } else if (targetChar.linked_user_id) {
            // 回退：使用角色关联的用户
            console.log('[acceptMessageReply] 👤 检测到关联的用户 ID:', targetChar.linked_user_id);
            const user = await db.characters.get(targetChar.linked_user_id);
            if (user) {
                userName = user.name;
                userDesc = `\n\n【对话对象(User)信息】\n名字：${user.name}\n设定：${user.description || '无'}`;
                console.log('[acceptMessageReply] ✅ 用户人设已加载:', userName);
            }
        }
        
        let loreContext = "";
        const lorebookIds = targetChar.lorebookIds || (targetChar.lorebookId ? [targetChar.lorebookId] : []);
        
        // 获取微信聊天历史用于世界书匹配（使用对应用户的上下文）
        const wechatHistory = getChatHistory(targetChar, contextAccountId);
        const recentText = wechatHistory.slice(-10).map(m => m.content).join(' ');
        
        // 总是调用（会自动加载全局世界书）
        loreContext = await getLorebookContext(lorebookIds, `${targetChar.name} ${userName} ${recentText}`);
        
        // 2. 获取微信聊天历史（使用对应用户的上下文）
        const fullWechatHistory = getChatHistory(targetChar, contextAccountId);
        console.log('[acceptMessageReply] 📚 微信聊天历史条数:', fullWechatHistory.length);
        
        // 3. 获取短信聊天历史（从 Dexie）
        let smsMessages = await db.sms_messages.where('accountId').equals(accountId).toArray();
        const chatMessages = smsMessages.filter(msg => (msg.number || msg.sender) === currentMessageChatId);
        console.log('[acceptMessageReply] 📱 短信聊天历史条数:', chatMessages.length);
        
        // 4. 计算虚拟时间
        const virtualTimeStr = getFormattedVirtualTime(targetChar);
        
        // 5. 构建陌生号码提示
        const strangerPrompt = isStranger ? `
【重要：陌生号码情境】
你收到了一个陌生号码发来的短信。你不认识这个人，你不知道对方是谁。
请以面对陌生人的态度来回复：可以好奇、警惕、冷淡或符合你性格的任何反应。
不要表现得好像认识对方，除非对方在消息中自报身份。
` : '';
        
        // 6. 获取当前好友状态，用于提示词
        const currentFriendStatus = getFriendStatus(targetChar, accountId);
        let friendStatusPrompt = '';
        let smsActionInstructions = '';
        
        if (currentFriendStatus === 'blocked_by_char') {
            friendStatusPrompt = `
【重要：当前关系状态 - 你已将对方拉黑】
你之前把对方拉黑了，对方现在只能通过短信联系你。
对方在微信上无法给你发消息、也无法发好友申请。
你要根据自己的人设和当前对话内容来决定是否原谅对方、是否把对方从黑名单移出来。
`;
            smsActionInstructions = `
【可用操作指令】
- **解除拉黑（把对方从黑名单移出来）**：在回复中包含 \`((UNBLOCK_USER))\` 指令。当你决定原谅对方、愿意和好、想恢复正常联系时使用。使用后对方将恢复好友状态，可以在微信上正常聊天。请根据你的人设来判断是否要这样做。
- 指令可以和消息内容一起发送，例如："好吧 我原谅你了((UNBLOCK_USER))"
`;
        } else if (currentFriendStatus === 'deleted_by_char') {
            friendStatusPrompt = `
【重要：当前关系状态 - 你已将对方删除】
你之前删除了对方的好友关系，对方现在只能通过短信联系你。
你要根据自己的人设和当前对话内容来决定是否要重新加回对方。
`;
            smsActionInstructions = `
【可用操作指令】
- **重新加回好友（主动加回对方）**：在回复中包含 \`((ADD_BACK_USER))\` 指令。当你想和对方和好、恢复联系时使用。使用后对方将恢复好友状态，可以在微信上正常聊天。请根据你的人设来判断是否要这样做。
- 指令可以和消息内容一起发送，例如："算了 我加回你了((ADD_BACK_USER))"
`;
        }
        
        // 6.5 读取查手机NPC活动记录
        let fpNpcActivityTextSms = "";
        let _fpHasPhoneActivitySms = false;
        let _fpNpcLinesForMemorySms = []; // ★ 保存活动详情，用于写入长期记忆
        try {
            if (targetChar.chat_history_by_user) {
                const fpNpcLinesSms = [];
                for (const key of Object.keys(targetChar.chat_history_by_user)) {
                    if (!key.startsWith('fp_npc_')) continue;
                    const npcIdStr = key.replace('fp_npc_', '');
                    const npcHistory = targetChar.chat_history_by_user[key] || [];
                    const unnotifiedFpMsgs = npcHistory.filter(m => m.fpSent && !m.fpNotified);
                    if (unnotifiedFpMsgs.length === 0) continue;
                    let npcName = 'NPC';
                    try {
                        const npcChar = await db.characters.get(parseInt(npcIdStr));
                        if (npcChar) npcName = npcChar.nick || npcChar.name || 'NPC';
                    } catch (e) {}
                    const firstFpTime = unnotifiedFpMsgs[0].time || 0;
                    for (const m of npcHistory) {
                        if ((m.time || 0) < firstFpTime) continue;
                        if (m.fpNotified) continue;
                        if (m.fpSent && m.role === 'char') {
                            let desc = m.content || '';
                            if (desc.startsWith('[img:')) desc = '一张图片/表情包';
                            else if (desc.startsWith('[imgcard:')) {
                                const imgContent = stripImgcardInlineTags(desc.match(/\[imgcard:(.*?)\]/)?.[1] || '一张图片');
                                desc = `一张图片卡片（${imgContent}）`;
                            }
                            else if (desc.startsWith('[voice:')) {
                                const voiceContent = desc.match(/\[voice:(.*?)\]/)?.[1] || '';
                                desc = `一条语音消息："${voiceContent}"`;
                            }
                            fpNpcLinesSms.push(`  → 冒充你给「${npcName}」发了一条消息，内容原文: "${desc}"`);
                        } else if (!m.fpSent && m.role === 'user') {
                            let desc = m.content || '';
                            fpNpcLinesSms.push(`  ← 「${npcName}」回复了，内容原文: "${desc}"`);
                        }
                    }
                }
                // 也检测查手机发布的朋友圈
                if (targetChar.fp_moments_by_user) {
                    for (const mKey of Object.keys(targetChar.fp_moments_by_user)) {
                        const momentsList = targetChar.fp_moments_by_user[mKey] || [];
                        for (const m of momentsList) {
                            if (m.fpSent && !m.fpNotified) {
                                let desc = m.content || '';
                                let imgInfo = '';
                                if (m.images && m.images.length > 0) imgInfo = `（附带${m.images.length}张图片）`;
                                fpNpcLinesSms.push(`  → 冒充你发了一条朋友圈${imgInfo}，朋友圈内容原文: "${desc}"`);
                                if (m.likes && m.likes.length > 0) {
                                    const likeNames = m.likes.map(l => typeof l === 'string' ? l : (l.name || '')).filter(Boolean).join('、');
                                    if (likeNames) fpNpcLinesSms.push(`    ❤ 点赞了这条朋友圈的人: ${likeNames}`);
                                }
                                if (m.comments && m.comments.length > 0) {
                                    for (const c of m.comments) {
                                        const cName = c.name || '好友';
                                        const cText = c.text || c.content || '';
                                        if (cText) fpNpcLinesSms.push(`    💬 ${cName} 评论了: "${cText}"`);
                                    }
                                }
                                // ★ 不立即标记fpNotified
                            }
                        }
                    }
                }
                if (fpNpcLinesSms.length > 0) {
                    _fpNpcLinesForMemorySms = [...fpNpcLinesSms]; // ★ 保存副本用于长期记忆
                    fpNpcActivityTextSms = `\n\n---\n\n## 紧急事件：有人动了你的手机\n\n你发现有人偷偷拿了你的手机，冒充你做了以下事情：\n\n${fpNpcLinesSms.join('\n')}\n\n以上都不是你自己做的，是对方用你手机冒充你做的。\n请根据你的人设和性格，自然地对此做出反应。不要忽略这件事。`;
                    _fpHasPhoneActivitySms = true;
                    console.log('[acceptMessageReply] ✅ 检测到查手机活动，共', fpNpcLinesSms.length, '条记录（待AI回复后标记）');
                }
            }
        } catch (e) {
            console.warn('[acceptMessageReply] 读取查手机NPC活动失败:', e);
        }

        // 7. 构建系统提示
        let systemPrompt = `你正在进行角色扮演。
【当前时间】
${virtualTimeStr}${fpNpcActivityTextSms}

【角色(你)信息】
名字：${targetChar.name}
${targetChar.nick ? `昵称：${targetChar.nick}` : ''}
类型：${targetChar.type || 'char'}
设定：
${targetChar.description || ''}

${targetChar.identity ? `虚拟身份信息：
${targetChar.identity.account ? `账号：${targetChar.identity.account}` : ''}
${targetChar.type !== 'user' && targetChar.identity.password ? `密码：${targetChar.identity.password}` : ''}
${targetChar.identity.phone ? `手机：${targetChar.identity.phone}` : ''}
${targetChar.identity.address ? `住址：${targetChar.identity.address}` : ''}
${targetChar.identity.id_card ? `身份证：${targetChar.identity.id_card}` : ''}
${targetChar.identity.bank_card ? `银行卡：${targetChar.identity.bank_card}` : ''}
${targetChar.type !== 'user' && targetChar.identity.bank_password ? `银行卡密码：${targetChar.identity.bank_password}` : ''}
${targetChar.identity.balance !== undefined && targetChar.identity.balance !== null ? `余额：${targetChar.identity.balance}` : ''}
` : ''}
${userDesc}
${loreContext}
${strangerPrompt}
${friendStatusPrompt}

请完全沉浸在角色中，用符合角色性格的语气回复。
回复简短自然，像真实短信一样。
请注意：不要重复输出名字前缀，直接输出回复内容。
${smsActionInstructions}
${targetChar.identity?.password ? `【修改密码功能】
你可以随时修改自己的账号密码：((CHANGE_PASSWORD:新密码))
修改后原密码立即失效。适用场景：生气了不想让对方查你手机、觉得不安全、想保护隐私、赌气、冷战等。
注意：不是必须的，根据你的性格和情绪自然决定，不要频繁修改。
` : ''}
【特别提示】
${(() => {
    // 检查最后一条短信是否是用户发送的
    const lastSms = chatMessages.length > 0 ? chatMessages[chatMessages.length - 1] : null;
    const lastIsSent = lastSms && (lastSms.type === 'sent' || lastSms.sender === (myChar.nick || myChar.name));
    if (lastIsSent) {
        return `对方刚刚给你发了一条短信，内容是："${lastSms.content}"。
你必须认真阅读并理解对方发来的这条消息，然后做出自然的、针对性的回复。
不要忽略对方说的内容，要像真实聊天一样回应对方的话。`;
    } else {
        return `由于对方可能暂时没有回复你之前的消息，你需要主动发送新的短信内容。这可能是：
- 补充说明之前的话题
- 主动分享新的信息或想法
- 询问对方的情况或状态
- 根据你的性格和当前情境，自然地推进对话`;
    }
})()}
请确保每次生成的内容都是**全新的**，不要重复你之前已经发送过的消息。

【重要回复规则 - 必须严格遵守】
1. **核心原则：一句话 = 一条消息！每个短句必须独立成一条！**
2. **必须**模拟短信连发消息的习惯：请生成 ${targetChar.reply_min_count || 1} 到 ${targetChar.reply_max_count || 3} 条短消息${(targetChar.reply_min_count || 1) === 1 ? '' : '，不能只发一条'}！${(targetChar.reply_min_count || 1) >= 3 ? `\n   🚨 严禁少于${targetChar.reply_min_count}条！你必须至少生成 ${targetChar.reply_min_count} 条消息！` : ''}
3. **必须**使用分隔符 "|||" 来隔开每一条消息。
4. ⚠️ **绝对禁止在一条消息里塞多句话！绝对禁止用空格连接多句话！一个|||之间只能有一个短句！**
5. 像真实短信聊天一样分多条发送，每句话单独发。
6. 严禁只发送标点符号。每一条消息都必须有实际文字内容。
7. 语气要自然、口语化，符合人设。
8. ⚠️ **严禁重复之前已经发送过的内容**！这是一个新的回复请求，你需要根据当前的对话情境，生成**全新的、不同的**回复内容。请查看对话历史，确保你的回复是对话的自然延续，而不是重复之前说过的话。

❌ 错误示例："没干嘛啊 刚打完一把游戏|||怎么了 突然找我 想我了？" ← 多句话塞进一个气泡 禁止！
✅ 正确示例："没干嘛啊|||刚打完一把游戏|||怎么了|||突然找我|||想我了？" ← 每句话独立一条！

请以JSON格式返回${(targetChar.reply_min_count || 1) >= 3 ? `，reply中必须包含至少${(targetChar.reply_min_count || 1) - 1}个|||分隔符` : ''}：
{
  "reply": "短句1|||短句2|||短句3|||短句4|||短句5"
}`;
        
        // 7. 构建历史记录（合并微信和短信历史）
        const contextCount = targetChar.context_message_count || 20;
        
        // 只有在非陌生人情况下才附带微信历史
        let recentWechatHistory = [];
        if (!isStranger) {
            recentWechatHistory = fullWechatHistory.slice(-contextCount)
                .map(m => {
                    let content = m.content || '';
                    if (m.imageDescription) {
                        content += `\n(图片描述: ${m.imageDescription})`;
                    }
                    return {
                        role: m.role === 'char' ? 'assistant' : 'user',
                        content: content
                    };
                })
                .filter(m => m.content && m.content.trim());
        }
        
        // 短信历史
        const recentSmsHistory = chatMessages.slice(-10).map(msg => {
            const isSent = msg.type === 'sent' || msg.sender === (myChar.nick || myChar.name);
            return {
                role: isSent ? 'user' : 'assistant',
                content: msg.content
            };
        }).filter(m => m.content && m.content.trim());
        
        // 合并历史：微信历史 + 短信历史
        const combinedHistory = [...recentWechatHistory, ...recentSmsHistory].slice(-contextCount);
        
        console.log('[acceptMessageReply] 📝 合并后的历史消息数:', combinedHistory.length);
        console.log('[acceptMessageReply]   - 微信历史:', recentWechatHistory.length, '条');
        console.log('[acceptMessageReply]   - 短信历史:', recentSmsHistory.length, '条');
        
        // 7. 调用AI
        const messages = [
            { role: 'system', content: systemPrompt },
            ...combinedHistory
        ];
        
        console.log('[acceptMessageReply] 📤 准备发送给 AI');
        const aiResponse = await callAI(messages);
        
        // 8. 解析回复
        let replyText = '';
        const parsed = extractAndParseJSON(aiResponse);
        if (parsed) {
            replyText = parsed.reply || parsed.content || parsed.message || '';
        }
        
        if (!replyText) {
            replyText = aiResponse.trim() || '...';
        }
        
        // ✅ 清理末尾的 [DONE] / [done]
        replyText = replyText.replace(/\s*\[DONE\]\s*$/i, '').trim();
        
        // 🎯 检测解除拉黑指令 ((UNBLOCK_USER))
        if (/\(\(UNBLOCK_USER\)\)/i.test(replyText)) {
            console.log('[acceptMessageReply] 🔓 检测到解除拉黑指令');
            replyText = replyText.replace(/\(\(UNBLOCK_USER\)\)/gi, '').trim();
            // 执行解除拉黑
            const freshChar = await db.characters.get(targetChar.id);
            if (freshChar) {
                await setFriendStatus(freshChar, accountId, 'friend');
                console.log('[acceptMessageReply] ✅ 已解除拉黑，恢复好友状态');
                
                // 添加系统消息到微信聊天记录
                const history = getChatHistory(freshChar, accountId);
                history.push({
                    role: 'system',
                    content: `[${freshChar.name} 将你从黑名单中移出，你们已恢复好友关系]`,
                    time: Date.now(),
                    type: 'char_unblock'
                });
                await setChatHistory(freshChar, accountId, history);
                
                // 刷新微信界面
                if (typeof currentChatCharId !== 'undefined' && currentChatCharId === targetChar.id) {
                    await renderChatBody(freshChar);
                }
                const activeTab = document.querySelector('.wechat-tab-item.active');
                if (activeTab) {
                    const tabIndex = Array.from(document.querySelectorAll('.wechat-tab-item')).indexOf(activeTab);
                    switchWechatTab(tabIndex);
                }
                
                showToast(`${freshChar.name} 把你从黑名单移出来了！`);
            }
        }
        
        // 🎯 检测重新加回好友指令 ((ADD_BACK_USER))
        if (/\(\(ADD_BACK_USER\)\)/i.test(replyText)) {
            console.log('[acceptMessageReply] 🤝 检测到重新加回好友指令');
            replyText = replyText.replace(/\(\(ADD_BACK_USER\)\)/gi, '').trim();
            // 执行重新加回好友
            const freshChar = await db.characters.get(targetChar.id);
            if (freshChar) {
                await setFriendStatus(freshChar, accountId, 'friend');
                console.log('[acceptMessageReply] ✅ 已重新加回好友');
                
                // 添加系统消息到微信聊天记录
                const history = getChatHistory(freshChar, accountId);
                history.push({
                    role: 'system',
                    content: `[${freshChar.name} 重新加你为好友，你们已恢复好友关系]`,
                    time: Date.now(),
                    type: 'char_add_back'
                });
                await setChatHistory(freshChar, accountId, history);
                
                // 刷新微信界面
                if (typeof currentChatCharId !== 'undefined' && currentChatCharId === targetChar.id) {
                    await renderChatBody(freshChar);
                }
                const activeTab = document.querySelector('.wechat-tab-item.active');
                if (activeTab) {
                    const tabIndex = Array.from(document.querySelectorAll('.wechat-tab-item')).indexOf(activeTab);
                    switchWechatTab(tabIndex);
                }
                
                showToast(`${freshChar.name} 重新加你为好友了！`);
            }
        }
        
        // 🎯 检测朋友圈屏蔽/解除屏蔽指令 ((BLOCK_MOMENTS)) / ((UNBLOCK_MOMENTS)) — 静默操作
        if (/\(\(BLOCK_MOMENTS\)\)/i.test(replyText)) {
            console.log('[acceptMessageReply] 检测到朋友圈屏蔽指令');
            replyText = replyText.replace(/\(\(BLOCK_MOMENTS\)\)/gi, '').trim();
            try { await executeBlockMoments(targetChar.id, accountId, true); } catch (e) { console.error('[acceptMessageReply] 朋友圈屏蔽失败:', e); }
        }
        if (/\(\(UNBLOCK_MOMENTS\)\)/i.test(replyText)) {
            console.log('[acceptMessageReply] 检测到朋友圈解除屏蔽指令');
            replyText = replyText.replace(/\(\(UNBLOCK_MOMENTS\)\)/gi, '').trim();
            try { await executeBlockMoments(targetChar.id, accountId, false); } catch (e) { console.error('[acceptMessageReply] 朋友圈解除屏蔽失败:', e); }
        }
        
        // 🎯 检测修改密码指令 ((CHANGE_PASSWORD:新密码))
        const changePasswordMatch = replyText.match(/\(\(CHANGE_PASSWORD:\s*([^)]+)\)\)/i);
        if (changePasswordMatch) {
            console.log('[acceptMessageReply] 🔐 检测到修改密码指令');
            const newPassword = changePasswordMatch[1].trim();
            replyText = replyText.replace(/\(\(CHANGE_PASSWORD:[^)]+\)\)/gi, '').trim();
            
            // 执行修改密码
            const freshChar = await db.characters.get(targetChar.id);
            if (freshChar) {
                // 确保 identity 对象存在
                if (!freshChar.identity) {
                    freshChar.identity = {};
                }
                
                const oldPassword = freshChar.identity.password || '';
                freshChar.identity.password = newPassword;
                
                // 🛡️ 使用 update() 只更新密码字段，防止覆盖设置
                await safeDexieUpdate(db.characters, freshChar.id, { 'identity.password': newPassword }, `修改密码[${freshChar.name}]`);
                console.log('[acceptMessageReply] ✅ 已修改密码，新密码:', newPassword);
                
                // 🔥 修复：直接操作全局 fpWechatVerified Set，而不是创建新的局部变量（局部变量会遮蔽全局的，导致内存中的验证状态未被清除）
                fpWechatVerified.delete(String(freshChar.id));
                saveFpWechatVerified();
                
                // 添加系统消息到微信聊天记录
                const history = getChatHistory(freshChar, accountId);
                const sysMsgContent = `[${freshChar.name} 修改了账号密码，原密码已失效]`;
                history.push({
                    role: 'system',
                    content: sysMsgContent,
                    time: Date.now(),
                    type: 'char_change_password'
                });
                await setChatHistory(freshChar, accountId, history);
                
                // 🔥 修复：使用 appendMessageToUI 追加系统消息，避免 renderChatBody 导致页面闪烁
                if (typeof currentChatCharId !== 'undefined' && currentChatCharId === targetChar.id) {
                    await appendMessageToUI('system', sysMsgContent);
                }
                const activeTab = document.querySelector('.wechat-tab-item.active');
                if (activeTab) {
                    const tabIndex = Array.from(document.querySelectorAll('.wechat-tab-item')).indexOf(activeTab);
                    switchWechatTab(tabIndex);
                }
                
                showToast(`${freshChar.name} 修改了密码！`);
            }
        }
        
        // 🎯 检测角色自主手机活动指令 ((PHONE_ACTIVITY:描述))
        const phoneActivityMatchSms = replyText.match(/\(\(PHONE_ACTIVITY:\s*([^)]+)\)\)/i);
        if (phoneActivityMatchSms && targetChar.allow_autonomous_activity) {
            const activityDescSms = phoneActivityMatchSms[1].trim();
            console.log('[acceptMessageReply] 📱 检测到角色自主手机活动指令:', activityDescSms);
            replyText = replyText.replace(/\(\(PHONE_ACTIVITY:\s*[^)]+\)\)/gi, '').trim();
            generateCharAutonomousActivity(targetChar.id, accountId, activityDescSms).catch(e => {
                console.error('[acceptMessageReply] 角色自主活动生成失败:', e);
            });
        }
        
        // 9. 处理分隔符，拆分成多条消息
        const replySegments = replyText.split('|||').map(s => s.trim()).filter(s => s.length > 0);
        
        if (replySegments.length === 0) {
            // 如果指令被清除后没有内容了，使用默认回复
            replySegments.push('...');
        }
        
        // 10. 保存回复到短信记录（如果有多条，逐条发送）
        const phoneNumber = targetChar.identity?.phone || generateVirtualPhoneNumber(targetChar.id);
        
        for (let i = 0; i < replySegments.length; i++) {
            const segment = replySegments[i];
            
            // 如果不是第一条，稍微延时
            if (i > 0) {
                await new Promise(r => setTimeout(r, 500));
            }
            
            // 保存到 Dexie 数据库
            const newMsgId = await db.sms_messages.add({
                accountId: accountId,
                charId: targetChar.id,
                sender: targetChar.nick || targetChar.name,
                number: phoneNumber,
                content: segment,
                time: Date.now() + i * 100, // 稍微错开时间
                read: true,
                type: 'received'
            });
            
            // 在详情页显示新消息
            const msgContainer = document.getElementById('message-container');
            if (msgContainer) {
                const newMsgHtml = `<div class="message-wrapper" data-msg-id="${newMsgId}" data-msg-index="${msgContainer.children.length}">
                    <div class="message-bubble message-received" 
                         data-msg-text="${escapeHtml(segment)}"
                         data-msg-type="received">${segment.replace(/\n/g, '<br>')}</div>
                </div>`;
                msgContainer.innerHTML += newMsgHtml;
                
                // 为新消息添加长按事件
                attachMessageLongPressEvents();
            }
        }
        
        // 重新渲染消息列表
        renderMessageList();
        
        // 滚动到底部
        setTimeout(() => {
            const scrollArea = document.getElementById('message-area-scroll');
            if (scrollArea) {
                scrollArea.scrollTo({ top: scrollArea.scrollHeight, behavior: 'smooth' });
            }
        }, 100);
        
        console.log('[acceptMessageReply] ✅ 回复完成，共', replySegments.length, '条消息');
        
        // ★ AI回复成功后，标记查手机活动为已通知
        if (_fpHasPhoneActivitySms) {
            try {
                const freshCharForFp = await db.characters.get(targetChar.id);
                if (freshCharForFp) {
                    let markedCount = 0;
                    const fpNotifyPayload = {};
                    if (freshCharForFp.chat_history_by_user) {
                        for (const key of Object.keys(freshCharForFp.chat_history_by_user)) {
                            if (!key.startsWith('fp_npc_')) continue;
                            const npcHistory = freshCharForFp.chat_history_by_user[key] || [];
                            let changed = false;
                            for (const m of npcHistory) {
                                if ((m.fpSent || (!m.fpSent && m.role === 'user')) && !m.fpNotified) {
                                    m.fpNotified = true;
                                    markedCount++;
                                    changed = true;
                                }
                            }
                            if (changed) fpNotifyPayload[`chat_history_by_user.${key}`] = npcHistory;
                        }
                    }
                    if (freshCharForFp.fp_moments_by_user) {
                        for (const mKey of Object.keys(freshCharForFp.fp_moments_by_user)) {
                            const momentsList = freshCharForFp.fp_moments_by_user[mKey] || [];
                            let changed = false;
                            for (const m of momentsList) {
                                if (m.fpSent && !m.fpNotified) {
                                    m.fpNotified = true;
                                    markedCount++;
                                    changed = true;
                                }
                            }
                            if (changed) fpNotifyPayload[`fp_moments_by_user.${mKey}`] = momentsList;
                        }
                    }
                    // 🛡️ 使用 update() 只更新标记字段，防止覆盖设置
                    if (Object.keys(fpNotifyPayload).length > 0) {
                        await safeDexieUpdate(db.characters, targetChar.id, fpNotifyPayload, `查手机活动标记[${freshCharForFp.name}]`);
                    }
                    console.log('[acceptMessageReply] ✅ 查手机活动已标记为已通知，共标记', markedCount, '条');
                }
                
                // ★ 将查手机事件写入长期记忆（仅首次有新标记时写入，避免重复）
                if (markedCount > 0) {
                    try {
                        const smsUserName = smsUserChar ? smsUserChar.name : (myChar.nick || myChar.name);
                        const fpMemoryContent = `${smsUserName}偷偷拿了${targetChar.name}的手机，做了以下事情：${_fpNpcLinesForMemorySms.map(l => l.trim().replace(/^[→←]\s*/, '')).join('；')}。${targetChar.name}已经发现并做出了反应。`;
                        await db.chat_summaries.add({
                            accountId: accountId,
                            chatType: 'private',
                            chatId: String(targetChar.id),
                            time: Date.now(),
                            content: fpMemoryContent,
                            messageCount: 0,
                            timeRange: '',
                            keywords: ['查手机', '冒充', '手机被动'],
                            startTime: Date.now(),
                            endTime: Date.now()
                        });
                        console.log('[acceptMessageReply] ✅ 查手机事件已写入长期记忆');
                    } catch (memErr) {
                        console.warn('[acceptMessageReply] 写入查手机长期记忆失败:', memErr);
                    }
                } else {
                    console.log('[acceptMessageReply] ℹ️ 查手机活动已全部通知过，跳过重复写入长期记忆');
                }
            } catch (fpErr) {
                console.warn('[acceptMessageReply] 标记fpNotified失败:', fpErr);
            }
        }
        
        // 恢复标题
        if (smsNameEl) {
            smsNameEl.innerText = originalSmsName;
            smsNameEl.style.fontSize = "";
        }
        
    } catch (error) {
        console.error('[acceptMessageReply] ❌ 接受回复失败:', error);
        
        // 恢复标题
        if (smsNameEl) {
            smsNameEl.innerText = originalSmsName;
            smsNameEl.style.fontSize = "";
        }
        
        // 🚨 显示详细错误信息（使用Toast弹窗）
        let errorMsg = error.message || error.toString() || '未知错误';
        
        // 如果是网络错误或API密钥错误，添加友好提示
        if (errorMsg.includes('API') || errorMsg.includes('fetch') || errorMsg.includes('Failed')) {
            errorMsg += '\n\n💡 可能的原因：API密钥未配置/已失效、网络连接问题、或API服务不可用';
        }
        
        // 使用Toast弹窗显示错误
        showApiErrorToast(errorMsg);
    } finally {
        clearTimeout(_safetySmsLockTimer);
        _isAcceptingSmsReply = false;
        _isAcceptingSmsReplyTime = 0;
    }
}

