        // 注册 Service Worker（内联方式，不依赖外部sw.js文件）
        async function registerServiceWorkerAndSubscribe() {
            if (!('serviceWorker' in navigator)) {
                console.log('[SW] Not supported');
                showDebugToast('❌ 浏览器不支持Service Worker');
                return;
            }
            
            try {
                // 内联 Service Worker 代码
                const swCode = `
const CACHE_NAME = 'ins-desktop-v1';

self.addEventListener('install', function(event) {
    event.waitUntil(
        caches.open(CACHE_NAME).then(function(cache) {
            console.log('[SW] Cache opened');
            return Promise.resolve();
        }).catch(function(err) {
            console.warn('[SW] Cache init failed:', err);
            return Promise.resolve();
        })
    );
    self.skipWaiting();
});

self.addEventListener('activate', function(event) {
    event.waitUntil(
        caches.keys().then(function(names) {
            return Promise.all(
                names.filter(function(n) { return n !== CACHE_NAME; })
                    .map(function(n) { return caches.delete(n); })
            );
        }).then(function() { return self.clients.claim(); })
    );
});

self.addEventListener('notificationclick', function(event) {
    event.notification.close();
    event.waitUntil(
        clients.matchAll({ type: 'window', includeUncontrolled: true }).then(function(clientList) {
            for (var i = 0; i < clientList.length; i++) {
                if ('focus' in clientList[i]) return clientList[i].focus();
            }
            if (clients.openWindow) return clients.openWindow('./');
        })
    );
});

self.addEventListener('message', function(event) {
    if (event.data && event.data.type === 'SHOW_NOTIFICATION') {
        var d = event.data.data;
        self.registration.showNotification(d.title || '', {
            body: d.body || '',
            icon: d.icon || '',
            tag: d.tag || 'default',
            data: d.data || {}
        });
    }
});
`;
                const swBlob = new Blob([swCode], { type: 'application/javascript' });
                const swUrl = URL.createObjectURL(swBlob);
                
                const registration = await navigator.serviceWorker.register(swUrl);
                console.log('[SW] Registered (inline):', registration.scope);
                showDebugToast('✓ Service Worker已注册');
                
                await navigator.serviceWorker.ready;
                console.log('[SW] Ready');
                
                // 监听 SW 消息
                navigator.serviceWorker.addEventListener('message', event => {
                    if (event.data && event.data.type === 'OPEN_CHAT' && event.data.chatId) {
                        if (typeof openChat === 'function') openChat(event.data.chatId);
                    }
                });
                
                // 请求通知权限
                if ('Notification' in window) {
                    const permission = await Notification.requestPermission();
                    if (permission === 'granted') {
                        console.log('[Notification] ✓ 通知权限已授予');
                        showDebugToast('✓ 通知权限已授予', true);
                    } else {
                        console.log('[Notification] ✗ 通知权限被拒绝');
                        showDebugToast('✗ 通知权限被拒绝');
                    }
                }
                
                console.log('[SW] 内联模式就绪');
                showDebugToast('✓ 本地通知已就绪', true);
                
            } catch (err) {
                console.error('[SW] Error:', err);
                showDebugToast(`✗ Service Worker错误: ${err.message}`);
            }
        }
        
        // Base64 转 Uint8Array (用于 VAPID 公钥)
        function urlBase64ToUint8Array(base64String) {
            const padding = '='.repeat((4 - base64String.length % 4) % 4);
            const base64 = (base64String + padding)
                .replace(/\-/g, '+')
                .replace(/_/g, '/');
            
            const rawData = window.atob(base64);
            const outputArray = new Uint8Array(rawData.length);
            
            for (let i = 0; i < rawData.length; ++i) {
                outputArray[i] = rawData.charCodeAt(i);
            }
            return outputArray;
        }
        
