                        const INTIMATE_TYPES_MAP = { couple: '情侣', bestie: '闺蜜', bro: '基友', side: '小三' };
                        const reqTypeName = INTIMATE_TYPES_MAP[pendingReq.relationType] || '亲密';
                        intimateRequestContext = `\n\n## 待处理：亲密关系邀请\n\n对方（${userName}）向你发送了「${reqTypeName}」关系邀请，希望和你建立亲密关系。\n请根据你的性格、人设和你们的关系现状，在本次回复中决定是否接受。\n- 如果接受，请在回复中加入：((INTIMATE_ACCEPT))\n- 如果拒绝，请在回复中加入：((INTIMATE_REJECT))\n\n你必须在这次回复中做出选择（接受或拒绝），不能忽略此邀请。`;
