                                if (gHistory.length === 0) continue;
                                
                                // 检查角色是否已退群
                                const leftRecord = (g.leftMembers || []).find(lm => lm.id === targetCharId);
                                const isLeftGroup = !!leftRecord;
                                
                                // ✅ 使用统一的上下文条数（与私聊共享池）
                                let recentMsgs;
