                                                // ✅ 角色收取转账 → 角色FP钱包收入
                                                await fpWalletTransaction(targetCharId, myAccountId, 'income', parseFloat(tfData.amount), '转账收款', `来自${userName}${tfData.desc ? ' - ' + tfData.desc : ''}`);
