    // 导出分类
    async function exportStickerCategory(id) {
        const cat = await db.sticker_categories.get(id);
        const blob = new Blob([JSON.stringify(cat, null, 2)], {type: 'application/json'});
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `表情包-${cat.name}.json`;
        a.click();
        URL.revokeObjectURL(url);
    }

// 导入分类
function importStickerCategory(input) {
    const file = input.files[0];
    if (!file) return;
    
    const reader = new FileReader();
    reader.onload = async (e) => {
        try {
            const json = JSON.parse(e.target.result);
            // 简单的格式校验
            if (!json.name || !Array.isArray(json.stickers)) {
                throw new Error("格式不正确");
            }
            
            // 如果当前在详情页，询问是导入为新分类还是替换当前分类
            if (currentStickerCategoryId) {
                const action = confirm(`导入方式：\n确定 = 替换当前分类\n取消 = 创建新分类`);
                if (action) {
                    // 替换当前分类
                    const cat = await db.sticker_categories.get(currentStickerCategoryId);
                    if (cat) {
                        cat.name = json.name;
                        cat.stickers = json.stickers;
                        await db.sticker_categories.put(cat);
                        alert(`成功导入并替换分类：${json.name}`);
                        renderStickerCategoryDetail();
                    }
                } else {
                    // 创建新分类
                    delete json.id;
                    await db.sticker_categories.add(json);
                    alert(`成功导入为新分类：${json.name}`);
                    backToStickerList();
                }
            } else {
                // 在列表页，创建新分类
                delete json.id;
                await db.sticker_categories.add(json);
                alert(`成功导入分类：${json.name}`);
                renderStickerCategories();
            }
        } catch (err) {
            alert("导入失败: " + err.message);
        }
        // 清空input，允许重复导入同一文件
        input.value = '';
    };
    reader.readAsText(file);
}
// 批量导入表情包（从文本文件）
async function batchImportStickersFromText(input) {
    const file = input.files[0];
    if (!file) return;
    
    if (!currentStickerCategoryId) {
        alert('请先选择一个分类');
        input.value = '';
        return;
    }
    
    const fileName = file.name.toLowerCase();
    const isDocx = fileName.endsWith('.docx') || fileName.endsWith('.doc');
    
    // 如果是 .docx 文件，使用 JSZip 解析
    if (isDocx) {
        try {
            const arrayBuffer = await file.arrayBuffer();
            const zip = await JSZip.loadAsync(arrayBuffer);
            const docXml = await zip.file('word/document.xml').async('string');
            
            // ── 1. 先提取超链接 URL 映射（Word 把链接地址存在 rels 文件里） ──
            const hyperlinkMap = {};
            try {
                const relsFile = zip.file('word/_rels/document.xml.rels');
                if (relsFile) {
                    const relsXml = await relsFile.async('string');
                    const relRegex = /<Relationship[^>]+Id="([^"]+)"[^>]+Target="([^"]+)"[^>]*>/g;
                    let relMatch;
                    while ((relMatch = relRegex.exec(relsXml)) !== null) {
                        hyperlinkMap[relMatch[1]] = relMatch[2];
                    }
                }
            } catch(e) { /* rels 文件读取失败不影响主流程 */ }
            
            // ── 2. 按段落（<w:p>）提取文本，保留换行 ──
            const paragraphs = docXml.split(/<\/w:p>/);
            const lines = [];
            
            for (const para of paragraphs) {
                let lineText = '';
                
                // 处理超链接节点：<w:hyperlink r:id="rId5"><w:r><w:t>显示文字</w:t></w:r></w:hyperlink>
                // 优先使用 rels 中的真实 URL 而非显示文本
                let processedPara = para.replace(/<w:hyperlink[^>]*r:id="([^"]*)"[^>]*>([\s\S]*?)<\/w:hyperlink>/g, (fullMatch, rId, innerXml) => {
                    const realUrl = hyperlinkMap[rId];
                    if (realUrl && (realUrl.startsWith('http://') || realUrl.startsWith('https://'))) {
                        lineText += realUrl;
                        return ''; // 已处理，从剩余 XML 中移除
                    }
                    return fullMatch; // 无有效 URL，保留原样让后续 <w:t> 提取
                });
                
                // 提取剩余的 <w:t> 标签文本
                const textMatches = processedPara.match(/<w:t[^>]*>([^<]*)<\/w:t>/g) || [];
                for (const tm of textMatches) {
                    const content = tm.replace(/<w:t[^>]*>/, '').replace(/<\/w:t>/, '');
                    lineText += content;
                }
                
                lineText = lineText.trim();
                if (lineText) lines.push(lineText);
            }
            
            const extractedText = lines.join('\n');
            console.log('[DOCX导入] 提取到', lines.length, '行文本');
            
            // 处理提取的文本
            await processStickerText(extractedText, input);
        } catch (err) {
            console.error('解析 .docx 文件失败:', err);
            alert('解析 Word 文档失败，请确保文件格式正确。\n建议：将 Word 文档另存为 .txt 纯文本文件后再导入。\n\n错误信息: ' + err.message);
            input.value = '';
        }
        return;
    }
    
    // 处理纯文本文件 (.txt, .md 等)
    const reader = new FileReader();
    reader.onload = async (e) => {
        try {
            const text = e.target.result;
            await processStickerText(text, input);
        } catch (err) {
            console.error('批量导入失败:', err);
            alert('导入失败: ' + err.message);
            input.value = '';
        }
    };
    reader.readAsText(file, 'UTF-8');
}

// 处理表情包文本内容的通用函数
async function processStickerText(text, input) {
    try {
        const lines = text.split(/\r?\n/).filter(line => line.trim());
        
        if (lines.length === 0) {
            alert('文件为空或格式不正确');
            input.value = '';
            return;
        }
        
        const stickers = [];
        let successCount = 0;
        let failCount = 0;
        const errors = [];
        
        for (let i = 0; i < lines.length; i++) {
            const line = lines[i].trim();
            if (!line) continue;
            
            // 解析格式：描述：url 或 描述:url
            // 支持中英文冒号（：:）、冒号后有空格/全角空格/多余空格、冒号前有空格
            // 也支持「描述 url」用空格分隔的情况（当没有冒号时，以最后一个http开头的部分为URL）
            let description = '';
            let url = '';
            let parsed = false;
            
            // 方式1：用冒号分隔（中文：、英文:）
            const colonMatch = line.match(/^(.+?)\s*[：:]\s*(.+)$/);
            if (colonMatch) {
                description = colonMatch[1].trim();
                url = colonMatch[2].trim();
                parsed = true;
            }
            
            // 方式2：没匹配到冒号，尝试用空格分隔（描述 + 空格 + URL）
            if (!parsed) {
                const spaceMatch = line.match(/^(.+?)\s+(https?:\/\/.+)$/i);
                if (spaceMatch) {
                    description = spaceMatch[1].trim();
                    url = spaceMatch[2].trim();
                    parsed = true;
                }
            }
            
            // 方式3：整行就是一个URL
            if (!parsed && (line.startsWith('http://') || line.startsWith('https://') || line.startsWith('data:image'))) {
                url = line;
                parsed = true;
            }
            
            if (parsed && url) {
                // 清理 URL：去掉首尾空白、全角空格
                url = url.replace(/[\s\u3000]+$/, '').replace(/^[\s\u3000]+/, '');
                
                // 验证URL格式
                if (url.startsWith('http://') || url.startsWith('https://') || url.startsWith('data:image')) {
                    stickers.push({
                        url: url,
                        description: description,
                        created_at: Date.now()
                    });
                    successCount++;
                } else {
                    failCount++;
                    errors.push(`第${i+1}行：URL格式不正确 - ${line}`);
                }
            } else {
                failCount++;
                errors.push(`第${i+1}行：格式不正确 - ${line}`);
            }
        }
        
        if (stickers.length === 0) {
            alert('未能解析出任何表情包。\n格式应为：描述：图片链接\n例如：一只猫：https://example.com/cat.jpg');
            input.value = '';
            return;
        }
        
        // 添加到分类
        const cat = await db.sticker_categories.get(currentStickerCategoryId);
        if (!cat) {
            alert('分类不存在');
            input.value = '';
            return;
        }
        
        if (!cat.stickers) cat.stickers = [];
        cat.stickers.push(...stickers);
        await db.sticker_categories.put(cat);
        
        // 显示结果
        let message = `✅ 成功导入 ${successCount} 个表情包`;
        if (failCount > 0) {
            message += `\n❌ 失败 ${failCount} 个`;
            if (errors.length <= 5) {
                message += '\n\n错误详情：\n' + errors.join('\n');
            } else {
                message += `\n\n前5个错误：\n${errors.slice(0, 5).join('\n')}\n...还有${errors.length - 5}个错误`;
            }
            message += '\n\n提示：格式应为"描述：图片链接"，例如：\n一只猫：https://example.com/cat.jpg';
        }
        
        // 使用更友好的提示方式
        if (failCount === 0) {
            alert(message);
        } else {
            // 如果有错误，使用confirm让用户选择是否查看详情
            const showDetails = confirm(message + '\n\n是否查看详细错误信息？');
            if (showDetails && errors.length > 0) {
                alert('详细错误信息：\n\n' + errors.join('\n'));
            }
        }
        
        // 刷新页面
        renderStickerCategoryDetail();
        input.value = '';
    } catch (err) {
        console.error('处理表情包文本失败:', err);
        alert('导入失败: ' + err.message);
        input.value = '';
    }
}

