// 朋友圈交互逻辑
let activeMomentMenuId = null;

function toggleMomentMenu(id, e) {
    e.stopPropagation(); // 阻止冒泡
    
    // 如果已经打开了别的，先关闭别的
    if (activeMomentMenuId && activeMomentMenuId !== id) {
        const prev = document.getElementById(`moment-menu-${activeMomentMenuId}`);
        if (prev) prev.classList.remove('show');
    }
    
    const menu = document.getElementById(`moment-menu-${id}`);
    if (menu) {
        if (menu.classList.contains('show')) {
            menu.classList.remove('show');
            activeMomentMenuId = null;
        } else {
            menu.classList.add('show');
            activeMomentMenuId = id;
            
            // 绑定一次性全局点击事件来关闭菜单
            document.addEventListener('click', closeMomentMenuOutside, { once: true });
        }
    }
}

function closeMomentMenuOutside(e) {
    if (activeMomentMenuId) {
        const menu = document.getElementById(`moment-menu-${activeMomentMenuId}`);
        if (menu && !menu.contains(e.target)) {
            menu.classList.remove('show');
            activeMomentMenuId = null;
        }
    }
}

async function likeMoment(id) {
    // 立即关闭菜单
    const menu = document.getElementById(`moment-menu-${id}`);
    if (menu) menu.classList.remove('show');
    activeMomentMenuId = null;

    if (!currentMyCharId) return;
    
    const user = await db.characters.get(parseInt(currentMyCharId));
    const moment = await db.moments.get(id);
    
    if (user && moment) {
        if (!moment.likes) moment.likes = [];
        
        const idx = moment.likes.findIndex(l => l.userId == user.id);
        if (idx > -1) {
            // 取消点赞
            moment.likes.splice(idx, 1);
        } else {
            // 点赞
            moment.likes.push({ userId: user.id, name: user.name });
        }
        
        await db.moments.put(moment);
        renderMomentsList(); // 刷新列表
    }
}

async function commentMoment(id) {
    // 立即关闭菜单
    const menu = document.getElementById(`moment-menu-${id}`);
    if (menu) menu.classList.remove('show');
    activeMomentMenuId = null;

    if (!currentMyCharId) return;
    
    // 使用 setTimeout 让菜单先关闭，再弹出 prompt
    setTimeout(async () => {
        const content = prompt("请输入评论内容：");
        if (content && content.trim()) {
            const user = await db.characters.get(parseInt(currentMyCharId));
            const moment = await db.moments.get(id);
            
            if (user && moment) {
                if (!moment.comments) moment.comments = [];
                
                moment.comments.push({
                    userId: user.id,
                    name: user.name,
                    content: content.trim(),
                    time: Date.now()
                });
                
                await db.moments.put(moment);
                renderMomentsList(); // 刷新列表
                
                // 🔥 触发朋友圈发布者AI回复用户的评论
                generateMomentOwnerReply(id, user.name, content.trim());
            }
        }
    }, 50);
}

// === 朋友圈评论长按菜单 ===
let _commentLongPressTimer = null;

function startCommentLongPress(e, momentId, commentIdx) {
    _commentLongPressTimer = setTimeout(() => {
        _commentLongPressTimer = null;
        // 触发触觉反馈（如果支持）
        if (navigator.vibrate) navigator.vibrate(20);
        showCommentContextMenu(e, momentId, commentIdx);
    }, 500);
}

function cancelCommentLongPress() {
    if (_commentLongPressTimer) {
        clearTimeout(_commentLongPressTimer);
        _commentLongPressTimer = null;
    }
}

function showCommentContextMenu(e, momentId, commentIdx) {
    // 移除已存在的菜单
    const old = document.getElementById('comment-context-menu');
    if (old) old.remove();

    const menu = document.createElement('div');
    menu.id = 'comment-context-menu';
    menu.style.cssText = `
        position:fixed; z-index:99999;
        background:#fff; border-radius:10px;
        box-shadow:0 6px 24px rgba(0,0,0,0.18);
        overflow:hidden; min-width:120px;
        animation: fadeIn 0.15s ease;
    `;

    // 定位：优先在手指/鼠标位置附近
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    menu.style.left = Math.min(clientX, window.innerWidth - 140) + 'px';
    menu.style.top = Math.min(clientY - 10, window.innerHeight - 100) + 'px';

    const btnStyle = 'padding:12px 20px; font-size:15px; color:#333; cursor:pointer; border:none; background:none; width:100%; text-align:left; display:block;';
    const dividerStyle = 'height:1px; background:#f0f0f0; margin:0;';

    menu.innerHTML = `
        <button style="${btnStyle}" ontouchstart="this.style.background='#f5f5f5'" ontouchend="this.style.background=''" onclick="copyMomentComment(${momentId},${commentIdx})">复制</button>
        <div style="${dividerStyle}"></div>
        <button style="${btnStyle}color:#ff3b30;" ontouchstart="this.style.background='#f5f5f5'" ontouchend="this.style.background=''" onclick="deleteMomentComment(${momentId},${commentIdx})">删除</button>
    `;

    document.body.appendChild(menu);

    // 点击其他区域关闭菜单
    const dismiss = (ev) => {
        if (!menu.contains(ev.target)) {
            menu.remove();
            document.removeEventListener('click', dismiss, true);
            document.removeEventListener('touchstart', dismiss, true);
        }
    };
    setTimeout(() => {
        document.addEventListener('click', dismiss, true);
        document.addEventListener('touchstart', dismiss, true);
    }, 50);
}

// 复制评论内容
async function copyMomentComment(momentId, commentIdx) {
    document.getElementById('comment-context-menu')?.remove();
    try {
        const moment = await db.moments.get(momentId);
        if (moment && moment.comments && moment.comments[commentIdx]) {
            const text = moment.comments[commentIdx].content || '';
            await navigator.clipboard.writeText(text);
            showToast('已复制');
        }
    } catch (e) {
        console.error('[朋友圈] 复制评论失败:', e);
    }
}

// 删除评论
async function deleteMomentComment(momentId, commentIdx) {
    document.getElementById('comment-context-menu')?.remove();
    try {
        const moment = await db.moments.get(momentId);
        if (moment && moment.comments && moment.comments[commentIdx]) {
            moment.comments.splice(commentIdx, 1);
            await db.moments.put(moment);
            renderMomentsList();
            showToast('评论已删除');
        }
    } catch (e) {
        console.error('[朋友圈] 删除评论失败:', e);
    }
}

// 回复朋友圈中某个角色的评论
async function replyToMomentComment(momentId, replyToName, commentIdx) {
    if (!currentMyCharId) return;
    
    setTimeout(async () => {
        const content = prompt(`回复 ${replyToName}：`);
        if (content && content.trim()) {
            const user = await db.characters.get(parseInt(currentMyCharId));
            const moment = await db.moments.get(momentId);
            
            if (user && moment) {
                if (!moment.comments) moment.comments = [];
                
                // 添加用户的回复
                moment.comments.push({
                    userId: user.id,
                    name: user.name,
                    replyTo: replyToName,
                    content: content.trim(),
                    time: Date.now()
                });
                
                await db.moments.put(moment);
                renderMomentsList();
                
                // 触发被回复的角色自动回复
                generateReplyToUserComment(momentId, replyToName, content.trim());
            }
        }
    }, 50);
}

// AI生成角色对用户回复的再回复
async function generateReplyToUserComment(momentId, charName, userComment) {
    try {
        const moment = await db.moments.get(momentId);
        if (!moment) return;
        
        const accountId = getCurrentAccountId();
        const myChar = await db.characters.get(parseInt(currentMyCharId));
        const myName = myChar?.name || '我';
        
        // 找到这个角色
        const allChars = await db.characters.toArray();
        const targetChar = allChars.find(c => {
            const displayName = getCharDisplayName(c, accountId);
            return displayName === charName || c.name === charName;
        });
        
        if (!targetChar) return;
        
        // 获取用户与角色的关系上下文
        let relationContext = '';
        try {
            if (myChar) {
                relationContext += `\n【${myName}（回复你的人）的信息】\n`;
                relationContext += `名字：${myName}\n`;
                if (myChar.description) relationContext += `设定：${myChar.description}\n`;
            }
            if (targetChar.remark) {
                relationContext += `${targetChar.name} 对 ${myName} 的备注/称呼：${targetChar.remark}\n`;
            }
            // 最近聊天记录
            const history = getChatHistory(targetChar, accountId);
            if (history && history.length > 0) {
                const recent = history.slice(-10).map(m => {
                    const role = m.role === 'char' ? targetChar.name : myName;
                    return `${role}: ${m.content}`;
                }).join('\n');
                relationContext += `\n【${targetChar.name}与${myName}的最近聊天】\n${recent}\n`;
            }
        } catch (e) {
            console.warn('[朋友圈回复] 获取关系上下文失败:', e);
        }
        
        // 找到角色之前在这条朋友圈下的评论
        const charPrevComments = (moment.comments || [])
            .filter(c => {
                const cName = c.name;
                return cName === charName;
            })
            .map(c => c.content)
            .join('；');
        
        const prompt = `你是 ${targetChar.name}，你在 ${myName} 的朋友圈下评论了："${charPrevComments}"
${relationContext}
${myName} 回复了你："${userComment}"

请以 ${targetChar.name} 的身份，用简短自然的语气再回复 ${myName}（3-20字，可以用表情、语气词）。
注意：你和 ${myName} 是认识的，请根据你们的关系亲密程度来回复。

人设参考：${targetChar.description || targetChar.personality || '普通朋友'}

只返回回复内容，不要JSON，不要引号。`;
        
        const result = await callAI([
            { role: 'system', content: '你是一个社交媒体评论角色扮演助手，直接返回回复内容，不要任何格式标记。' },
            { role: 'user', content: prompt }
        ], { _useSecondary: true });
        
        const replyContent = result.trim().replace(/^["'"]|["'"]$/g, '');
        if (replyContent) {
            // 重新获取最新的moment（防止并发修改）
            const freshMoment = await db.moments.get(momentId);
            if (freshMoment) {
                if (!freshMoment.comments) freshMoment.comments = [];
                freshMoment.comments.push({
                    userId: targetChar.id,
                    name: targetChar.remark || targetChar.wx_nickname || targetChar.name,
                    replyTo: myName,
                    content: replyContent,
                    time: Date.now()
                });
                await db.moments.put(freshMoment);
                renderMomentsList();
            }
        }
    } catch (err) {
        console.error('[朋友圈回复] AI回复生成失败:', err);
    }
}

// 🔥 朋友圈发布者AI回复用户的评论
async function generateMomentOwnerReply(momentId, userName, userComment) {
    try {
        const moment = await db.moments.get(momentId);
        if (!moment) return;
        
        // 找到发布者
        const ownerChar = await db.characters.get(moment.userId);
        if (!ownerChar) return;
        
        // 如果发布者是用户自己，不需要AI回复
        if (parseInt(currentMyCharId) === ownerChar.id) return;
        
        const myChar = await db.characters.get(parseInt(currentMyCharId));
        const myName = myChar?.name || userName;
        
        // 获取用户与角色的关系上下文
        const accountId = getCurrentAccountId();
        let relationContext = '';
        try {
            // 用户信息
            if (myChar) {
                relationContext += `\n【${myName}（评论者）的信息】\n`;
                relationContext += `名字：${myName}\n`;
                if (myChar.description) relationContext += `设定：${myChar.description}\n`;
            }
            // 角色备注（角色给用户的备注）
            if (ownerChar.remark_by_user && ownerChar.remark_by_user[accountId]) {
                relationContext += `${myName} 给 ${ownerChar.name} 的备注：${ownerChar.remark_by_user[accountId]}\n`;
            }
            if (ownerChar.remark) {
                relationContext += `${ownerChar.name} 对 ${myName} 的备注/称呼：${ownerChar.remark}\n`;
            }
            // 最近聊天记录
            const history = getChatHistory(ownerChar, accountId);
            if (history && history.length > 0) {
                const recent = history.slice(-10).map(m => {
                    const role = m.role === 'char' ? ownerChar.name : myName;
                    return `${role}: ${m.content}`;
                }).join('\n');
                relationContext += `\n【${ownerChar.name}与${myName}的最近聊天】\n${recent}\n`;
            }
        } catch (e) {
            console.warn('[朋友圈回复] 获取关系上下文失败:', e);
        }
        
        // 获取已有的所有评论，用于上下文
        const existingComments = (moment.comments || []).map(c => {
            const replyPart = c.replyTo ? ` 回复 ${c.replyTo}` : '';
            return `${c.name}${replyPart}：${c.content}`;
        }).join('\n');
        
        const promptText = `你是 ${ownerChar.name}，你发了一条朋友圈："${moment.content}"
${relationContext}
${existingComments ? `朋友圈下已有的评论：\n${existingComments}\n` : ''}
${myName} 评论了你的朋友圈："${userComment}"

请以 ${ownerChar.name} 的身份回复 ${myName} 的评论。要求：
- 简短自然（3-30字）
- 符合你的性格和说话风格
- 符合你和 ${myName} 之间的关系和亲密程度
- 可以用表情、语气词
- 像真人回复朋友圈评论一样随意

人设参考：${ownerChar.description || ownerChar.personality || ''}

只返回回复内容，不要JSON，不要引号。`;
        
        // 延迟2-5秒后回复，模拟真人
        const delay = 2000 + Math.random() * 3000;
        await new Promise(r => setTimeout(r, delay));
        
        const result = await callAI([
            { role: 'system', content: '你是一个社交媒体评论角色扮演助手，直接返回回复内容，不要任何格式标记。' },
            { role: 'user', content: promptText }
        ], { _useSecondary: true });
        
        const replyContent = result.trim().replace(/^["'"""]+|["'"""]+$/g, '');
        if (replyContent) {
            const freshMoment = await db.moments.get(momentId);
            if (freshMoment) {
                if (!freshMoment.comments) freshMoment.comments = [];
                freshMoment.comments.push({
                    userId: ownerChar.id,
                    name: ownerChar.remark || ownerChar.wx_nickname || ownerChar.name,
                    replyTo: myName,
                    content: replyContent,
                    time: Date.now()
                });
                await db.moments.put(freshMoment);
                renderMomentsList();
                console.log(`[朋友圈] ${ownerChar.name} 回复了 ${myName} 的评论: ${replyContent}`);
            }
        }
    } catch (err) {
        console.error('[朋友圈] 发布者AI回复失败:', err);
    }
}

// 🔥 共同好友NPC自动评论朋友圈
async function triggerMutualFriendComments(momentId) {
    try {
        const moment = await db.moments.get(momentId);
        if (!moment) return;
        
        // 如果已经触发过NPC评论，跳过（防止重复）
        if (moment._npcCommented) return;
        
        const accountId = getCurrentAccountId();
        if (!accountId) return;
        
        // 找到发布者
        const ownerChar = await db.characters.get(moment.userId);
        if (!ownerChar) return;
        
        // 获取发布者的关联角色/NPC
        const relationships = ownerChar.relationships || [];
        if (relationships.length === 0) return;
        
        // 找到发布者的所有关联NPC（不再限制必须是共同好友）
        const allChars = await db.characters.toArray();
        const relatedNPCs = [];
        
        for (const rel of relationships) {
            if (!rel.targetId) continue;
            const npc = allChars.find(c => c.id === rel.targetId);
            if (!npc) continue;
            // 排除用户角色，不要给用户自动生成评论
            if (npc.type === 'user') continue;
            
            relatedNPCs.push({ npc, relation: rel.relation, desc: rel.desc || '' });
        }
        
        if (relatedNPCs.length === 0) return;
        
        console.log(`[朋友圈NPC] 发现 ${relatedNPCs.length} 个关联NPC可以评论 ${ownerChar.name} 的朋友圈`);
        
        // 标记已触发NPC评论
        const markMoment = await db.moments.get(momentId);
        if (markMoment) {
            markMoment._npcCommented = true;
            await db.moments.put(markMoment);
        }
        
        // 随机选取1-3个NPC来评论（不是所有人都会评论）
        const shuffled = relatedNPCs.sort(() => Math.random() - 0.5);
        const commentCount = Math.min(shuffled.length, 1 + Math.floor(Math.random() * 3));
        const selectedNPCs = shuffled.slice(0, commentCount);
        
        // 🔥 一次API调用批量生成所有NPC评论（不再逐个单独调用）
        try {
            const freshMoment = await db.moments.get(momentId);
            if (!freshMoment) return;
            
            // 获取发布者的人设和世界书上下文
            const ownerDesc = ownerChar.description || ownerChar.personality || '';
            let mutualLoreContext = '';
            try {
                const lorebookIds = ownerChar.lorebookIds || (ownerChar.lorebookId ? [ownerChar.lorebookId] : []);
                if (lorebookIds.length > 0 && typeof getLorebookContext === 'function') {
                    mutualLoreContext = await getLorebookContext(lorebookIds, ownerChar.name);
                }
            } catch (e) {
                console.warn('[朋友圈NPC] 获取世界书失败:', e);
            }
            
            // 构建所有选中NPC的信息
            const npcInfos = selectedNPCs.map(({ npc, relation }) => {
                const displayName = npc.remark || npc.wx_nickname || npc.name;
                return `- ${displayName}（和${ownerChar.name}的关系：${relation}）：${npc.description || npc.personality || '普通朋友'}`;
            }).join('\n');
            
            // 构建包含人设上下文的 system prompt
            const mutualNpcSystemPrompt = `你正在进行角色扮演世界中的社交模拟。请严格基于以下角色设定和世界观来生成评论，确保每条评论都符合对应角色的人设。

【朋友圈发布者信息】
名字：${ownerChar.name}
${ownerChar.wx_nickname ? `微信网名：${ownerChar.wx_nickname}` : ''}
${ownerDesc ? `人设：\n${ownerDesc}` : ''}
${mutualLoreContext ? `\n【世界观】\n${mutualLoreContext}` : ''}

只返回JSON数组，不要任何其他文字。`;
            
            const batchPrompt = `${ownerChar.name} 发了一条朋友圈："${freshMoment.content}"
${freshMoment.imageCount > 0 || (freshMoment.images && freshMoment.images.length > 0) ? `（附带${freshMoment.imageCount || freshMoment.images.length}张图片${freshMoment.imageDesc ? '：' + freshMoment.imageDesc : ''}）` : ''}

以下是 ${ownerChar.name} 的好友，请为每个人生成一条符合其人设、性格和关系的朋友圈评论：
${npcInfos}

要求：
1. 每条评论简短自然（2-25字）
2. 可以用表情、语气词、调侃、夸赞、吐槽等
3. **必须符合每个角色的人设、性格特点和与${ownerChar.name}的关系**
4. 像真人在朋友圈下评论一样随意
5. 鼓励好友之间互相回复（使用 replyTo 字段指定回复的人名）

请返回JSON数组格式：
[{"name": "角色名", "content": "评论内容"}, {"name": "角色名", "replyTo": "被回复的角色名", "content": "回复内容"}, ...]`;

            const result = await callAI([
                { role: 'system', content: mutualNpcSystemPrompt },
                { role: 'user', content: batchPrompt }
            ], { json_mode: true, _useSecondary: true });
            
            // 解析结果
            let aiComments = [];
            try {
                let cleanResult = result.trim();
                if (cleanResult.startsWith('```')) {
                    cleanResult = cleanResult.replace(/```json?\n?/g, '').replace(/```$/g, '').trim();
                }
                // 尝试提取JSON数组
                const parsed = extractAndParseJSON(cleanResult);
                if (Array.isArray(parsed)) {
                    aiComments = parsed;
                } else if (parsed && Array.isArray(parsed.comments)) {
                    aiComments = parsed.comments;
                } else {
                    aiComments = JSON.parse(cleanResult);
                }
            } catch (e) {
                console.warn('[朋友圈NPC] AI评论批量解析失败:', e);
            }
            
            // 延迟逐条写入评论（模拟真实场景）
            const latestMoment = await db.moments.get(momentId);
            if (latestMoment && aiComments.length > 0) {
                if (!latestMoment.comments) latestMoment.comments = [];
                
                // 先收集本轮要添加的评论
                const newComments = [];
                for (const aiComment of aiComments) {
                    // 匹配NPC
                    const matched = selectedNPCs.find(({ npc }) => {
                        const displayName = npc.remark || npc.wx_nickname || npc.name;
                        return displayName === aiComment.name || npc.name === aiComment.name;
                    });
                    if (matched && aiComment.content) {
                        const commentObj = {
                            userId: matched.npc.id,
                            name: matched.npc.remark || matched.npc.wx_nickname || matched.npc.name,
                            content: aiComment.content.trim().replace(/^["'"""]+|["'"""]+$/g, ''),
                            time: Date.now() + Math.random() * 60000
                        };
                        if (aiComment.replyTo) {
                            commentObj.replyTo = aiComment.replyTo;
                        }
                        newComments.push(commentObj);
                        console.log(`[朋友圈NPC] ${matched.npc.name}(${matched.relation}) 评论了 ${ownerChar.name} 的朋友圈: ${aiComment.content}`);
                    }
                }
                
                // 校验 replyTo：确保被回复的人确实有评论，否则去掉 replyTo
                const allCommentNames = new Set([
                    ...latestMoment.comments.map(c => c.name),
                    ...newComments.map(c => c.name)
                ]);
                for (const c of newComments) {
                    if (c.replyTo && !allCommentNames.has(c.replyTo)) {
                        console.log(`[朋友圈NPC] ⚠️ replyTo "${c.replyTo}" 不存在，已移除回复标记`);
                        delete c.replyTo;
                    }
                }
                
                latestMoment.comments.push(...newComments);
                await db.moments.put(latestMoment);
                renderMomentsList();
                console.log(`[朋友圈NPC] ✅ 批量生成完成: ${newComments.length}条评论`);
            }
        } catch (err) {
            console.error('[朋友圈NPC] 批量评论生成失败:', err);
        }
        
        // 部分NPC也可能点赞（随机50%概率）
        for (const { npc } of relatedNPCs) {
            if (Math.random() < 0.5) {
                const likeDelay = 1000 + Math.random() * 5000;
                setTimeout(async () => {
                    try {
                        const latestMoment = await db.moments.get(momentId);
                        if (!latestMoment) return;
                        if (!latestMoment.likes) latestMoment.likes = [];
                        // 检查是否已经点赞
                        if (latestMoment.likes.some(l => l.userId === npc.id)) return;
                        latestMoment.likes.push({
                            userId: npc.id,
                            name: npc.remark || npc.wx_nickname || npc.name
                        });
                        await db.moments.put(latestMoment);
                        renderMomentsList();
                        console.log(`[朋友圈NPC] ${npc.name} 点赞了 ${ownerChar.name} 的朋友圈`);
                    } catch (e) {}
                }, likeDelay);
            }
        }
    } catch (err) {
        console.error('[朋友圈NPC] NPC评论触发失败:', err);
    }
}

