let currentBillFilter = 'all';

function showBillPage() {
    const billPage = document.getElementById('bill-page');
    billPage.style.display = 'flex';
    billPage.offsetHeight;
    billPage.classList.add('active');
    currentBillFilter = 'all';
    renderBillList();
}

