// ==================== 角色主动来电功能 ====================
let _incomingCallCharId = null;     // 当前来电角色ID
let _incomingCallRingtone = null;   // 来电铃声音频
let _incomingCallTimeout = null;    // 来电超时自动挂断
let _incomingCallFirstMsg = null;   // AI生成的第一句话（接听后使用）

// 显示来电弹窗
async function showIncomingCall(charId, firstMessage) {
    if (_incomingCallCharId) return; // 已有来电，不叠加
    
    const char = await db.characters.get(charId);
    if (!char) return;
    
    const accountId = getCurrentAccountId();
    const displayName = getCharDisplayName(char, accountId);
    const avatar = getCharAvatar(char, accountId);
    
    // 🔧 如果用户正在视频通话中（包括最小化状态），自动拒绝并通知对方正在通话中
    if (isInVideoCall()) {
        console.log(`[IncomingCall] ❌ 用户正在视频通话中，自动拒绝 ${displayName} 的来电`);
        let history = getChatHistory(char, accountId);
        // ⚠️ 不设 isVideoCall:true，用 type:'call_busy'，确保 AI 上下文能读到这条消息
        // content 给 AI 看（完整语义），displayContent 给用户看（简短）
        history.push({
            role: 'system',
            content: `📞 你给对方打了语音电话，但对方正在和别人通话中，电话占线未能接通。`,
            displayContent: `📞 语音通话占线中`,
            time: Date.now(),
            type: 'call_busy'
        });
        await setChatHistory(char, accountId, history);
        await safeCharacterPut(char);
        // 刷新聊天界面
        if (currentChatCharId === charId) {
            const freshChar = await db.characters.get(charId);
            if (freshChar) await renderChatBody(freshChar, true);
        }
        // 刷新微信列表
        const wechatList = document.getElementById('wechat-chat-list');
        if (wechatList) await renderWechatList(wechatList);
        return 'busy';
    }
    
    _incomingCallCharId = charId;
    _incomingCallFirstMsg = firstMessage || null;
    
    // 填充来电信息
    const nameEl = document.getElementById('incoming-call-name');
    const avatarEl = document.getElementById('incoming-call-avatar');
    if (nameEl) nameEl.textContent = displayName;
    if (avatarEl) avatarEl.style.backgroundImage = avatar ? `url(${avatar})` : '';
    
    // 显示弹窗
    const overlay = document.getElementById('incoming-call-overlay');
    if (overlay) overlay.style.display = 'block';
    
    // 尝试播放铃声（静音环境下可能被浏览器拦截）
    try {
        _incomingCallRingtone = new Audio('data:audio/wav;base64,UklGRnoGAABXQVZFZm10IBAAAAABAAEAQB8AAEAfAAABAAgAZGF0YQ==');
        _incomingCallRingtone.loop = true;
        _incomingCallRingtone.volume = 0.3;
        _incomingCallRingtone.play().catch(() => {});
    } catch (e) { /* 忽略音频失败 */ }
    
    // 震动反馈（移动端）
    if (navigator.vibrate) {
        navigator.vibrate([300, 200, 300, 200, 300]);
    }
    
    // 30秒无操作自动未接
    _incomingCallTimeout = setTimeout(() => {
        missIncomingCall('timeout');
    }, 30000);
    
    console.log(`[IncomingCall] 📞 ${displayName} 来电中...`);
}

// 接听来电
async function acceptIncomingCall() {
    if (!_incomingCallCharId) return;
    
    const charId = _incomingCallCharId;
    const firstMsg = _incomingCallFirstMsg;
    cleanupIncomingCall();
    
    const char = await db.characters.get(charId);
    if (!char) return;
    
    const accountId = getCurrentAccountId();
    
    // 记录系统消息：通话已接听
    let history = getChatHistory(char, accountId);
    history.push({
        role: 'system',
        content: `📞 ${getCharDisplayName(char, accountId)} 发起了语音通话，你已接听`,
        time: Date.now()
    });
    await setChatHistory(char, accountId, history);
    await safeCharacterPut(char);
    
    // 设置视频通话角色ID，直接进入视频通话页面
    videoCallCharId = charId;
    await showVideoCallPage(char, firstMsg || '');
    
    console.log(`[IncomingCall] ✅ 已接听 ${char.name} 的来电，进入通话页面`);
}

// 挂断来电
async function declineIncomingCall() {
    if (!_incomingCallCharId) return;
    
    const charId = _incomingCallCharId;
    cleanupIncomingCall();
    
    await recordMissedCall(charId, 'declined');
    console.log(`[IncomingCall] ❌ 已挂断来电`);
}

// 来电超时未接
async function missIncomingCall(reason) {
    if (!_incomingCallCharId) return;
    
    const charId = _incomingCallCharId;
    cleanupIncomingCall();
    
    await recordMissedCall(charId, reason);
    console.log(`[IncomingCall] ⏰ 来电未接 (${reason})`);
}

// 记录未接来电到聊天记录
async function recordMissedCall(charId, reason) {
    const char = await db.characters.get(charId);
    if (!char) return;
    
    const accountId = getCurrentAccountId();
    const displayName = getCharDisplayName(char, accountId);
    let history = getChatHistory(char, accountId);
    
    const reasonText = reason === 'declined' ? '你已挂断' : '未接听';
    history.push({
        role: 'system',
        content: `📞 ${displayName} 发起了语音通话，${reasonText}`,
        time: Date.now()
    });
    await setChatHistory(char, accountId, history);
    await safeCharacterPut(char);
    
    // 发送系统通知
    sendSystemNotification(`未接来电`, `${displayName} 给你打了个电话`);
    
    // 如果当前正在该聊天页面，刷新显示
    if (currentChatCharId === charId) {
        const freshChar = await db.characters.get(charId);
        if (freshChar) await renderChatBody(freshChar, true);
    }
    
    // 刷新微信列表
    const wechatList = document.getElementById('wechat-chat-list');
    if (wechatList) await renderWechatList(wechatList);
}

// 清理来电状态
function cleanupIncomingCall() {
    _incomingCallCharId = null;
    _incomingCallFirstMsg = null;
    
    // 隐藏弹窗
    const overlay = document.getElementById('incoming-call-overlay');
    if (overlay) overlay.style.display = 'none';
    
    // 停止铃声
    if (_incomingCallRingtone) {
        _incomingCallRingtone.pause();
        _incomingCallRingtone = null;
    }
    
    // 停止震动
    if (navigator.vibrate) navigator.vibrate(0);
    
    // 清除超时
    if (_incomingCallTimeout) {
        clearTimeout(_incomingCallTimeout);
        _incomingCallTimeout = null;
    }
}

// ==================== 视频通话功能 ====================
let videoCallTimeout = null;
let videoCallTimer = null;
let videoCallSeconds = 0;
let videoCallCharId = null;
let videoCallCancelled = false; // 标记视频通话是否已被取消/超时
let isCameraOn = true;
let currentVideoCallId = null; // 当前视频通话的ID
let currentVideoCallMessages = []; // 当前视频通话的消息记录
let isVideoCallMinimized = false; // 标记视频通话是否处于最小化状态

// 最小化视频通话 - 隐藏全屏页面，显示悬浮按钮
function minimizeVideoCall() {
    const videoPage = document.getElementById('video-call-page');
    const floatingBtn = document.getElementById('video-call-floating-btn');
    if (videoPage) videoPage.style.display = 'none';
    if (floatingBtn) floatingBtn.style.display = 'block';
    isVideoCallMinimized = true;
    // 更新悬浮按钮计时器
    updateFloatingTimer();
    // 悬浮按钮拖拽初始化
    initFloatingBtnDrag();
}

// 恢复视频通话 - 显示全屏页面，隐藏悬浮按钮
function restoreVideoCall() {
    const videoPage = document.getElementById('video-call-page');
    const floatingBtn = document.getElementById('video-call-floating-btn');
    if (videoPage) videoPage.style.display = 'block';
    if (floatingBtn) floatingBtn.style.display = 'none';
    isVideoCallMinimized = false;
}

// 更新悬浮按钮上的通话计时
function updateFloatingTimer() {
    if (!isVideoCallMinimized) return;
    const timerEl = document.getElementById('video-call-floating-timer');
    if (timerEl) {
        const minutes = Math.floor(videoCallSeconds / 60);
        const seconds = videoCallSeconds % 60;
        timerEl.textContent = `${minutes}:${seconds < 10 ? '0' + seconds : seconds}`;
    }
}

// 悬浮按钮拖拽功能
function initFloatingBtnDrag() {
    const btn = document.getElementById('video-call-floating-btn');
    if (!btn || btn._dragInited) return;
    btn._dragInited = true;
    
    let isDragging = false;
    let startX, startY, startLeft, startTop;
    let hasMoved = false;
    
    function onStart(e) {
        isDragging = true;
        hasMoved = false;
        const touch = e.touches ? e.touches[0] : e;
        startX = touch.clientX;
        startY = touch.clientY;
        const rect = btn.getBoundingClientRect();
        startLeft = rect.left;
        startTop = rect.top;
        btn.style.transition = 'none';
        e.preventDefault();
    }
    
    function onMove(e) {
        if (!isDragging) return;
        const touch = e.touches ? e.touches[0] : e;
        const dx = touch.clientX - startX;
        const dy = touch.clientY - startY;
        if (Math.abs(dx) > 3 || Math.abs(dy) > 3) hasMoved = true;
        const newLeft = Math.max(0, Math.min(window.innerWidth - 70, startLeft + dx));
        const newTop = Math.max(0, Math.min(window.innerHeight - 90, startTop + dy));
        btn.style.position = 'fixed';
        btn.style.left = newLeft + 'px';
        btn.style.top = newTop + 'px';
        btn.style.right = 'auto';
        btn.style.bottom = 'auto';
        e.preventDefault();
    }
    
    function onEnd(e) {
        if (!isDragging) return;
        isDragging = false;
        btn.style.transition = 'left 0.3s ease';
        // 自动吸附到左右两侧
        const rect = btn.getBoundingClientRect();
        const midX = rect.left + rect.width / 2;
        if (midX < window.innerWidth / 2) {
            btn.style.left = '12px';
        } else {
            btn.style.left = (window.innerWidth - rect.width - 12) + 'px';
        }
        // 如果没有拖拽过，视为点击
        if (!hasMoved) {
            restoreVideoCall();
        }
    }
    
    btn.addEventListener('touchstart', onStart, { passive: false });
    btn.addEventListener('touchmove', onMove, { passive: false });
    btn.addEventListener('touchend', onEnd);
    btn.addEventListener('mousedown', onStart);
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onEnd);
}

// 检查是否正在视频通话中（包括最小化状态）
function isInVideoCall() {
    return videoCallCharId !== null;
}

// 发起视频通话
async function initiateVideoCall() {
    if (!currentChatCharId) {
        alert('请先选择一个聊天对象');
        return;
    }
    
    // 🔧 如果已经在视频通话中，提示用户
    if (isInVideoCall()) {
        alert('你正在视频通话中，请先结束当前通话');
        return;
    }

    // 关闭菜单面板
    closeChatPanel();

    // 获取角色信息
    const char = await db.characters.get(currentChatCharId);
    if (!char) {
        alert('无法获取角色信息');
        return;
    }

    // 检查好友状态
    const accountId = getCurrentAccountId();
    const friendStatus = getFriendStatus(char, accountId);
    if (friendStatus !== 'friend') {
        alert(`你还不是 ${char.name} 的好友，无法发起视频通话`);
        return;
    }

    videoCallCharId = currentChatCharId;
    videoCallCancelled = false; // 重置取消标记

    // 显示等待接听页面
    showVideoWaitingPage(char);

    try {
        // 调用API判断角色是否接听（一次调用返回：是否接通 + 第一句话/拒绝消息）
        const response = await callVideoCallAPI(char, accountId);
        
        // ✅ 检查：如果在 API 调用期间被超时/取消了，忽略响应
        if (videoCallCancelled) {
            console.log('[视频通话] API 返回但通话已被取消/超时，忽略响应');
            return;
        }
        
        // 清除超时定时器
        if (videoCallTimeout) {
            clearTimeout(videoCallTimeout);
            videoCallTimeout = null;
        }

        if (response.accepted) {
            // 接听了，显示视频通话页面，直接传入第一句话和预生成的图片tags（一次 API 调用已获得）
            showVideoCallPage(char, response.acceptMessage, response.imageTags);
        } else {
            // 不接听，返回聊天页面并显示拒绝消息（保存到聊天记录）
            hideVideoWaitingPage();
            await addVideoCallMessage(char, accountId, response.rejectMessage);
        }
    } catch (error) {
        console.error('视频通话请求失败:', error);
        if (!videoCallCancelled) {
            hideVideoWaitingPage();
            alert('视频通话请求失败: ' + error.message);
        }
    }
}

// 调用API判断是否接听视频通话（合并接听判断+第一句话为一次调用）
async function callVideoCallAPI(char, accountId) {
    // 构建消息历史
    let history = getChatHistory(char, accountId);
    
    // 获取对话对象（用户）人设
    let userDesc = "";
    let userName = "用户";
    if (char.linked_user_id) {
        const user = await db.characters.get(char.linked_user_id);
        if (user) {
            userName = user.name;
            userDesc = `\n\n【对话对象(User)信息】\n名字：${user.name}\n设定：${user.description || '无'}`;
        }
    }
    
    // 获取世界书上下文
    let loreContext = "";
    const lorebookIds = char.lorebookIds || (char.lorebookId ? [char.lorebookId] : []);
    if (lorebookIds.length > 0 || true) { // 始终调用，会自动加载全局世界书
        const recentText = history.slice(-10).map(m => m.content).join(' ');
        loreContext = await getLorebookContext(lorebookIds, `${char.name} ${userName} ${recentText}`);
    }
    
    // 计算虚拟时间
    const virtualTimeStr = getFormattedVirtualTime(char);
    
    // 🔧 读取总结记忆和话题感知
    let summaryMemoryContext = '';
    try { summaryMemoryContext = await getSummaryMemoryContext('private', char.id, accountId); } catch (e) {}
    let recentTopicsContext = '';
    try { recentTopicsContext = buildRecentTopicsContext(history); } catch (e) {}
    
    // 🔧 构建通话前的聊天摘要（至关重要！让 AI 知道通话的上下文和原因）
    const preCallHistory = history.slice(-10);
    const preCallContext = preCallHistory.map(m => {
        // 🔧 修复：系统消息正确归属为"[系统]"，而非角色名
        if (m.role === 'system') return `[系统]: ${String(m.content || '').substring(0, 80)}`;
        const sender = m.role === 'user' ? userName : char.name;
        const content = String(m.content || '').substring(0, 80);
        return `${sender}: ${content}`;
    }).join('\n');
    
    // 🔧 检查并构建之前视频通话的详细历史摘要（解决"每次都以为是第一次通话"的问题）
    const prevVideoCallMsgs = history.filter(m => m.isVideoCall && m.role !== 'system');
    const hasPrevVideoCalls = prevVideoCallMsgs.length > 0;
    let prevVideoCallSummary = '';
    if (hasPrevVideoCalls) {
        // 从历史中提取所有视频通话会话，按"接通→结束"分组
        const callSessions = [];
        let currentSession = null;
        for (const m of history) {
            if (m.isVideoCall && m.role === 'system' && m.content.includes('已接通')) {
                currentSession = { messages: [], startTime: m.time };
            } else if (m.isVideoCall && m.role === 'system' && m.content.includes('已结束')) {
                if (currentSession) {
                    currentSession.endTime = m.time;
                    callSessions.push(currentSession);
                    currentSession = null;
                }
            } else if (m.isVideoCall && m.role !== 'system' && currentSession) {
                currentSession.messages.push(m);
            } else if (m.isVideoCall && m.role !== 'system' && !currentSession) {
                // 未接通的视频通话（拒接）
                callSessions.push({ messages: [m], rejected: true, startTime: m.time });
            }
        }
        // 如果有未结束的会话也记录下来
        if (currentSession && currentSession.messages.length > 0) {
            callSessions.push(currentSession);
        }
        
        if (callSessions.length > 0) {
            const summaryParts = [`你和${userName}之前已经进行过 **${callSessions.length} 次**视频通话：`];
            callSessions.slice(-5).forEach((session, idx) => { // 最多显示最近5次
                const charMsgs = session.messages.filter(m => m.role === 'char');
                const userMsgs = session.messages.filter(m => m.role === 'user');
                if (session.rejected) {
                    const rejectContent = charMsgs.length > 0 ? String(charMsgs[0].content || '').replace('[未接听视频通话] ', '').replace('[视频通话] ', '').substring(0, 60) : '';
                    summaryParts.push(`- 第${callSessions.length - callSessions.slice(-5).length + idx + 1}次：你没接听${rejectContent ? '，理由："' + rejectContent + '"' : ''}`);
                } else {
                    const firstCharMsg = charMsgs.length > 0 ? String(charMsgs[0].content || '').replace('[视频通话] ', '').substring(0, 80) : '';
                    const msgCount = session.messages.length;
                    summaryParts.push(`- 第${callSessions.length - callSessions.slice(-5).length + idx + 1}次：已接通（共${msgCount}条对话）${firstCharMsg ? '，你接通时说："' + firstCharMsg + '..."' : ''}`);
                }
            });
            prevVideoCallSummary = summaryParts.join('\n');
        }
    }

    // 构建完整系统提示（包含双方人设、世界书、上下文）
    const systemPrompt = `# 视频通话请求

【当前时间】
${virtualTimeStr}

---

## 你是谁

**你的名字**：${char.name}
${char.nick ? `**昵称**：${char.nick}` : ''}
${char.wx_nickname ? `**微信网名**：${char.wx_nickname}` : ''}

你不是AI助手，你不是${userName}。你是一个独立的人，有自己的生活、情绪和想法。

**你的人设**：
${char.description || ''}
${userDesc}
${char.relationships && char.relationships.length > 0 ? `
**你的关联角色/NPC**：
${char.relationships.map(r => `- ${r.targetName}（${r.relation}）${r.desc ? '：' + r.desc : ''}`).join('\n')}` : ''}

${summaryMemoryContext ? `## 你的记忆（必须严格遵守，这些是已经发生过的事实）
${summaryMemoryContext}
` : ''}
${recentTopicsContext || ''}
${loreContext ? `## 世界观设定\n${loreContext}` : ''}

---

## 通话前的聊天摘要（这是你们通话的上下文和原因，至关重要！）

${preCallContext || '（暂无聊天记录）'}

${prevVideoCallSummary ? `---

## ⚡ 视频通话历史（非常重要！你们不是第一次通话！）

${prevVideoCallSummary}

**⚠️ 这不是你们的第一次视频通话！你必须自然地承接之前通话的关系、话题和记忆。绝对不能表现得像第一次通话一样打招呼或做自我介绍。你要像和熟悉的人再次视频一样自然。**` : ''}

---

## 场景

${userName}${hasPrevVideoCalls ? '再次' : ''}向你发起了**视频通话请求**（不是文字聊天！）。

请根据你的人设、与${userName}的关系、**上面的聊天摘要内容**${hasPrevVideoCalls ? '以及之前的视频通话历史' : ''}和当前情绪氛围，决定是否接听。

⚠️ **这是视频通话，不是文字聊天！绝对禁止以下行为**：
- 禁止使用 ||| 分隔符（那是文字聊天的格式，视频通话不需要）
- 禁止把回复拆分成多条短消息
- 你说的是完整的口语对话，不是打字

- 如果你决定**接听**：写出你接通视频后的第一段话（100-500字），包含动作描写。
  - 格式：动作描写:"说的话"
  - 动作必须是通过手机屏幕能看到的（挥手、微笑、调整镜头、比心、做鬼脸等）
  - ⚡ **你的第一句话必须跟上面的「通话前聊天摘要」内容相关**！自然地延续之前的话题、情绪或事件。绝对不要每次都用一样的"嗨～接通啦"之类的通用打招呼，要根据你们最近聊了什么来说。比如之前聊到出去玩，你可以说"对了刚才说要去哪玩来着？让我看看你现在在哪～"
  ${hasPrevVideoCalls ? `- ⚡ **你们之前已经通过话！** 不要像第一次通话那样惊讶或新奇地打招呼。可以提到上次通话的内容、吐槽对方又打来了、或者自然地继续之前的话题。` : ''}
  
- 如果你决定**不接听**：写出拒绝消息，说明原因，符合你的人设和语气。

---

## 回复格式

用JSON格式返回（不要有markdown标记）：

{
    "accepted": true或false,
    "message": "你的回复内容（接听则写视频通话第一段话含动作描写，不接听则写拒绝消息）"${char.video_novelai_enabled ? `,
    "image_tags": "（仅接听时需要）根据你的回复内容，生成一组英文 NovelAI/Danbooru 风格的图片 tag，用逗号分隔，不超过30个tag。规则：根据角色性别用1boy或1girl；提取表情(smile,blush,wink等)、动作(waving,peace sign等)、外貌特征(发色发型瞳色)、服装、场景；必须包含 looking at viewer, upper body；禁止出现 smartphone/phone/screen/video call/pov/UI 等标签；不要加质量词(masterpiece等)。只写tag，不要解释。"` : ''}
}

只返回JSON，不要有其他内容。`;

    // 构建消息数组（带上下文）
    // 🔧 修复：保留视频通话的系统边界标记（接通/结束），让AI清楚区分每次通话
    const contextCount = char.context_message_count || 20;
    const recentHistory = [];
    const slicedHistory = history.slice(-contextCount);
    for (const m of slicedHistory) {
        if (m.role === 'system') {
            // 视频通话边界标记转为 user 消息，让AI看到通话的起止
            if (m.isVideoCall) {
                recentHistory.push({
                    role: 'user',
                    content: m.content // 如 "📹 视频通话已接通" / "📹 视频通话已结束，通话时长 X秒"
                });
            }
            // 其他系统消息跳过
            continue;
        }
        recentHistory.push({
            role: m.role === 'user' ? 'user' : 'assistant',
            content: m.content
        });
    }
    
    const messages = [
        { role: 'system', content: systemPrompt },
        ...recentHistory,
        { role: 'user', content: '[用户向你发起了视频通话请求]' }
    ];

    try {
        const aiResponse = await callAI(messages);
        
        // 解析AI返回的JSON
        let response;
        try {
            // 尝试直接解析
            response = JSON.parse(aiResponse);
        } catch (e) {
            // 如果解析失败，尝试提取JSON部分
            const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
            if (jsonMatch) {
                response = JSON.parse(jsonMatch[0]);
            } else {
                throw new Error('无法解析AI响应');
            }
        }

        return {
            accepted: response.accepted || false,
            acceptMessage: response.accepted ? response.message : null,
            rejectMessage: !response.accepted ? response.message : null,
            imageTags: response.accepted ? (response.image_tags || null) : null
        };
    } catch (error) {
        console.error('AI调用失败:', error);
        throw error;
    }
}

// 添加视频通话消息到聊天记录（拒绝接听时调用）
async function addVideoCallMessage(char, accountId, message) {
    let history = getChatHistory(char, accountId);
    
    // 添加系统消息：用户发起了视频通话
    history.push({
        role: 'system',
        content: '📹 你发起了视频通话',
        time: Date.now() - 1,
        isVideoCall: true
    });
    
    // 添加角色的拒绝消息
    history.push({
        role: 'char',
        content: `[未接听视频通话] ${message}`,
        time: Date.now(),
        isVideoCall: true
    });
    
    await setChatHistory(char, accountId, history);
    
    // 刷新聊天界面
    if (currentChatCharId === char.id) {
        renderChatBody(char);
    }
}

