        msgDivs.forEach(div => {
            const isUser = div.style.alignSelf === 'flex-end';
            videoMessages.push({
                role: isUser ? 'user' : 'assistant',
                content: div.textContent
            });
        });

        // 获取对话对象（用户）人设
        let userDesc = "";
