// 申请代付
async function requestPayment(amount) {
    // 获取代付对象（可以选择任意角色）
    const allCharacters = await db.characters.toArray();
    const availableChars = allCharacters.filter(c => {
        if (c.type === 'system' || c.type === 'online_friend') return false;
        if (!c.name || c.name.trim() === '') return false;
        return true;
    });
    
    if (availableChars.length === 0) {
        alert('没有可选择的代付对象');
        return;
    }
    
    // 弹出选择代付对象的弹窗
    const modal = document.createElement('div');
    modal.id = 'emei-payment-request-modal';
    modal.style.cssText = 'position:fixed; top:0; left:0; right:0; bottom:0; background:rgba(0,0,0,0.5); z-index:10000; display:flex; align-items:center; justify-content:center;';
    
    modal.innerHTML = `
        <div style="background:#fff; border-radius:16px; padding:20px; width:80%; max-width:350px; max-height:60vh; display:flex; flex-direction:column;">
            <h3 style="margin:0 0 16px 0; text-align:center; font-size:16px; font-weight:600;">选择代付对象</h3>
            <div style="flex:1; overflow-y:auto; margin-bottom:16px;">
                ${availableChars.map(char => `
                    <div onclick="selectPaymentRequestTarget(${char.id}, '${char.name.replace(/'/g, "\\'")}')" style="display:flex; align-items:center; padding:12px; border-bottom:1px solid #f5f5f5; cursor:pointer; transition:background 0.2s;" onmouseover="this.style.background='#f8f8f8'" onmouseout="this.style.background='#fff'">
                        <div style="width:40px; height:40px; border-radius:50%; background-image:url(${char.avatar || ''}); background-size:cover; background-color:#e0e0e0; margin-right:12px; flex-shrink:0;"></div>
                        <span style="font-size:14px; color:#333;">${char.name}</span>
                    </div>
                `).join('')}
            </div>
            <button onclick="this.closest('#emei-payment-request-modal').remove()" style="padding:12px; background:#f0f0f0; color:#666; border:none; border-radius:8px; font-size:14px; cursor:pointer;">取消</button>
        </div>
    `;
    
    document.body.appendChild(modal);
}

// 选择代付对象
async function selectPaymentRequestTarget(charId, charName) {
    const modal = document.getElementById('emei-payment-request-modal');
    if (modal) modal.remove();
    
    const recipient = await db.characters.get(charId);
    if (!recipient) {
        alert('角色信息不存在');
        return;
    }
    
    const subtotal = emeiData.cart.reduce((sum, item) => sum + item.price * item.count, 0);
    const delivery = 3;
    const discount = emeiData.selectedCoupon ? emeiData.selectedCoupon.amount : 0;
    const total = subtotal + delivery - discount;
    
    // 发送代付请求卡片到聊天
    await sendPaymentRequestCard(recipient, total);
    
    // 获取收货人信息用于显示
    let recipientName = '我自己';
    if (emeiData.selectedRecipient !== 'self') {
        const recipientChar = await db.characters.get(parseInt(emeiData.selectedRecipient));
        if (recipientChar) recipientName = recipientChar.name;
    }
    
    alert(`已向 ${charName} 发送代付请求\n订单详情：${emeiData.currentStore.name}，收货人：${recipientName}`);
    hideEmeiPage();
}

// 发送订单卡片到聊天
async function sendEmeiOrderCard() {
    // 如果是给自己点单，且没有打开聊天，不发送卡片
    if (emeiData.selectedRecipient === 'self' && !currentChatCharId) {
        return;
    }
    
    const accountId = getCurrentAccountId();
    let chatCharId;
    
    // 如果是给角色点单，发送到该角色的聊天
    if (emeiData.selectedRecipient !== 'self') {
        chatCharId = parseInt(emeiData.selectedRecipient);
    } else {
        // 给自己点单，发送到当前打开的聊天
        chatCharId = currentChatCharId;
    }
    
    if (!chatCharId) return;
    
    const char = await db.characters.get(chatCharId);
    if (!char) return;
    
    // 构建订单信息
    const orderInfo = {
        store: emeiData.currentStore.name,
        items: emeiData.cart.map(item => `${item.name} x${item.count}`).join('、'),
        total: (emeiData.cart.reduce((sum, item) => sum + item.price * item.count, 0) + 3 - (emeiData.selectedCoupon ? emeiData.selectedCoupon.amount : 0)).toFixed(2),
        recipient: emeiData.selectedRecipient === 'self' ? '我自己' : char.name
    };
    
    // 🔧 小票风格卡片
    const itemsHtml = emeiData.cart.map(item => `<div style="display:flex;justify-content:space-between;margin-bottom:6px;font-size:13px;"><span style="color:#333;font-weight:600;">${item.name} x${item.count}</span><span style="font-family:Arial,sans-serif;">¥${(item.price * item.count).toFixed(2)}</span></div>`).join('');
    const deliveryFee = 3;
    const couponAmount = emeiData.selectedCoupon ? emeiData.selectedCoupon.amount : 0;
    const cardHtml = `<div style="width:260px;background:#fff;padding:16px;box-shadow:0 4px 15px rgba(0,0,0,0.1);position:relative;font-family:'Courier New',Courier,monospace;box-sizing:border-box;"><div style="position:absolute;top:-5px;left:0;width:100%;height:10px;background:linear-gradient(135deg,transparent 5px,#fff 5px) 0 0,linear-gradient(225deg,transparent 5px,#fff 5px) 0 0;background-size:20px 20px;background-repeat:repeat-x;"></div><div style="position:absolute;bottom:-10px;left:0;width:100%;height:10px;background:linear-gradient(45deg,transparent 5px,#fff 5px) 0 0,linear-gradient(-45deg,transparent 5px,#fff 5px) 0 0;background-size:20px 20px;background-repeat:repeat-x;"></div><div style="text-align:center;font-weight:800;font-size:16px;color:#333;margin-bottom:5px;border-bottom:2px dashed #ddd;padding-bottom:12px;">${orderInfo.store} · 订单详情</div><div style="margin:12px 0;font-size:13px;color:#555;">${itemsHtml}<div style="display:flex;justify-content:space-between;margin-bottom:6px;font-size:11px;color:#999;"><span>配送费</span><span>¥${deliveryFee.toFixed(2)}</span></div>${couponAmount > 0 ? `<div style="display:flex;justify-content:space-between;margin-bottom:6px;font-size:11px;color:#ff6b6b;"><span>优惠券</span><span>-¥${couponAmount.toFixed(2)}</span></div>` : ''}</div><div style="border-top:1px dashed #ccc;margin:12px 0;"></div><div style="display:flex;justify-content:space-between;font-size:16px;font-weight:900;color:#000;margin-bottom:12px;"><span>合计</span><span style="font-family:Arial,sans-serif;">¥${orderInfo.total}</span></div><div style="text-align:center;font-size:10px;color:#aaa;font-family:Arial,sans-serif;">${new Date().toLocaleString('zh-CN')}</div></div>`;
    
    // 🔧 使用按账号隔离的聊天记录（accountId 已在函数开头声明）
    let history = getChatHistory(char, accountId);
    history.push({
        role: 'user',
        content: `[emei_order]${cardHtml}`,
        time: Date.now()
    });
    await setChatHistory(char, accountId, history);
    
    // 如果当前在该聊天窗口，刷新显示
    if (currentChatCharId === chatCharId) {
        renderChatBody(char);
    } else if (emeiData.selectedRecipient !== 'self') {
        // 给角色点单，即使没打开聊天窗口也提示用户
        alert(`订单已发送给 ${char.name}！可以在聊天中查看订单详情。`);
    }
}

// 发送代付请求卡片
async function sendPaymentRequestCard(recipient, amount) {
    if (!recipient) return;
    
    // 获取收货人信息
    let recipientName = '我自己';
    if (emeiData.selectedRecipient !== 'self') {
        const recipientChar = await db.characters.get(parseInt(emeiData.selectedRecipient));
        if (recipientChar) recipientName = recipientChar.name;
    }
    
    // 🔧 小票风格代付请求卡片
    const storeName = emeiData.currentStore.name;
    const payItemsHtml = emeiData.cart.map(i => `<div style="display:flex;justify-content:space-between;margin-bottom:6px;font-size:13px;"><span style="color:#333;font-weight:600;">${i.name} x${i.count}</span><span style="font-family:Arial,sans-serif;">¥${(i.price * i.count).toFixed(2)}</span></div>`).join('');
    const cardHtml = `<div style="width:260px;background:#fff;padding:16px;box-shadow:0 4px 15px rgba(0,0,0,0.1);position:relative;font-family:'Courier New',Courier,monospace;box-sizing:border-box;"><div style="position:absolute;top:-5px;left:0;width:100%;height:10px;background:linear-gradient(135deg,transparent 5px,#fff 5px) 0 0,linear-gradient(225deg,transparent 5px,#fff 5px) 0 0;background-size:20px 20px;background-repeat:repeat-x;"></div><div style="position:absolute;bottom:-10px;left:0;width:100%;height:10px;background:linear-gradient(45deg,transparent 5px,#fff 5px) 0 0,linear-gradient(-45deg,transparent 5px,#fff 5px) 0 0;background-size:20px 20px;background-repeat:repeat-x;"></div><div style="text-align:center;font-weight:800;font-size:16px;color:#333;margin-bottom:5px;border-bottom:2px dashed #ddd;padding-bottom:12px;">${storeName} · 代付请求</div><div style="text-align:center;font-size:12px;color:#888;margin:8px 0;">帮我付一下外卖~</div><div style="margin:12px 0;font-size:13px;color:#555;">${payItemsHtml}</div><div style="border-top:1px dashed #ccc;margin:12px 0;"></div><div style="display:flex;justify-content:space-between;font-size:16px;font-weight:900;color:#000;margin-bottom:14px;"><span>合计</span><span style="font-family:Arial,sans-serif;color:#ff4d4f;">¥${amount.toFixed(2)}</span></div><div onclick="handlePaymentRequest(this)" data-amount="${amount.toFixed(2)}" data-pay-type="char_pay" style="display:block;width:100%;padding:10px;background:#ff4d4f;color:white;text-align:center;border-radius:4px;font-family:sans-serif;font-weight:bold;letter-spacing:1px;cursor:pointer;box-sizing:border-box;">帮我支付</div><div style="text-align:center;font-size:10px;color:#aaa;margin-top:12px;font-family:Arial,sans-serif;">${new Date().toLocaleString('zh-CN')}</div></div>`;
    
    // 🔧 使用按账号隔离的聊天记录
    const accountId = getCurrentAccountId();
    let history = getChatHistory(recipient, accountId);
    history.push({
        role: 'user',
        content: `[payment_request]${cardHtml}`,
        time: Date.now()
    });
    await setChatHistory(recipient, accountId, history);
    
    if (currentChatCharId === recipient.id) {
        renderChatBody(recipient);
    }
}

// 处理代付请求
async function handlePaymentRequest(btn) {
    const payType = btn.getAttribute('data-pay-type');
    const amount = parseFloat(btn.getAttribute('data-amount') || 0);
    
    if (payType === 'user_pay') {
        // 用户帮角色支付外卖 → 扣用户钱包余额
        const accountId = getCurrentAccountId();
        if (!accountId) {
            showToast('请先登录账号');
            return;
        }
        
        const myChar = await db.characters.get(parseInt(accountId));
        if (!myChar) {
            showToast('账号数据异常');
            return;
        }
        
        if (!myChar.identity) myChar.identity = {};
        const balance = parseFloat(myChar.identity.balance || 0);
        
        if (balance < amount) {
            showToast(`余额不足 (当前: ¥${balance.toFixed(2)})`);
            return;
        }
        
        // 扣款
        myChar.identity.balance = (balance - amount).toFixed(2);
        await safeCharacterPut(myChar);
        
        // 更新余额显示
        await updateBalancePageDisplay();
        await updateWalletBalanceDisplay();
        
        // 记录账单（支出）
        await addTransaction('expense', amount, '外卖代付', '帮TA支付外卖');
        
        // 更新按钮状态
        btn.innerText = '已支付 ¥' + amount.toFixed(2);
        btn.style.background = '#52c41a';
        btn.style.cursor = 'default';
        btn.onclick = null;
        
        showToast(`支付成功！已扣款 ¥${amount.toFixed(2)}`);
    } else {
        // 角色帮用户支付外卖 → 直接显示已支付
        btn.innerText = '已支付';
        btn.style.background = '#52c41a';
        btn.style.cursor = 'default';
        btn.onclick = null;
        
        showToast('对方已支付');
    }
}

// 🔧 显示分享订单弹窗（给自己点单后可以分享给好友）
async function showShareOrderModal(amount) {
    const allCharacters = await db.characters.toArray();
    const accountId = getCurrentAccountId();
    
    // 过滤可分享的角色（有好友关系的角色）
    const availableChars = allCharacters.filter(c => {
        if (c.type === 'system' || c.type === 'user') return false;
        if (!c.name || c.name.trim() === '') return false;
        // 检查是否是好友
        const status = getFriendStatus(c, accountId);
        return status === 'friend';
    });
    
    if (availableChars.length === 0) {
        hideEmeiPage();
        return;
    }
    
    const modal = document.createElement('div');
    modal.id = 'emei-share-modal';
    modal.style.cssText = 'position:fixed; top:0; left:0; right:0; bottom:0; background:rgba(0,0,0,0.5); z-index:10000; display:flex; align-items:center; justify-content:center;';
    
    modal.innerHTML = `
        <div style="background:#fff; border-radius:16px; padding:20px; width:85%; max-width:350px; max-height:70vh; display:flex; flex-direction:column;">
            <h3 style="margin:0 0 8px 0; text-align:center; font-size:16px; font-weight:600;">分享订单给好友</h3>
            <p style="margin:0 0 16px 0; text-align:center; font-size:12px; color:#999;">选择想要分享的好友（可多选）</p>
            <div id="share-char-list" style="flex:1; overflow-y:auto; margin-bottom:16px; max-height:300px;">
                ${availableChars.map(char => `
                    <label style="display:flex; align-items:center; padding:12px; border-bottom:1px solid #f5f5f5; cursor:pointer;">
                        <input type="checkbox" value="${char.id}" style="width:18px; height:18px; margin-right:12px; accent-color:var(--ins-pink);">
                        <div style="width:40px; height:40px; border-radius:50%; background-image:url(${char.avatar || ''}); background-size:cover; background-color:#e0e0e0; margin-right:12px; flex-shrink:0;"></div>
                        <span style="font-size:14px; color:#333;">${char.name}</span>
                    </label>
                `).join('')}
            </div>
            <div style="display:flex; gap:12px;">
                <button onclick="closeShareOrderModal()" style="flex:1; padding:12px; background:#f0f0f0; color:#666; border:none; border-radius:8px; font-size:14px; cursor:pointer;">跳过</button>
                <button onclick="confirmShareOrder()" style="flex:1; padding:12px; background:var(--ins-pink); color:#fff; border:none; border-radius:8px; font-size:14px; cursor:pointer;">分享</button>
            </div>
        </div>
    `;
    
    document.body.appendChild(modal);
}

// 关闭分享弹窗
function closeShareOrderModal() {
    const modal = document.getElementById('emei-share-modal');
    if (modal) modal.remove();
    hideEmeiPage();
}

// 确认分享订单
async function confirmShareOrder() {
    const checkboxes = document.querySelectorAll('#share-char-list input[type="checkbox"]:checked');
    const selectedIds = Array.from(checkboxes).map(cb => parseInt(cb.value));
    
    if (selectedIds.length === 0) {
        closeShareOrderModal();
        return;
    }
    
    const accountId = getCurrentAccountId();
    
    // 向每个选中的好友发送分享卡片
    for (const charId of selectedIds) {
        await sendShareOrderCard(charId, accountId);
    }
    
    showToast(`已分享给 ${selectedIds.length} 位好友`);
    closeShareOrderModal();
}

// 发送分享订单卡片
async function sendShareOrderCard(charId, accountId) {
    const char = await db.characters.get(charId);
    if (!char) return;
    
    const orderInfo = {
        store: emeiData.currentStore.name,
        items: emeiData.cart.map(item => `${item.name} x${item.count}`).join('、'),
        total: (emeiData.cart.reduce((sum, item) => sum + item.price * item.count, 0) + 3 - (emeiData.selectedCoupon ? emeiData.selectedCoupon.amount : 0)).toFixed(2)
    };
    
    // 创建小票风格分享卡片HTML
    const shareItemsHtml = emeiData.cart.map(item => `<div style="display:flex;justify-content:space-between;margin-bottom:6px;font-size:13px;"><span style="color:#333;font-weight:600;">${item.name} x${item.count}</span><span style="font-family:Arial,sans-serif;">¥${(item.price * item.count).toFixed(2)}</span></div>`).join('');
    const cardHtml = `<div style="width:260px;background:#fff;padding:16px;box-shadow:0 4px 15px rgba(0,0,0,0.1);position:relative;font-family:'Courier New',Courier,monospace;box-sizing:border-box;"><div style="position:absolute;top:-5px;left:0;width:100%;height:10px;background:linear-gradient(135deg,transparent 5px,#fff 5px) 0 0,linear-gradient(225deg,transparent 5px,#fff 5px) 0 0;background-size:20px 20px;background-repeat:repeat-x;"></div><div style="position:absolute;bottom:-10px;left:0;width:100%;height:10px;background:linear-gradient(45deg,transparent 5px,#fff 5px) 0 0,linear-gradient(-45deg,transparent 5px,#fff 5px) 0 0;background-size:20px 20px;background-repeat:repeat-x;"></div><div style="text-align:center;font-weight:800;font-size:16px;color:#333;margin-bottom:5px;border-bottom:2px dashed #ddd;padding-bottom:12px;">🛵 ${orderInfo.store} · 外卖分享</div><div style="text-align:center;font-size:12px;color:#888;margin:8px 0;">我刚点了外卖，分享给你看看~</div><div style="margin:12px 0;font-size:13px;color:#555;">${shareItemsHtml}</div><div style="border-top:1px dashed #ccc;margin:12px 0;"></div><div style="display:flex;justify-content:space-between;font-size:16px;font-weight:900;color:#000;margin-bottom:8px;"><span>合计</span><span style="font-family:Arial,sans-serif;">¥${orderInfo.total}</span></div><div style="text-align:center;font-size:11px;color:#999;margin-top:8px;">🍔 一起点外卖呀~</div></div>`;
    
    // 添加到聊天记录
    let history = getChatHistory(char, accountId);
    history.push({
        role: 'user',
        content: `[emei_share]${cardHtml}`,
        time: Date.now()
    });
    await setChatHistory(char, accountId, history);
    
    // 如果当前在该聊天窗口，刷新显示
    if (currentChatCharId === charId) {
        renderChatBody(char);
    }
}

