    if (!container) return;
    let goods;
    if (category) {
        goods = await xianyuDb.goods.where('category').equals(category).toArray();
    } else {
        goods = await xianyuDb.goods.toArray();
    }
    goods.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
