// ===== 导入主题URL保护机制 =====
// 导入主题URL字段映射（input ID → theme属性名）
const _IMPORTED_URL_FIELDS = {
    'chat-theme-bg': 'chatBackground',
    'chat-theme-header-bg': 'headerBg',
    'chat-theme-footer-bg': 'footerBg',
    'chat-theme-icon-back': 'iconBack',
    'chat-theme-icon-offline': 'iconOffline',
    'chat-theme-icon-detail': 'iconDetail',
    'chat-theme-icon-ai': 'iconAi',
    'chat-theme-icon-emoji': 'iconEmoji',
    'chat-theme-icon-more': 'iconMore',
    'chat-theme-icon-send': 'iconSend'
};

/**
 * 获取主题URL字段的真实值（优先从导入保护数据中获取）
 * @param {string} inputId - 输入框的DOM ID
 * @returns {string} 真实的URL值
 */
function _getThemeUrlValue(inputId) {
    if (window._editingImportedTheme && window._editingImportedTheme[inputId]) {
        return window._editingImportedTheme[inputId];
    }
    return document.getElementById(inputId)?.value?.trim() || '';
}

/**
 * 清除导入主题编辑保护状态，恢复所有URL输入框的可编辑状态
 */
function _clearImportedThemeEditState() {
    if (window._editingImportedTheme) {
        Object.keys(_IMPORTED_URL_FIELDS).forEach(inputId => {
            const input = document.getElementById(inputId);
            if (input) {
                input.readOnly = false;
                input.style.color = '';
                input.style.background = '';
            }
        });
        window._editingImportedTheme = null;
    }
}

// ===== 导出加密选择弹窗 =====
/**
 * 显示导出方式选择弹窗，让用户选择加密或明文导出
 * @returns {Promise<'encrypted'|'plain'|null>} 用户选择结果，null表示取消
 */
function _showExportEncryptDialog() {
    return new Promise(resolve => {
        const overlay = document.createElement('div');
        overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.45);z-index:99999;display:flex;align-items:center;justify-content:center;';

        const dialog = document.createElement('div');
        dialog.style.cssText = 'background:#fff;border-radius:14px;padding:24px 20px 16px;width:300px;max-width:85vw;box-shadow:0 8px 32px rgba(0,0,0,0.2);text-align:center;';
        dialog.innerHTML = `
            <div style="font-size:16px;font-weight:600;color:#333;margin-bottom:8px;">选择导出方式</div>
            <div style="font-size:13px;color:#888;margin-bottom:20px;line-height:1.5;">
                加密导出：图片链接等数据将被加密保护，导入后编辑时不可查看链接<br>
                明文导出：数据不加密，导入后可以查看和编辑所有内容
            </div>
            <div style="display:flex;gap:8px;margin-bottom:8px;">
                <div id="_export-encrypted-btn" style="flex:1;padding:12px 0;background:#007aff;color:#fff;border-radius:10px;font-size:15px;font-weight:500;cursor:pointer;">🔒 加密导出</div>
                <div id="_export-plain-btn" style="flex:1;padding:12px 0;background:#34c759;color:#fff;border-radius:10px;font-size:15px;font-weight:500;cursor:pointer;">📄 明文导出</div>
            </div>
            <div id="_export-cancel-btn" style="padding:10px 0;color:#999;font-size:14px;cursor:pointer;">取消</div>
        `;

        overlay.appendChild(dialog);
        document.body.appendChild(overlay);

        const cleanup = () => document.body.removeChild(overlay);

        dialog.querySelector('#_export-encrypted-btn').onclick = () => { cleanup(); resolve('encrypted'); };
        dialog.querySelector('#_export-plain-btn').onclick = () => { cleanup(); resolve('plain'); };
        dialog.querySelector('#_export-cancel-btn').onclick = () => { cleanup(); resolve(null); };
        overlay.onclick = (e) => { if (e.target === overlay) { cleanup(); resolve(null); } };
    });
}

// ===== 主题加密/解密工具 =====
const _THEME_KEY = 'MxTheme@2026!Enc';

function _themeEncrypt(plainText) {
    // 1. 将明文转为UTF-8字节数组
    const encoder = new TextEncoder();
    const data = encoder.encode(plainText);
    const key = encoder.encode(_THEME_KEY);
    // 2. XOR混淆
    const encrypted = new Uint8Array(data.length);
    for (let i = 0; i < data.length; i++) {
        encrypted[i] = data[i] ^ key[i % key.length] ^ ((i * 7 + 13) & 0xFF);
    }
    // 3. 转Base64
    let binary = '';
    for (let i = 0; i < encrypted.length; i++) {
        binary += String.fromCharCode(encrypted[i]);
    }
    return btoa(binary);
}

function _themeDecrypt(cipherBase64) {
    // 1. Base64解码
    const binary = atob(cipherBase64);
    const encrypted = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) {
        encrypted[i] = binary.charCodeAt(i);
    }
    // 2. XOR还原
    const encoder = new TextEncoder();
    const key = encoder.encode(_THEME_KEY);
    const decrypted = new Uint8Array(encrypted.length);
    for (let i = 0; i < encrypted.length; i++) {
        decrypted[i] = encrypted[i] ^ key[i % key.length] ^ ((i * 7 + 13) & 0xFF);
    }
    // 3. UTF-8字节还原为字符串
    const decoder = new TextDecoder();
    return decoder.decode(decrypted);
}

// 导出单个主题（用户选择加密或明文，加密导入的主题强制加密）
async function exportSingleChatTheme(themeId) {
    try {
        const theme = await db.chat_themes.get(themeId);
        if (!theme) {
            showToast('❌ 主题不存在');
            return;
        }

        let choice;
        if (theme.isImported) {
            // 加密导入的主题只允许加密导出，防止通过明文导出泄露链接
            choice = 'encrypted';
            showToast('🔒 该主题为加密导入，将自动加密导出');
        } else {
            // 自建主题让用户选择导出方式
            choice = await _showExportEncryptDialog();
            if (!choice) return; // 取消
        }

        // 移除数据库自增ID和accountId及isImported标记
        const { id, accountId: _aid, isImported: _imp, ...rest } = theme;

        let jsonData;

        if (choice === 'encrypted') {
            // 加密导出
            const themesJson = JSON.stringify([rest]);
            const encryptedPayload = _themeEncrypt(themesJson);
            jsonData = {
                type: 'chat_themes_export',
                version: 2,
                encrypted: true,
                exportTime: new Date().toISOString(),
                count: 1,
                payload: encryptedPayload
            };
        } else {
            // 明文导出
            jsonData = {
                type: 'chat_themes_export',
                version: 2,
                encrypted: false,
                exportTime: new Date().toISOString(),
                count: 1,
                themes: [rest]
            };
        }

        const jsonStr = JSON.stringify(jsonData);
        const blob = new Blob([jsonStr], { type: 'application/json' });
        const url = URL.createObjectURL(blob);

        const isEnc = choice === 'encrypted';
        const safeName = (theme.name || 'theme').replace(/[^a-zA-Z0-9\u4e00-\u9fff_-]/g, '_');
        const a = document.createElement('a');
        a.href = url;
        a.download = `theme_${safeName}_${isEnc ? 'enc_' : ''}${new Date().toISOString().slice(0,10)}.json`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);

        showToast(`✅ 已导出主题「${theme.name}」${isEnc ? '（已加密）' : '（明文）'}`);
        console.log(`[ChatTheme] ✓ 单个主题导出成功(${isEnc ? '加密' : '明文'}):`, theme.name);
    } catch (error) {
        console.error('[ChatTheme] ✗ 导出失败:', error);
        showToast('❌ 导出失败: ' + error.message);
    }
}

// 导出全部主题（用户选择加密或明文，含加密导入主题时强制加密）
async function exportChatThemes() {
    try {
        const accountId = getCurrentAccountId() || 'offline';
        const themes = await db.chat_themes.where('accountId').equals(accountId).toArray();

        if (themes.length === 0) {
            showToast('❌ 暂无可导出的主题');
            return;
        }

        // 检查是否包含加密导入的主题
        const hasImportedTheme = themes.some(t => t.isImported);

        let choice;
        if (hasImportedTheme) {
            // 包含加密导入的主题，强制加密导出
            choice = 'encrypted';
            showToast('🔒 包含加密导入的主题，将自动加密导出');
        } else {
            // 全部是自建主题，让用户选择
            choice = await _showExportEncryptDialog();
            if (!choice) return; // 取消
        }

        // 移除数据库自增ID和accountId，导入时重新生成
        const exportData = themes.map(theme => {
            const { id, accountId: _aid, isImported: _imp, ...rest } = theme;
            return rest;
        });

        let jsonData;

        if (choice === 'encrypted') {
            // 加密导出
            const themesJson = JSON.stringify(exportData);
            const encryptedPayload = _themeEncrypt(themesJson);
            jsonData = {
                type: 'chat_themes_export',
                version: 2,
                encrypted: true,
                exportTime: new Date().toISOString(),
                count: exportData.length,
                payload: encryptedPayload
            };
        } else {
            // 明文导出
            jsonData = {
                type: 'chat_themes_export',
                version: 2,
                encrypted: false,
                exportTime: new Date().toISOString(),
                count: exportData.length,
                themes: exportData
            };
        }

        const jsonStr = JSON.stringify(jsonData);
        const blob = new Blob([jsonStr], { type: 'application/json' });
        const url = URL.createObjectURL(blob);

        const isEnc = choice === 'encrypted';
        const a = document.createElement('a');
        a.href = url;
        a.download = `chat_themes_${isEnc ? 'enc_' : ''}${new Date().toISOString().slice(0,10)}.json`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);

        showToast(`✅ 已导出 ${themes.length} 个主题${isEnc ? '（已加密）' : '（明文）'}`);
        console.log(`[ChatTheme] ✓ 主题导出成功(${isEnc ? '加密' : '明文'}):`, themes.length, '个');
    } catch (error) {
        console.error('[ChatTheme] ✗ 导出失败:', error);
        showToast('❌ 导出失败: ' + error.message);
    }
}

// 导入主题文件（兼容加密v2和旧版v1明文）
async function importChatThemes(event) {
    const file = event.target.files[0];
    if (!file) return;

    // 重置input以便下次可以选同一文件
    event.target.value = '';

    try {
        const text = await file.text();
        const jsonData = JSON.parse(text);

        // 校验格式
        if (jsonData.type !== 'chat_themes_export') {
            showToast('❌ 文件格式不正确，请选择主题导出文件');
            return;
        }

        let themesArr;
        let isEncryptedSource = false; // 标记来源是否为加密文件

        if (jsonData.version >= 2 && jsonData.payload) {
            // v2加密格式：解密payload
            isEncryptedSource = true;
            try {
                const decryptedJson = _themeDecrypt(jsonData.payload);
                themesArr = JSON.parse(decryptedJson);
            } catch (e) {
                showToast('❌ 主题解密失败，文件可能已损坏');
                console.error('[ChatTheme] 解密失败:', e);
                return;
            }
        } else if (Array.isArray(jsonData.themes)) {
            // v2明文格式 或 v1旧版明文格式：直接读取
            isEncryptedSource = false;
            themesArr = jsonData.themes;
        } else {
            showToast('❌ 文件格式不正确');
            return;
        }

        if (!Array.isArray(themesArr) || themesArr.length === 0) {
            showToast('❌ 没有找到可导入的主题数据');
            return;
        }

        const accountId = getCurrentAccountId() || 'offline';
        let importCount = 0;

        for (const theme of themesArr) {
            // 给每个主题绑定当前账号
            const themeData = {
                ...theme,
                accountId: accountId
            };
            // 仅加密来源的主题标记为导入（保护URL不可见）
            if (isEncryptedSource) {
                themeData.isImported = true;
            } else {
                delete themeData.isImported;
            }
            // 移除可能携带的旧id
            delete themeData.id;
            await db.chat_themes.add(themeData);
            importCount++;
        }

        const modeText = isEncryptedSource ? '（加密主题，图片链接受保护）' : '（明文主题）';
        showToast(`✅ 成功导入 ${importCount} 个主题${modeText}`);
        console.log(`[ChatTheme] ✓ 主题导入成功(${isEncryptedSource ? '加密' : '明文'}):`, importCount, '个');

        // 刷新主题列表
        await loadChatThemeList();
    } catch (error) {
        console.error('[ChatTheme] ✗ 导入失败:', error);
        if (error instanceof SyntaxError) {
            showToast('❌ 文件解析失败，请确认是有效的主题文件');
        } else {
            showToast('❌ 导入失败: ' + error.message);
        }
    }
}

window.exportSingleChatTheme = exportSingleChatTheme;
window.exportChatThemes = exportChatThemes;
window.importChatThemes = importChatThemes;

// ===========================================
// 默契绘画游戏 + 菜单面板滑动翻页
// ===========================================

// ---- 菜单面板滑动翻页逻辑 ----
(function() {
    let actionPageIndex = 0;
    let touchStartX = 0;
    let touchDeltaX = 0;
    let isSwiping = false;

    function getTrack() { return document.getElementById('action-panel-track'); }
    function getDots() { return document.querySelectorAll('#action-panel-dots .action-dot'); }

    function setActionPage(idx) {
        actionPageIndex = idx;
        const track = getTrack();
        if (track) track.style.transform = 'translateX(' + (-idx * 50) + '%)';
        getDots().forEach((d, i) => {
            d.classList.toggle('active', i === idx);
        });
    }

    document.addEventListener('touchstart', function(e) {
        const swiper = document.getElementById('action-panel-swiper');
        if (!swiper || !swiper.closest('.action-panel') || swiper.closest('.action-panel').style.display === 'none') return;
        if (!swiper.contains(e.target)) return;
        touchStartX = e.touches[0].clientX;
        touchDeltaX = 0;
        isSwiping = true;
        const track = getTrack();
        if (track) track.style.transition = 'none';
    }, { passive: true });

    document.addEventListener('touchmove', function(e) {
        if (!isSwiping) return;
        const swiper = document.getElementById('action-panel-swiper');
        if (!swiper || !swiper.contains(e.target)) return;
        touchDeltaX = e.touches[0].clientX - touchStartX;
        const track = getTrack();
        if (track) {
            const base = -actionPageIndex * 50;
            const pct = (touchDeltaX / swiper.offsetWidth) * 50;
            track.style.transform = 'translateX(' + (base + pct) + '%)';
        }
    }, { passive: true });

    document.addEventListener('touchend', function(e) {
        if (!isSwiping) return;
        isSwiping = false;
        const track = getTrack();
        if (track) track.style.transition = 'transform 0.3s cubic-bezier(0.2, 0.8, 0.2, 1)';
        const threshold = 50;
        if (touchDeltaX < -threshold && actionPageIndex < 1) {
            setActionPage(1);
        } else if (touchDeltaX > threshold && actionPageIndex > 0) {
            setActionPage(0);
        } else {
            setActionPage(actionPageIndex);
        }
    }, { passive: true });

    // 点击小圆点
    document.addEventListener('click', function(e) {
        const dot = e.target.closest('.action-dot');
        if (dot && dot.dataset.page !== undefined) {
            setActionPage(parseInt(dot.dataset.page));
        }
    });

    // 面板每次打开时重置到第一页
    const origToggle = window.toggleChatPanel;
    window.toggleChatPanel = function(type) {
        if (type === 'action') {
            setActionPage(0);
        }
        origToggle(type);
    };
})();

// ---- 默契绘画游戏逻辑 ----
const MOQI_TOPICS = [
    "手机","杯子","雨伞","钥匙","灯泡","镜子","书包","手表","拖鞋","枕头",
    "小猫","小狗","兔子","小鸟","熊猫","鱼","蝴蝶","猴子","大象","企鹅",
    "汉堡","冰淇淋","蛋糕","奶茶","面条","水果","披萨","棒棒糖","饺子","火锅",
    "太阳","月亮","星星","云朵","彩虹","开心","睡觉","跑步","跳舞","害羞",
    "外星人","超人","火箭","城堡","魔法棒","爱心","礼物","气球","烟花","天使"
];

let moqiCurrentTopic = '';
let moqiUserCtx = null;
let moqiAiCtx = null;
let moqiIsDrawing = false;
let moqiCurrentColor = '#333333';
let moqiCurrentTool = 'pen';
let moqiBrushSize = 3;
let moqiUndoStack = [];
let moqiAiDrawn = false;
let moqiCharName = '角色'; // 当前聊天角色名
let moqiCharDesc = ''; // 当前聊天角色人设描述

async function showMoqiDrawGame() {
    closeChatPanel();

    // 获取当前聊天角色信息
    try {
        const charId = window._currentChatCharId || null;
        if (charId) {
            const char = await db.characters.get(charId);
            if (char) {
                const accountId = localStorage.getItem('current_my_char_id') || '1';
                // 优先用备注名
                const nickMap = char.account_nicks || {};
                moqiCharName = nickMap[accountId] || char.nick || char.name || '角色';
                moqiCharDesc = char.description || char.desc || '';
            }
        }
    } catch (e) {
        console.warn('[默契绘画] 获取角色信息失败:', e);
    }

    // 更新界面上的角色名
    const charLabel = document.getElementById('moqi-char-label');
    if (charLabel) charLabel.textContent = moqiCharName + ' 的画';
    const btnText = document.getElementById('moqi-ai-btn-text');
    if (btnText) btnText.textContent = '让' + moqiCharName + '画上半部分';

    const overlay = document.getElementById('moqi-draw-overlay');
    overlay.style.display = 'flex';
    initMoqiCanvases();
}
window.showMoqiDrawGame = showMoqiDrawGame;

function closeMoqiDrawGame() {
    document.getElementById('moqi-draw-overlay').style.display = 'none';
}
window.closeMoqiDrawGame = closeMoqiDrawGame;

function initMoqiCanvases() {
    const aiCanvas = document.getElementById('moqi-ai-canvas');
    const userCanvas = document.getElementById('moqi-user-canvas');
    
    // 设置 canvas 分辨率
    const w = aiCanvas.offsetWidth;
    const h = aiCanvas.offsetHeight;
    const dpr = window.devicePixelRatio || 1;

    [aiCanvas, userCanvas].forEach(c => {
        c.width = w * dpr;
        c.height = h * dpr;
        const ctx = c.getContext('2d');
        ctx.scale(dpr, dpr);
        ctx.fillStyle = '#fff';
        ctx.fillRect(0, 0, w, h);
    });

    moqiAiCtx = aiCanvas.getContext('2d');
    moqiUserCtx = userCanvas.getContext('2d');
    moqiUndoStack = [];
    moqiAiDrawn = false;

    // 用户绘画事件
    setupMoqiUserDrawing(userCanvas);
}

function setupMoqiUserDrawing(canvas) {
    let lastX, lastY;
    const dpr = window.devicePixelRatio || 1;

    function getPos(e) {
        const rect = canvas.getBoundingClientRect();
        const touch = e.touches ? e.touches[0] : e;
        return {
            x: (touch.clientX - rect.left),
            y: (touch.clientY - rect.top)
        };
    }

    function startDraw(e) {
        e.preventDefault();
        moqiIsDrawing = true;
        const pos = getPos(e);
        lastX = pos.x;
        lastY = pos.y;
        // 保存撤销快照
        moqiSaveUndoSnapshot();
    }

    function draw(e) {
        e.preventDefault();
        if (!moqiIsDrawing) return;
        const pos = getPos(e);
        const ctx = moqiUserCtx;

        ctx.save();
        ctx.beginPath();
        ctx.moveTo(lastX, lastY);
        ctx.lineTo(pos.x, pos.y);
        ctx.lineWidth = moqiBrushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';

        if (moqiCurrentTool === 'eraser') {
            ctx.globalCompositeOperation = 'destination-out';
            ctx.strokeStyle = 'rgba(255,255,255,1)';
            ctx.lineWidth = moqiBrushSize * 3;
        } else {
            ctx.globalCompositeOperation = 'source-over';
            ctx.strokeStyle = moqiCurrentColor;
        }

        ctx.stroke();
        ctx.restore();

        lastX = pos.x;
        lastY = pos.y;
    }

    function endDraw(e) {
        if (e) e.preventDefault();
        moqiIsDrawing = false;
    }

    // Remove old handlers
    canvas.onmousedown = null;
    canvas.onmousemove = null;
    canvas.onmouseup = null;
    canvas.onmouseleave = null;
    canvas.ontouchstart = null;
    canvas.ontouchmove = null;
    canvas.ontouchend = null;

    canvas.addEventListener('mousedown', startDraw);
    canvas.addEventListener('mousemove', draw);
    canvas.addEventListener('mouseup', endDraw);
    canvas.addEventListener('mouseleave', endDraw);
    canvas.addEventListener('touchstart', startDraw, { passive: false });
    canvas.addEventListener('touchmove', draw, { passive: false });
    canvas.addEventListener('touchend', endDraw, { passive: false });
}

function moqiSaveUndoSnapshot() {
    const canvas = document.getElementById('moqi-user-canvas');
    moqiUndoStack.push(canvas.toDataURL());
    if (moqiUndoStack.length > 30) moqiUndoStack.shift();
}

function moqiUndo() {
    if (moqiUndoStack.length === 0) return;
    const dataUrl = moqiUndoStack.pop();
    const canvas = document.getElementById('moqi-user-canvas');
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;
    const img = new Image();
    img.onload = function() {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.drawImage(img, 0, 0);
    };
    img.src = dataUrl;
}
window.moqiUndo = moqiUndo;

function moqiClearUser() {
    moqiSaveUndoSnapshot();
    const canvas = document.getElementById('moqi-user-canvas');
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;
    ctx.save();
    ctx.setTransform(1, 0, 0, 1, 0, 0);
    ctx.fillStyle = '#fff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.restore();
}
window.moqiClearUser = moqiClearUser;

function moqiSetColor(el) {
    moqiCurrentColor = el.dataset.color;
    document.querySelectorAll('.moqi-color-btn').forEach(b => b.classList.remove('active'));
    el.classList.add('active');
    moqiSetTool('pen');
}
window.moqiSetColor = moqiSetColor;

function moqiSetTool(tool) {
    moqiCurrentTool = tool;
    document.getElementById('moqi-pen-btn').classList.toggle('active', tool === 'pen');
    document.getElementById('moqi-eraser-btn').classList.toggle('active', tool === 'eraser');
}
